-- dbo.IMSSIPMessage source

ALTER VIEW IMSSIPMessage
AS
  Select FactId as MsgId,
         SessionId,
         VirtualTestId as TestId,
         FullDate as MsgTime,
         PosId,
         NetworkId,
         case when Direction = 'U' then 1 else 0 end as Direction,
         CONVERT(smallint, Identifier4) as SDPPresence,
         Identifier as MessageId,
         CONVERT(smallint, Identifier2) as ResponseCode,
         CONVERT(int, Identifier3) as CallId,
         SIPCallId,
         Message
  from FactL3Messages
  where Technology = 'VoIP';


