-- dbo.LTEPRACH source

ALTER VIEW LTEPRACH
AS
    SELECT FactId AS MsgId,
           SessionId,
           VirtualTestId AS TestId,
           FullDate AS MsgTime,
           PosId,
           NetworkId,
           Config,
           MaxAttempts,
           StepSize,
           InitPower,
           CASE WHEN Reason = 'Connection Request' THEN 0
                WHEN Reason = 'Radio Link Failure' THEN 1
                WHEN Reason = 'UL Data Arrival'    THEN 2
                WHEN Reason = 'DL Data Arrival'    THEN 3
                WHEN Reason = 'Handover'           THEN 4 END AS Reason,
           Pathloss,
           CRNTI,
           TxPower,
           CASE WHEN Result = 'Success'                                            THEN 0
                WHEN Result = 'Failure at MSG2'                                    THEN 1
                WHEN Result = 'Failure at MSG4 due to CT timer expired'            THEN 2
                WHEN Result = 'Failure at MSG4 due to CT resolution is not passed' THEN 3
                WHEN Result = 'Aborted'                                            THEN 4 END AS Result,
           NumTx,
           CASE WHEN Type = 'Contention Free RACH procedure'  THEN 0
                WHEN Type = 'Contention Based RACH procedure' THEN 1 END AS Type,
           BackOFF,
           NumContentionFailed,
           NumContentionPassed,
           CELevel
    FROM FactLTEPRACH;


