-- dbo.NBIoTServingCellInfo source

ALTER VIEW NBIoTServingCellInfo
AS
  SELECT FactId AS MsgId,
         SessionId,
         VirtualtestId AS TestId,
         FullDate AS MsgTime,
         PosId,
         NetworkId,
         PCI,
         DLEARFCN,
         ULEARFCN,
         DLBandWidth,
         ULBandWidth,
         CellIdentity,
         TAC,
         BandIndicator,
         MCC,
         MNC,
         CONVERT(int, CASE WHEN ServiceState = 'No service'               THEN 0
                           WHEN ServiceState = 'Limited service'          THEN 1
                           WHEN ServiceState = 'Service available'        THEN 2
                           WHEN ServiceState = 'Limited regional service' THEN 3
                           WHEN ServiceState = 'Power save'               THEN 4 END) AS ServiceState,
         eNBAntennas,
         UEAntennas,
         CONVERT(int, CASE WHEN NBOpMode = 'In-band same PCI'      THEN 0
                           WHEN NBOpMode = 'In-band different PCI' THEN 1
                           WHEN NBOpMode = 'Guard band'            THEN 2
                           WHEN NBOpMode = 'Stand alone'           THEN 3 END) AS NBOpMode,
         NBMeasBW,
         NBRank,
         Srxlev,
         Qrxlevmin,
         PMax,
         MaxUETxPower
  FROM FactNBIoTCellInfo;


