-- dbo.vActivePDPSessions source

ALTER VIEW vActivePDPSessions
AS
  Select fi1.FileId, s.SessionId
  from FileInfo fi1
       JOIN FileInfo fi2 ON fi2.FileId = fi1.FileId
       JOIN Sessions s ON s.FileId = fi1.FileId
  where fi1.InfoName = 'PDPActive' and fi1.Id = 1 and
        fi2.InfoName = 'DeviceOS' and fi2.Str_1 ='Android';


-- dbo.vAnalysisCommentSessions source

ALTER VIEW vAnalysisCommentSessions
AS
  Select s.SessionId, a.Comment, a.CommentId
  from Sessions s
       LEFT JOIN AnalysisCommentSessionsBridge bridge ON bridge.SessionId = s.SessionId
       LEFT JOIN AnalysisComment a ON a.CommentId = bridge.CommentId;


-- dbo.vAnalysisCommentSessionsB source

ALTER VIEW vAnalysisCommentSessionsB
AS
  Select s.SessionId, a.Comment, a.CommentId
  from SessionsB s
       LEFT JOIN AnalysisCommentSessionsBBridge bridge ON bridge.SessionId = s.SessionId
       LEFT JOIN AnalysisComment a ON a.CommentId = bridge.CommentId;


-- dbo.vAnalysisCommentTestInfo source

ALTER VIEW vAnalysisCommentTestInfo
AS
  Select t.SessionId, t.TestId, a.Comment, a.CommentId
  from TestInfo t
       LEFT JOIN AnalysisCommentTestInfoBridge bridge ON bridge.TestId = t.TestId
       LEFT JOIN AnalysisComment a ON a.CommentId = bridge.CommentId;


-- dbo.vAndroidPerformanceData source

ALTER VIEW vAndroidPerformanceData
AS
  Select MsgId,
         SessionId,
         MsgTime,
         dbo.DelphiDateTime(MsgTime) as dTime,
         CONVERT(varchar, MsgTime, 14) as msgTime2,
         BatteryLevel,
         BatteryTemp,
         case BatteryStatus
           when 0 then 'Unknown'
           when 1 then 'ChargingAC'
           when 2 then 'ChargingUSB'
           when 3 then 'Discharging'
           when 4 then 'NotCharging'
           when 5 then 'Full'
           when 6 then 'PauseAC'
           when 7 then 'PauseUSB'
         end as BatteryStatus,
         case BatteryHealth
           when 1 then 'Unknown'
           when 2 then 'Good'
           when 3 then 'Overheat'
           when 4 then 'Dead'
           when 5 then 'OverVoltage'
           when 6 then 'UnspecifiedFailure'
         end as BatteryHealth,
         case ScreenStatus
           when 0 then 'screen off'
           when 1 then 'screen on'
         end as ScreenStatus,
         CPUCores,
         RTRIM(REPLACE(CPUFreqencies, ';', '; ')) as CPUFreqencies,
         CPUTemp,
         CPULoad,
         CPULoadStatistics,
         CPULoadMainProcess,
         CPUScalingRate
  from AndroidPerformanceData;


-- dbo.vAppTestIPThroughput source

ALTER VIEW vAppTestIPThroughput
AS
  Select ap.TestId, a.ActionId,
         AVG(iDL.ThroughputKbps) as DLThput,
         AVG(iUL.ThroughputKbps) as ULThput
  from FactIPThroughput iDL
       JOIN FactIPThroughput iUL ON iUL.SessionId = iDL.SessionId
       JOIN ResultsAppActionSocialMedia a ON a.SessionId = iDL.SessionId
       JOIN ResultsAppTestParameters ap ON ap.TestId = a.TestId
  where a.AppTypeId in (1, 2) and ap.ServiceClass = 4 and
        iDL.Direction = 'Downlink' and
        iUL.Direction = 'Uplink' and
        iDL.FullDate between DATEADD(ms, a.InitDuration, a.StartTime) and DATEADD(ms, a.InitDuration + a.CoreDuration, a.StartTime) and
        iUL.FullDate between DATEADD(ms, a.InitDuration, a.StartTime) and DATEADD(ms, a.InitDuration + a.CoreDuration, a.StartTime)
  group by ap.TestId, a.ActionId;


-- dbo.vBandWCDMAPilotScan source

ALTER VIEW vBandWCDMAPilotScan
AS
  Select 'All Bands' As SelectBand
  UNION ALL
  Select Name AS SelectBand
  from vSQDefinitionsRFBand where RFBand in (Select DISTINCT RFBand from MsgWCDMAScannerPilotInfo);


-- dbo.vBestActiveCells source

ALTER VIEW vBestActiveCells
AS
SELECT sessionID,
       TestID,
       PosID,
       NetworkID,
       msgTime,
       numCells,
       FreqDL,
       Max(AggrEcIo_PSC)  AS MaxEcIo,
       Max(RSCP_PSC)  AS MaxRSCP,
       Max(AggrEcIo)  AS TotEcIo,
       Max(AggrRSCP)  AS TotRSCP,
       Max(case when AggrEcIo_PSC_A0 = -99 then NULL
                else AggrEcIo_PSC_A0 end)  AS MaxEcIo_A0,
       Max(case when AggrEcIo_PSC_A1 = -99 then NULL
                else AggrEcIo_PSC_A1 end)  AS MaxEcIo_A1

FROM WCDMAActiveSet

WHERE AggrEcIo_PSC <> -99 AND
      AggrEcIo <> -99 AND
      RSCP_PSC <> -200 AND
      AggrRSCP <> -200

GROUP BY sessionID,
	 TestID,
	 PosID,
	 NetworkID,
	 msgTime,
	 numCells,
	 FreqDL;


-- dbo.vBtsList source

ALTER VIEW vBtsList
as
SELECT 	'GSM' as technology,
	case when b.BCCH < 500 or b.BCCH > 900 then 'GSM'
	else 'DCS' end as SubTech,
	b.Id, b.MCC, b.MNC, b.LAC, b.CID,
	b.CellName + ' - ' + Convert(varchar, b.BCCH) + ' - ' + Convert(varchar, b.BSIC) + ' - ' + Convert(varchar, b.CID) + ' - ' + Convert(varchar, b.LAC) + ' - ' + Convert(varchar, b.MNC) + ' - ' + Convert(varchar, b.MCC) as BTSName,
	b.Longitude,
	b.Latitude,
	b.CellName,
	b.CGI,
	b.Direction,
	b.longitude + (SIN(RADIANS(Cast(b.Direction as float))) / COS(RADIANS(Cast(b.latitude as float))) * 0.001) as LonDiff,
	b.latitude + (COS(RADIANS(Cast(b.Direction as float))) * 0.001) as LatDiff,
	b.areaname,
	o.Display,
	b.BCCH,
	b.BSIC,
	NULL as NodeBIdentity,
	NULL as RNC,
	NULL as MSC,
	NULL as UARFCN,
	NULL as SC,
	NULL as RA,
	NULL as URA,
	NULL as TimeOffset,
	NULL as CPICH_POWER,
	NULL as MaxTxPower,
	NULL as AntHeight,
	NULL as AntType,
	NULL as AntGain,
	NULL as AntTilt,
	NULL as AntFeederLoss,

	NULL as TAC,
	NULL as EARFCN,
	NULL as PhyCID,
	NULL as TAI,
	NULL as ECGI,
	NULL as eNBID,
	NULL as GeNBID,

        Case when CIDN1   is NULL then ' ' else CONVERT(varchar,CIDN1)   end + '-' +
        Case when LACN1   is NULL then ' ' else CONVERT(varchar,LACN1)   end + '-' +
        Case when BCCHN1  is NULL then ' ' else CONVERT(varchar,BCCHN1)  end + '-' +
        Case when BSICN1  is NULL then ' ' else CONVERT(varchar,BSICN1)  end as N1Info,

        Case when CIDN2   is NULL then ' ' else CONVERT(varchar,CIDN2)   end + '-' +
        Case when LACN2   is NULL then ' ' else CONVERT(varchar,LACN2)   end + '-' +
        Case when BCCHN2  is NULL then ' ' else CONVERT(varchar,BCCHN2)  end + '-' +
        Case when BSICN2  is NULL then ' ' else CONVERT(varchar,BSICN2)  end as N2Info,

        Case when CIDN3   is NULL then ' ' else CONVERT(varchar,CIDN3)   end + '-' +
        Case when LACN3   is NULL then ' ' else CONVERT(varchar,LACN3)   end + '-' +
        Case when BCCHN3  is NULL then ' ' else CONVERT(varchar,BCCHN3)  end + '-' +
        Case when BSICN3  is NULL then ' ' else CONVERT(varchar,BSICN3)  end as N3Info,

        Case when CIDN4   is NULL then ' ' else CONVERT(varchar,CIDN4)   end + '-' +
        Case when LACN4   is NULL then ' ' else CONVERT(varchar,LACN4)   end + '-' +
        Case when BCCHN4  is NULL then ' ' else CONVERT(varchar,BCCHN4)  end + '-' +
        Case when BSICN4  is NULL then ' ' else CONVERT(varchar,BSICN4)  end as N4Info,

        Case when CIDN5   is NULL then ' ' else CONVERT(varchar,CIDN5)   end + '-' +
        Case when LACN5   is NULL then ' ' else CONVERT(varchar,LACN5)   end + '-' +
        Case when BCCHN5  is NULL then ' ' else CONVERT(varchar,BCCHN5)  end + '-' +
        Case when BSICN5  is NULL then ' ' else CONVERT(varchar,BSICN5)  end as N5Info,

        Case when CIDN6   is NULL then ' ' else CONVERT(varchar,CIDN6)   end + '-' +
        Case when LACN6   is NULL then ' ' else CONVERT(varchar,LACN6)   end + '-' +
        Case when BCCHN6  is NULL then ' ' else CONVERT(varchar,BCCHN6)  end + '-' +
        Case when BSICN6  is NULL then ' ' else CONVERT(varchar,BSICN6)  end as N6Info,

        Case when CIDN7   is NULL then ' ' else CONVERT(varchar,CIDN7)   end + '-' +
        Case when LACN7   is NULL then ' ' else CONVERT(varchar,LACN7)   end + '-' +
        Case when BCCHN7  is NULL then ' ' else CONVERT(varchar,BCCHN7)  end + '-' +
        Case when BSICN7  is NULL then ' ' else CONVERT(varchar,BSICN7)  end as N7Info,

        Case when CIDN8   is NULL then ' ' else CONVERT(varchar,CIDN8)   end + '-' +
        Case when LACN8   is NULL then ' ' else CONVERT(varchar,LACN8)   end + '-' +
        Case when BCCHN8  is NULL then ' ' else CONVERT(varchar,BCCHN8)  end + '-' +
        Case when BSICN8  is NULL then ' ' else CONVERT(varchar,BSICN8)  end as N8Info,

        Case when CIDN9   is NULL then ' ' else CONVERT(varchar,CIDN9)   end + '-' +
        Case when LACN9   is NULL then ' ' else CONVERT(varchar,LACN9)   end + '-' +
        Case when BCCHN9  is NULL then ' ' else CONVERT(varchar,BCCHN9)  end + '-' +
        Case when BSICN9  is NULL then ' ' else CONVERT(varchar,BSICN9)  end as N9Info,

        Case when CIDN10  is NULL then ' ' else CONVERT(varchar,CIDN10)  end + '-' +
        Case when LACN10  is NULL then ' ' else CONVERT(varchar,LACN10)  end + '-' +
        Case when BCCHN10 is NULL then ' ' else CONVERT(varchar,BCCHN10) end + '-' +
        Case when BSICN10 is NULL then ' ' else CONVERT(varchar,BSICN10) end as N10Info,

        Case when CIDN11  is NULL then ' ' else CONVERT(varchar,CIDN11)  end + '-' +
        Case when LACN11  is NULL then ' ' else CONVERT(varchar,LACN11)  end + '-' +
        Case when BCCHN11 is NULL then ' ' else CONVERT(varchar,BCCHN11) end + '-' +
        Case when BSICN11 is NULL then ' ' else CONVERT(varchar,BSICN11) end as N11Info,

        Case when CIDN12  is NULL then ' ' else CONVERT(varchar,CIDN12)  end + '-' +
        Case when LACN12  is NULL then ' ' else CONVERT(varchar,LACN12)  end + '-' +
        Case when BCCHN12 is NULL then ' ' else CONVERT(varchar,BCCHN12) end + '-' +
        Case when BSICN12 is NULL then ' ' else CONVERT(varchar,BSICN12) end as N12Info,

        Case when CIDN13  is NULL then ' ' else CONVERT(varchar,CIDN13)  end + '-' +
        Case when LACN13  is NULL then ' ' else CONVERT(varchar,LACN13)  end + '-' +
        Case when BCCHN13 is NULL then ' ' else CONVERT(varchar,BCCHN13) end + '-' +
        Case when BSICN13 is NULL then ' ' else CONVERT(varchar,BSICN13) end as N13Info,

        Case when CIDN14  is NULL then ' ' else CONVERT(varchar,CIDN14)  end + '-' +
        Case when LACN14  is NULL then ' ' else CONVERT(varchar,LACN14)  end + '-' +
        Case when BCCHN14 is NULL then ' ' else CONVERT(varchar,BCCHN14) end + '-' +
        Case when BSICN14 is NULL then ' ' else CONVERT(varchar,BSICN14) end as N14Info,

        Case when CIDN15  is NULL then ' ' else CONVERT(varchar,CIDN15)  end + '-' +
        Case when LACN15  is NULL then ' ' else CONVERT(varchar,LACN15)  end + '-' +
        Case when BCCHN15 is NULL then ' ' else CONVERT(varchar,BCCHN15) end + '-' +
        Case when BSICN15 is NULL then ' ' else CONVERT(varchar,BSICN15) end as N15Info,

        Case when CIDN16  is NULL then ' ' else CONVERT(varchar,CIDN16)  end + '-' +
        Case when LACN16  is NULL then ' ' else CONVERT(varchar,LACN16)  end + '-' +
        Case when BCCHN16 is NULL then ' ' else CONVERT(varchar,BCCHN16) end + '-' +
        Case when BSICN16 is NULL then ' ' else CONVERT(varchar,BSICN16) end as N16Info,

        Case when CIDN17  is NULL then ' ' else CONVERT(varchar,CIDN17)  end + '-' +
        Case when LACN17  is NULL then ' ' else CONVERT(varchar,LACN17)  end + '-' +
        Case when BCCHN17 is NULL then ' ' else CONVERT(varchar,BCCHN17) end + '-' +
        Case when BSICN17 is NULL then ' ' else CONVERT(varchar,BSICN17) end as N17Info,

        Case when CIDN18  is NULL then ' ' else CONVERT(varchar,CIDN18)  end + '-' +
        Case when LACN18  is NULL then ' ' else CONVERT(varchar,LACN18)  end + '-' +
        Case when BCCHN18 is NULL then ' ' else CONVERT(varchar,BCCHN18) end + '-' +
        Case when BSICN18 is NULL then ' ' else CONVERT(varchar,BSICN18) end as N18Info,

        Case when CIDN19  is NULL then ' ' else CONVERT(varchar,CIDN19)  end + '-' +
        Case when LACN19  is NULL then ' ' else CONVERT(varchar,LACN19)  end + '-' +
        Case when BCCHN19 is NULL then ' ' else CONVERT(varchar,BCCHN19) end + '-' +
        Case when BSICN19 is NULL then ' ' else CONVERT(varchar,BSICN19) end as N19Info,

        Case when CIDN20  is NULL then ' ' else CONVERT(varchar,CIDN20)  end + '-' +
        Case when LACN20  is NULL then ' ' else CONVERT(varchar,LACN20)  end + '-' +
        Case when BCCHN20 is NULL then ' ' else CONVERT(varchar,BCCHN20) end + '-' +
        Case when BSICN20 is NULL then ' ' else CONVERT(varchar,BSICN20) end as N20Info,

	NULL as N21Info,
	NULL as N22Info,
	NULL as N23Info,
	NULL as N24Info,
	NULL as N25Info,
	NULL as N26Info,
	NULL as N27Info,
	NULL as N28Info,
	NULL as N29Info,
	NULL as N30Info,
	NULL as N31Info,
	NULL as N32Info
from 	BTSList b, Operators o
where   b.MCC = o.MCC and b.MNC = o.MNC

UNION

SELECT 	'UMTS' as technology,
	'UMTS' as SubTech,
	b.Id, b.MCC, b.MNC, b.LAC, b.CID,
	b.CellName + ' - ' + Convert(varchar, b.UARFCN) + ' - ' + Convert(varchar, b.SC) + ' - ' + Convert(varchar, b.CID) + ' - ' + Convert(varchar, b.LAC) + ' - ' + Convert(varchar, b.MNC) + ' - ' + Convert(varchar, b.MCC) as BTSName,
	b.Longitude,
	b.Latitude,
	b.CellName,
	b.CGI,
	b.AntDirection as Direction,
	b.longitude + (SIN(RADIANS(Cast(b.AntDirection as float))) / COS(RADIANS(Cast(b.latitude as float))) * 0.001) as LonDiff,
	b.latitude + (COS(RADIANS(Cast(b.AntDirection as float))) * 0.001) as LatDiff,
	b.areaname,
	o.Display,
	NULL as BCCH,
	NULL as BSIC,
	NodeBIdentity,
	RNC,
	MSC,
	UARFCN,
	SC,
	RA,
	URA,
	TimeOffset,
	CPICH_POWER,
	MaxTxPower,
	AntHeight,
	AntType,
	AntGain,
	AntTilt,
	AntFeederLoss,

	NULL as TAC,
	NULL as EARFCN,
	NULL as PhyCID,
	NULL as TAI,
	NULL as ECGI,
	NULL as eNBID,
	NULL as GeNBID,

	CONVERT(varchar,CellIdN1)  + '-' + CONVERT(varchar,SCN1)  as N1Info,
	CONVERT(varchar,CellIdN2)  + '-' + CONVERT(varchar,SCN2)  as N2Info,
	CONVERT(varchar,CellIdN3)  + '-' + CONVERT(varchar,SCN3)  as N3Info,
	CONVERT(varchar,CellIdN4)  + '-' + CONVERT(varchar,SCN4)  as N4Info,
	CONVERT(varchar,CellIdN5)  + '-' + CONVERT(varchar,SCN5)  as N5Info,
	CONVERT(varchar,CellIdN6)  + '-' + CONVERT(varchar,SCN6)  as N6Info,
	CONVERT(varchar,CellIdN7)  + '-' + CONVERT(varchar,SCN7)  as N7Info,
	CONVERT(varchar,CellIdN8)  + '-' + CONVERT(varchar,SCN8)  as N8Info,
	CONVERT(varchar,CellIdN9)  + '-' + CONVERT(varchar,SCN9)  as N9Info,
	CONVERT(varchar,CellIdN10) + '-' + CONVERT(varchar,SCN10) as N10Info,
	CONVERT(varchar,CellIdN11) + '-' + CONVERT(varchar,SCN11) as N11Info,
	CONVERT(varchar,CellIdN12) + '-' + CONVERT(varchar,SCN12) as N12Info,
	CONVERT(varchar,CellIdN13) + '-' + CONVERT(varchar,SCN13) as N13Info,
	CONVERT(varchar,CellIdN14) + '-' + CONVERT(varchar,SCN14) as N14Info,
	CONVERT(varchar,CellIdN15) + '-' + CONVERT(varchar,SCN15) as N15Info,
	CONVERT(varchar,CellIdN16) + '-' + CONVERT(varchar,SCN16) as N16Info,
	CONVERT(varchar,CellIdN17) + '-' + CONVERT(varchar,SCN17) as N17Info,
	CONVERT(varchar,CellIdN18) + '-' + CONVERT(varchar,SCN18) as N18Info,
	CONVERT(varchar,CellIdN19) + '-' + CONVERT(varchar,SCN19) as N19Info,
	CONVERT(varchar,CellIdN20) + '-' + CONVERT(varchar,SCN20) as N20Info,
	CONVERT(varchar,CellIdN21) + '-' + CONVERT(varchar,SCN21) as N21Info,
	CONVERT(varchar,CellIdN22) + '-' + CONVERT(varchar,SCN22) as N22Info,
	CONVERT(varchar,CellIdN23) + '-' + CONVERT(varchar,SCN23) as N23Info,
	CONVERT(varchar,CellIdN24) + '-' + CONVERT(varchar,SCN24) as N24Info,
	CONVERT(varchar,CellIdN25) + '-' + CONVERT(varchar,SCN25) as N25Info,
	CONVERT(varchar,CellIdN26) + '-' + CONVERT(varchar,SCN26) as N26Info,
	CONVERT(varchar,CellIdN27) + '-' + CONVERT(varchar,SCN27) as N27Info,
	CONVERT(varchar,CellIdN28) + '-' + CONVERT(varchar,SCN28) as N28Info,
	CONVERT(varchar,CellIdN29) + '-' + CONVERT(varchar,SCN29) as N29Info,
	CONVERT(varchar,CellIdN30) + '-' + CONVERT(varchar,SCN30) as N30Info,
	CONVERT(varchar,CellIdN31) + '-' + CONVERT(varchar,SCN31) as N31Info,
	CONVERT(varchar,CellIdN32) + '-' + CONVERT(varchar,SCN32) as N32Info

from    umtsbtsList b, Operators o
where   b.MCC = o.MCC and b.MNC = o.MNC

UNION

SELECT 	'CDMA' as technology,
	'CDMA' as SubTech,
        b.Id,
        b.MCC,
        b.SID as MNC,
        b.Channel as LAC,
        b.PN as CID,
        b.CellName + ' - ' + Convert(varchar, b.PN) + ' - ' + Convert(varchar, b.Channel) + ' - ' + Convert(varchar, b.SID) + ' - ' + Convert(varchar, b.MCC) as BTSName,
	b.Longitude,
	b.Latitude,
	b.CellName,
	b.CGI,
	b.Angle as Direction,
	b.longitude + (SIN(RADIANS(Cast(b.Angle as float))) / COS(RADIANS(Cast(b.latitude as float))) * 0.001) as LonDiff,
	b.latitude + (COS(RADIANS(Cast(b.Angle as float))) * 0.001) as LatDiff,
	b.areaname,
	o.Display,
	NULL as BCCH,
