-- dbo.vCDMAFER source

ALTER VIEW vCDMAFER
as
select
	a.msgTime,
	a.sessionID,
	a.TestID,
	a.networkID,
	a.posID,
	datediff(ms,a.msgTime,b.msgTime) as TimeDiff,
	b.tffch-a.tffch as Frames,
	case when b.tffch-a.tffch <> 0 then (cast((b.bffch - a.bffch) as float) / cast((b.tffch-a.tffch) as float))*100
        else 0.0 end as cFER
from
	CDMAFER a,
	CDMAFER b
where
	a.msgID+1 = b.msgID and
	a.sessionID = b.sessionID and
	b.tffch-a.tffch <> 0;


