where   i.FwdPowerControlInfoID = p.FwdPowerControlInfoID;


-- dbo.vCDMALayer3 source

ALTER VIEW vCDMALayer3 AS
  Select FactId as MsgId,
         SessionId,
         VirtualTestId as TestId,
         FullDate as MsgTime,
         PosId,
         NetworkId,
         Message as Msg,
         Identifier3 as LogCode,
         m.SubCategory as MessageClass,
         SimpleMsgName as MessageType,
         Identifier2 as MsgType,
         Identifier4 as Channel,
         Technology as Layer3Type,
         CONVERT(varchar, Identifier) COLLATE Latin1_General_CI_AS as ProtDiscr
  from FactL3Messages f
       JOIN CDMAL3Messages m ON m.Channel = f.Identifier4 and
                                m.MsgType = f.Identifier2
  where Technology = 'CDMA'

  UNION

  Select FactId as MsgId,
         SessionId,
         VirtualTestId as TestId,
         FullDate as MsgTime,
         PosId,
         NetworkId,
         Message as Msg,
         Identifier3 as LogCode,
         m.SubCategory as MessageClass,
         SimpleMsgName as MessageType,
         CONVERT(varchar, dbo.HexToInt(m.MsgType)) COLLATE Latin1_General_CI_AS as MsgType,
         Identifier4 as Channel,
         Technology as Layer3Type,
         UPPER(m.ProtDiscr) COLLATE Latin1_General_CI_AS as ProtDiscr
  from FactL3Messages f
       JOIN EvDOL3Messages m ON m.ProtDiscr = SUBSTRING(f.Message, 47, 2) and
                                m.MsgType = SUBSTRING(f.Message, 49, 2)
  where Technology = 'EVDO';


