-- dbo.vCDMASystemParameter source

ALTER VIEW vCDMASystemParameter As
select sessionId, testId, msgTime, PosId, NetworkId, Pilot_PN, SID, NID, BID,
      CASE When SearchWinA = 0 Then 4
	   When SearchWinA = 1 Then 6
	   When SearchWinA = 2 Then 8
	   When SearchWinA = 3 Then 10
	   When SearchWinA = 4 Then 14
           When SearchWinA = 5 Then 20
	   When SearchWinA = 6 Then 28
	   When SearchWinA = 7 Then 40
	   When SearchWinA = 8 Then 60
           When SearchWinA = 9 Then 80
	   When SearchWinA = 10 Then 100
	   When SearchWinA = 11 Then 130
	   When SearchWinA = 12 Then 160
	   When SearchWinA = 13 Then 226
	   When SearchWinA = 14 Then 320
           When SearchWinA = 15 Then 452 end as SearchWinA,
      CASE When SearchWinN = 0 Then 4
	   When SearchWinN = 1 Then 6
	   When SearchWinN = 2 Then 8
	   When SearchWinN = 3 Then 10
	   When SearchWinN = 4 Then 14
           When SearchWinN = 5 Then 20
	   When SearchWinN = 6 Then 28
	   When SearchWinN = 7 Then 40
	   When SearchWinN = 8 Then 60
           When SearchWinN = 9 Then 80
	   When SearchWinN = 10 Then 100
	   When SearchWinN = 11 Then 130
	   When SearchWinN = 12 Then 160
	   When SearchWinN = 13 Then 226
	   When SearchWinN = 14 Then 320
           When SearchWinN = 15 Then 452 end as SearchWinN,
T_ADD, T_DROP, T_COMP,
	CASE When T_TDROP = 0 Then 0.1
	     When T_TDROP = 1 Then 1
	     When T_TDROP = 2 Then 2
	     When T_TDROP = 3 Then 4
	     When T_TDROP = 4 Then 6
	     When T_TDROP = 5 Then 9
	     When T_TDROP = 6 Then 13
	     When T_TDROP = 7 Then 19
	     When T_TDROP = 8 Then 27
	     When T_TDROP = 9 Then 39
	     When T_TDROP = 10 Then 55
	     When T_TDROP = 11 Then 79
	     When T_TDROP = 12 Then 112
	     When T_TDROP = 13 Then 159
	     When T_TDROP = 14 Then 225
	     When T_TDROP = 15 Then 319 end as T_TDROP
from msgCDMASystemParameter;


-- dbo.vCDMATotalEcIo source

ALTER  VIEW vCDMATotalEcIo
AS

select
         sessionID,
