-- dbo.vChannelRequest source

ALTER VIEW vChannelRequest
AS
  Select FactId as MsgId,
         SessionId,
         VirtualTestId as TestId,
         FullDate as MsgTime,
         PosId,
         NetworkId,
         Message,
         Identifier3 as ParseCode,
         Message as DataSent,
         SimpleMsgName as ChReqType,
         Identifier
  from FactL3Messages
  where Technology = 'GSM' and
        Identifier in (6, 7, 8, 9);


-- dbo.vDNSResolution source

ALTER VIEW vDNSResolution
AS
	Select
		    k.*,
			e.MsgTime as MsgTimeEthereal,
			e.src,
			e.dst,
			e.protocol,
			e.msg as Etherealmsg,
			SUBSTRING(e.msg,18,LEN(e.msg)) as site
	from
			vResultsKPI k,
			MsgEthereal e
	where
			k.SessionId = e.SessionId and
			k.TestId = k.TestId and
			k.KPIId = 31100 and
			k.value3 = e.msg and
			DATEDIFF(ms,k.StartTime,e.MsgTime) < 4 and
			DATEDIFF(ms,e.MsgTime,k.StartTime) < 4 and
			e.protocol = 'DNS';


-- dbo.vDataTestInfoTechnology source

ALTER VIEW vDataTestInfoTechnology
AS
  Select Sessions.FileId,
         TestInfo.SessionId,
         TestInfo.TestId,
         Sessions.sessionType,
         TestInfo.startTime,
         DATEADD(ms, TestInfo.duration, TestInfo.startTime) as Endtime,
         Technology.Summary as Technology
  from Sessions
       JOIN TestInfo ON TestInfo.SessionId = Sessions.SessionId
       JOIN Technology ON Technology.TestId = Testinfo.TestId
  where Technology.TriggerMsg like 'Test end%';


-- dbo.vEDGECodingScheme source

ALTER VIEW vEDGECodingScheme
as
select
	c.msgID,
	c.sessionID,
	c.testID,
	c.msgTime,
	c.posID,
	c.NetworkID,
	'DL'as Link,
	DLCS as MCS,
	convert(float,c.duration)/1000 as duration
from
	CodingScheme c
where
	technology = 'EDGE' and
	DLCS is not NULL

Union
	select
	c.msgID,
	c.sessionID,
	c.testID,
	c.msgTime,
	c.posID,
	c.NetworkID,
	'UL'as Link,
	ULCS as MCS,
	convert(float,c.duration)/1000 as duration
from
	CodingScheme c
where
	technology = 'EDGE' and
	ULCS is not NULL;


-- dbo.vEGPRSMSBEP source

ALTER VIEW vEGPRSMSBEP
AS
  Select FactId as MsgId,
         SessionId,
         VirtualTestId as TestId,
         FullDate as MsgTime,
         PosId,
         NetworkId,
         Identifier2 as MsgType,
         case
           when ((dbo.HexToInt(SUBSTRING(Message, 11, 1))) & 12) / 4 = 2 then '8PSK'
           when ((dbo.HexToInt(SUBSTRING(Message, 11, 1))) & 12) / 4 = 3 and
                ((dbo.HexToInt(SUBSTRING(Message, 13, 1))) & 2) / 2 = 1 then 'GMSK&8PSK'
           when ((dbo.HexToInt(SUBSTRING(Message, 11, 1))) & 12) / 4 = 3 then 'GMSK'
         end as Modulation,

         case
           when ((dbo.HexToInt(SUBSTRING(Message, 11, 1))) & 12) / 4 = 2 then ((dbo.HexToInt(SUBSTRING(Message, 11, 2))) & 31)
           when ((dbo.HexToInt(SUBSTRING(Message, 11, 1))) & 14) / 4 = 3 and
                ((dbo.HexToInt(SUBSTRING(Message, 13, 1))) & 2) / 2 = 1 then ((dbo.HexToInt(SUBSTRING(Message, 13, 2))) & 31)
         end as PSKMeanBEP,

         case
           when ((dbo.HexToInt(SUBSTRING(Message, 11, 1))) & 12) / 4 = 2 then ((dbo.HexToInt(SUBSTRING(Message, 13, 1))) & 14) / 2
           when ((dbo.HexToInt(SUBSTRING(Message, 11, 1))) & 14) / 4 = 3 and
                ((dbo.HexToInt(SUBSTRING(Message, 13, 1))) & 2) / 2 = 1 then ((dbo.HexToInt(SUBSTRING(Message, 15, 1))) & 14) / 2
         end as PSKCVBEP,

         case
           when ((dbo.HexToInt(SUBSTRING(Message, 11, 1))) & 12) / 4 = 3 and
                ((dbo.HexToInt(SUBSTRING(Message, 13, 1))) & 2) / 2 = 1 then ((dbo.HexToInt(SUBSTRING(Message, 11, 2))) & 63) / 2
           when ((dbo.HexToInt(SUBSTRING(Message, 11, 1))) & 12) / 4 = 3 then ((dbo.HexToInt(SUBSTRING(Message, 11, 2))) & 63) / 2
         end as GMSKMeanBEP,

         case
           when ((dbo.HexToInt(SUBSTRING(Message, 11, 1))) & 12) / 4 = 3 and
                ((dbo.HexToInt(SUBSTRING(Message, 13, 1))) & 2) / 2 = 1 then ((dbo.HexToInt(SUBSTRING(Message, 12, 2))) & 31) / 4
           when ((dbo.HexToInt(SUBSTRING(Message, 11, 1))) & 12) / 4 = 3 then ((dbo.HexToInt(SUBSTRING(Message, 12, 2))) & 31) / 4
         end as GMSKCVBEP
  from FactL3Messages
  where Technology = 'GSM' and
        Identifier = 5 and  -- UL only
        Identifier2 = '08';


-- dbo.vETSISupplementaryKPIs source

/*
tr1 Start of player download TCP SYN towards streaming platform
tr1a (old tr5) Start of video transfer Reception of the HTTP 200 OK for the
tr2 (old tr6) Start of video playout (first frame displayed in player)

Video Preparation, tr1 tr1a
Video Preparation Time [s], tr1 tr1a

Pre-Playout Buffering, tr1a tr2
Pre-Playout Buffering Time [s], tr1a tr2
*/

ALTER VIEW vETSISupplementaryKPIs
AS
  Select kpi.SessionId,
         kpi.TestId,
         kpi.TriggerType,
         st.URL,

         case
           when kpi.VideoAccess <> 0 then 'Video Access Failed'
           else case
                  when kpi.VideoAccessDuration > CONVERT(float, va.Settings) then 'Video Access Timeout exceeded'
                  else case
                         when kpi.Reproduction <> 0 then 'Video Reproduction Failed'
                         else case
                                when kpi.ReproductionDelay > CONVERT(float, vr.Settings) then 'Video Reproduction Timeout exceeded'
                                else 'Successful'
                              end
                       end
                end
         end                                                                                                                                        as VideoStatus,

         case when kpi.VideoPlayout = 0 then 'Successful' else 'Playout failed' end                                                                 as VideoPlayoutStatus,

         case
           when f.NumFreezings > mnf.Settings then 'Number of freezings exceeded (' + mnf.Settings + ') '
           else case
                  when (1.0 * f.MaxFreezingTime) / 1000.0 > msf.Settings then 'Max single freezing exceeded (' + msf.Settings + 's)'
                  else case
                         when (1.0 * f.AccFreezingTime) / 1000.0 > maf.Settings then 'Max accumulated freezing exceeded (' + maf.Settings + 's)'
                         else 'Successful'
                       end
                end
         end                                                                                                                                        as FreezeStatus,

         case when kpi.IPAccess = 0  then 'Successful' else case when CHARINDEX('App', st.Player) > 0 then 'unavailable' else 'Failed' end end      as VideoPreparation,
         case when kpi.IPAccess = 0  then kpi.IPAccessDuration else NULL end                                                                        as VideoPreparationTime,

         case when kpi.Reproduction = 0  then 'Successful' else case when CHARINDEX('App', st.Player) > 0 then 'unavailable' else 'Failed' end end  as PrePlayoutBuffering,
         case when kpi.Reproduction = 0  then kpi.ReproductionDelay else NULL end                                                                   as PrePlayoutBufferingTime,

         CONVERT(float, va.Settings)  as VideoAccessTimeOut,
         CONVERT(float, vr.Settings)  as VideoReproductionTimeOut,

         CONVERT(float, mf.Settings)  as MinimumFreezeDuration,
         CONVERT(float, msf.Settings) as MaximumDurationSingleFreeze,
         CONVERT(float, maf.Settings) as MaximumDurationAccFreezes,
         CONVERT(float, mnf.Settings) as MaximumNumberFreezes

  from ETSIYouTubeTriggerSelectiveKPIs kpi
       JOIN ResultsVideoStream st ON st.TestId = kpi.TestId
       JOIN vResultsVideoStreamFreezingsAvg f ON f.TestId = kpi.TestId
       JOIN SQGeneralSettings va ON va.Identifier = 'ETSI_YouTube_KPI_Video IP Service Access timeout'
       JOIN SQGeneralSettings vr ON vr.Identifier = 'ETSI_YouTube_KPI_Video reproduction start delay timeout'
       JOIN SQGeneralSettings mf ON mf.Identifier  = 'ETSI_YouTube_KPI_Minimum freeze duration'
       JOIN SQGeneralSettings msf ON msf.Identifier = 'ETSI_YouTube_KPI_Maximum duration of single freeze'
       JOIN SQGeneralSettings maf ON maf.Identifier = 'ETSI_YouTube_KPI_Maximum duration of all freezes'
       JOIN SQGeneralSettings mnf ON mnf.Identifier = 'ETSI_YouTube_KPI_Maximum number of freezes';


-- dbo.vETSISupplementaryKPIsFormat source

ALTER VIEW vETSISupplementaryKPIsFormat
AS
  Select t.SessionId,
         t.TestId,
         t.TestName,
         NULL                            as ' ',
         kpi.VideoPreparation            as 'Video Preparation',
         kpi.VideoPreparationTime        as 'Video Preparation Time [s]',
         kpi.PrePlayoutBuffering         as 'Pre-Playout Buffering',
         kpi.PrePlayoutBufferingTime     as 'Pre-Playout Buffering Time [s]',
         NULL                            as '	',
         kpi.VideoAccessTimeOut          as 'Video IP Service Access TimeOut [s]',
         kpi.VideoReproductionTimeOut    as 'Video Reproduction Start TimeOut [s]',
         kpi.MinimumFreezeDuration       as 'Minimum freeze duration [ms]',
         kpi.MaximumDurationSingleFreeze as 'Maximum duration of single freeze [s]',
         kpi.MaximumDurationAccFreezes   as 'Maximum duration of all freezes [s]',
         kpi.MaximumNumberFreezes        as 'Maximum number of freezes',
         kpi.TriggerType                 as 'Used trigger to calculate KPIs'
  from TestInfo t
       JOIN vETSISupplementaryKPIs kpi ON kpi.TestId = t.TestId
  where dbo.IsStreamingAppTest(t.typeoftest) = 1;


-- dbo.vETSIYouTubeFreezings source

ALTER VIEW vETSIYouTubeFreezings
AS
  Select t.TestId,
         t.TestName,
         (1.0 * f.AccFreezingTime) / 1000.0                                                    as AccFreezingTime,
         (1.0 * f.AvgFreezingTime) / 1000.0                                                    as AvgFreezingTime,
         (1.0 * f.MaxFreezingTime) / 1000.0                                                    as MaxFreezingTime,
         ISNULL(f.NumFreezings, 0)                                                             as NumFreezings,
         case when f.NumFreezings > 0 then 'Freezings' else 'No Freezings' end                 as Freezings,

         case
           when kpi.VideoPlayout is NULL then NULL
           else case
                  when kpi.VideoPlayout = 0 and ISNULL(f.NumFreezings, 0) = 0 then 'Successful'
                  else 'Failed'
                end
         end                                                                                   as ImpairmentFree,
         kpi20621.Duration / 1000.0                                                            as PlayoutDuration,

         case
           when st.VideoDuration > 0 then ((1.0 * f.AccFreezingTime) / 1000.0) / st.VideoDuration * 100.0
           else NULL
         end                                                                                   as FreezingProportion,

         case
           when NumFreezings > mnf.Settings then 'Number of freezings exceeded (' + mnf.Settings + ') '
           else case
                  when (1.0 * f.MaxFreezingTime) / 1000.0 > msf.Settings then 'Max single freezing exceeded (' + msf.Settings + 's)'
                  else case
                         when (1.0 * f.AccFreezingTime) / 1000.0 > maf.Settings then 'Max accumulated freezing exceeded (' + maf.Settings + 's)'
                         else 'Successful'
                       end
                end
         end                                                                                   as Status,
         CONVERT(float, mf.Settings)                                                           as MinimumFreezeDuration,
         CONVERT(float, msf.Settings)                                                          as MaximumDurationSingleFreeze,
         CONVERT(float, maf.Settings)                                                          as MaximumDurationAccFreezes,
         CONVERT(float, mnf.Settings)                                                          as MaximumNumberFreezes,

         st.URL,
         st.VideoCodec,
         st.VideoResolution,
         st.VideoDuration,
         st.Player,
         kpi.TriggerType
  from TestInfo t
       LEFT JOIN vResultsVideoStreamFreezingsAvg f ON t.TestId = f.TestId
       LEFT JOIN ETSIYouTubeTriggerSelectiveKPIs kpi ON kpi.TestId = t.TestId
       LEFT JOIN vResultsKPI kpi20621 ON t.TestId = kpi20621.TestId and kpi20621.KPIId = 20621
       JOIN SQGeneralSettings mf  ON mf.Identifier  = 'ETSI_YouTube_KPI_Minimum freeze duration'
       JOIN SQGeneralSettings msf ON msf.Identifier = 'ETSI_YouTube_KPI_Maximum duration of single freeze'
       JOIN SQGeneralSettings maf ON maf.Identifier = 'ETSI_YouTube_KPI_Maximum duration of all freezes'
       JOIN SQGeneralSettings mnf ON mnf.Identifier = 'ETSI_YouTube_KPI_Maximum number of freezes'
       LEFT JOIN ResultsVideoStream st on t.TestId = st.TestId
  where dbo.IsStreamingAppTest(t.typeoftest) = 1;


-- dbo.vETSIYouTubeKPIs source

ALTER VIEW vETSIYouTubeKPIs
AS
  Select t.SessionId,
         t.TestId,
         t.TestName,
         r.Player,
         r.URL,
         r.VideoCodecYT,
         ISNULL(r.ViewingResolution, 0) as ViewingResolution,
         -- Initialized to Displaying
         case when ISNULL(DATEDIFF(ms, vi.MsgTime, vy.MsgTime) * 0, 108002) = 0 then 'Successful' else 'Failed' end                              as VideoAccess,
         case when ISNULL(DATEDIFF(ms, vi.MsgTime, vy.MsgTime) * 0, 108002) = 0 then DATEDIFF(ms, vi.MsgTime, vy.MsgTime) / 1000.0 else NULL end as VideoAccessDuration,
         -- Displaying to (End reached or correct Status)
         case when (ISNULL(DATEDIFF(ms, vy.MsgTime, vr.MsgTime) * 0, 108002) = 0) or
                   (vy.MsgTime IS NOT NULL and r.State in ('Completed', 'Stopped')) then 'Successful' else 'Failed' end                          as VideoPlayout,
         case when ISNULL(DATEDIFF(ms, vy.MsgTime, vr.MsgTime) * 0, 108002) = 0 then DATEDIFF(ms, vy.MsgTime, vr.MsgTime) / 1000.0
              when vy.MsgTime IS NOT NULL and r.State in ('Completed', 'Stopped') then vs.SequenceLength
              else NULL
         end                                                                                                                                     as VideoPlayoutDuration,

         -- Video Access to Playout ok and no Freezing
         case when ISNULL(DATEDIFF(ms, vi.MsgTime, vy.MsgTime) * 0, 108002) = 0 and
                   ((ISNULL(DATEDIFF(ms, vy.MsgTime, vr.MsgTime) * 0, 108002) = 0) or
                    (vy.MsgTime IS NOT NULL and r.State in ('Completed', 'Stopped'))) and
                   ISNULL(f.NumFreezings, 0) = 0 then 'Successful' else 'Failed' end                                                             as ImpairmentFreeVideoSession,

         -- Displaying to (End reached or correct Status) and SequenceLength > 0 -> calculate time
         case when (ISNULL(DATEDIFF(ms, vy.MsgTime, vr.MsgTime) * 0, 108002) = 0 or
                    (vy.MsgTime IS NOT NULL and r.State in ('Completed', 'Stopped')))
                   and ISNULL(vs.SequenceLength, 0) > 0
              then Round(ISNULL(((1.0 * f.AccFreezingTime) / 1000.0) / vs.SequenceLength * 100.0, 0), 2) else NULL end                           as FreezingTimeRatio,

         av.RatioFullHD,
         av.Ratio4k,
         av.RatioAdvert

  from TestInfo t
       LEFT JOIN VideoStatusTrace vi ON vi.TestId = t.TestId and vi.Event = 'Initialized'        --tr1
       LEFT JOIN VideoStatusTrace vy ON vy.TestId = t.TestId and vy.Event = 'Displaying'         --tr6
       LEFT JOIN VideoStatusTrace vr ON vr.TestId = t.TestId and vr.Event in ('Clip end reached', 'Video display duration reached') --tr8  -- intentional stop as valid end trigger added
       LEFT JOIN vResultsVideoStreamFreezingsAvg f ON f.TestId = t.TestId
       LEFT JOIN ResultsVideoStream r ON r.TestId = t.TestId
       LEFT JOIN VideoSettingsInfo vs ON vs.SampleId = t.TestId
       LEFT JOIN ResultsVQ08StreamAvg av ON av.TestId = t.TestId
  where dbo.IsStreamingAppTest(t.typeoftest) = 1;


-- dbo.vETSIYouTubeKPIsFormat source

ALTER VIEW vETSIYouTubeKPIsFormat
AS
  SELECT t.SessionId,
         t.TestId,
         t.typeoftest,
         app.VideoAccess                    as 'Video Access',
         app.VideoAccessDuration            as 'Video Access Time [s]',
         app.VideoPlayout                   as 'Video Playout',
         app.VideoPlayoutDuration           as 'Video Playout Duration [s]',
         app.ImpairmentFreeVideoSession     as 'Impairment Free Video Session',
         app.FreezingTimeRatio              as 'Video Freezing Time Proportion [%]'
  FROM TestInfo t
       JOIN vETSIYouTubeKPIs app ON t.TestId = app.TestId;


-- dbo.vETSIYouTubeStream source

/*
tr-4 Start of video download (pressing "Play") TCP SYN towards streaming platform
tr-5 Start of video transfer Reception of the HTTP 200 OK for the
tr-6 Start of video playout (first frame displayed in player)

4.3.7,	Video IP Service Access Failure Ratio [%], tr-4 tr-5,  Which of the alternatives of the start trigger point definition tr-4 was chosen
4.3.8,	Video IP Service Access Time [s], tr-4 tr-5, Which of the alternatives of the start trigger point definition tr-4 was chosen
4.3.9,	Video Reproduction Start Failure Ratio [%], tr-5 tr-6
4.3.10, Video Reproduction Start Delay [s], tr-5 tr-6
4.3.11, Video Play Start Failure Ratio [%], tr-4 tr-6  Which of the alternatives of the start trigger point definition tr-4 was chosen
4.3.12, Video Play Start Time [s], tr-4 tr-6, Which of the alternatives of the start trigger point definition tr-4 was chosen
*/
ALTER VIEW vETSIYouTubeStream
AS
  Select t.TestId,
         t.TestName,

         case when kpi.VideoAccess = 0  then 'Successful' else 'Failed'end                     as Access,
         kpi.VideoAccessDuration                                                               as AccessDuration,
         CONVERT(float, va.Settings)                                                           as AccessTimeOut,
         case
           when kpi.VideoAccess = 0 and kpi.VideoAccessDuration < CONVERT(float, va.Settings) then 'Successful'
           else 'Failed'
         end                                                                                   as AccessWithTimeOut,

         case when kpi.Reproduction = 0 then 'Successful' else 'Failed' end                    as Reproduction,
         kpi.ReproductionDelay                                                                 as ReproductionDelay,
         CONVERT(float, vr.Settings)                                                           as ReproductionTimeOut,
         case
           when kpi.Reproduction  = 0 and kpi.ReproductionDelay < CONVERT(float, vr.Settings) then 'Successful'
           else 'Failed'
         end                                                                                   as ReproductionWithTimeOut,

         case when kpi.PlayoutAccess = 0 then 'Successful' else 'Failed' end                   as Play,
         kpi.PlayoutAccessDuration                                                             as PlayDelay,
         case
           when kpi.VideoAccess = 0 and kpi.VideoAccessDuration < CONVERT(float, va.Settings) and
                kpi.Reproduction = 0 and kpi.ReproductionDelay < CONVERT(float, vr.Settings) then 'Successful'
           else 'Failed'
         end                                                                                   as PlayWithTimeOut,

         case
           when kpi.VideoAccess <> 0 then 'Video Access Failed'
           else case
                  when kpi.VideoAccessDuration > CONVERT(float, va.Settings) then 'Video Access Timeout exceeded'
                  else case
                         when kpi.Reproduction <> 0 then 'Video Reproduction Failed'
                         else case
                                when kpi.ReproductionDelay > CONVERT(float, vr.Settings) then 'Video Reproduction Timeout exceeded'
                                else 'Successful'
                              end
                       end
                end
         end                                                                                   as Status,

         case
           when kpi.VideoAccess = 0 and kpi.Reproduction = 0 then 0
           else case
                  when kpi.VideoAccess <> 0 then kpi.VideoAccess
                  else kpi.Reproduction
                end
         end                                                                                   as ErrorCode,
         st.URL,
         st.VideoCodecYT,
         st.VideoResolution,
         st.Player,
         kpi.TriggerType
  from TestInfo t
       JOIN ETSIYouTubeTriggerSelectiveKPIs kpi ON t.TestId = kpi.TestId
       JOIN ResultsVideoStream st ON t.TestId = st.TestId
       JOIN SQGeneralSettings va ON va.Identifier = 'ETSI_YouTube_KPI_Video IP Service Access timeout'
       JOIN SQGeneralSettings vr on vr.Identifier = 'ETSI_YouTube_KPI_Video reproduction start delay timeout'
  where dbo.IsStreamingAppTest(t.typeoftest) = 1;


-- dbo.vETSIYouTubeTriggerSelectiveKPIs source

ALTER VIEW vETSIYouTubeTriggerSelectiveKPIs
AS
  Select t.SessionId,
         t.TestId,
         t.TestName,
         -- Initialized to Loading
         ISNULL(DATEDIFF(ms, MIN(vi.MsgTime), MIN(vl.MsgTime)) * 0, 108002)                                                                                           as PlayerAccess,
         case when ISNULL(DATEDIFF(ms, MIN(vi.MsgTime), MIN(vl.MsgTime)) * 0, 108002) = 0 then DATEDIFF(ms, MIN(vi.MsgTime), MIN(vl.MsgTime)) / 1000.0 else NULL end  as PlayerAccessDuration,
         -- Loading to Loaded
         108002                                                                                                                                                       as PlayerDownload,
         NULL                                                                                                                                                         as PlayerDownloadDuration,
         -- Initialized to Loaded
         108002                                                                                                                                                       as PlayerSession,
         NULL                                                                                                                                                         as PlayerSessionDuration,
         -- Clip started to Buffering started
         ISNULL(DATEDIFF(ms, MIN(vc.MsgTime), MIN(vb.MsgTime)) * 0, 108002)                                                                                           as VideoAccess,
         case when ISNULL(DATEDIFF(ms, MIN(vc.MsgTime), MIN(vb.MsgTime)) * 0, 108002) = 0 then DATEDIFF(ms, MIN(vc.MsgTime), MIN(vb.MsgTime)) / 1000.0 else NULL end  as VideoAccessDuration,
         -- Buffering started to Displaying
         ISNULL(DATEDIFF(ms, MIN(vb.MsgTime), MIN(vy.MsgTime)) * 0, 108002)                                                                                           as Reproduction,
         case when ISNULL(DATEDIFF(ms, MIN(vb.MsgTime), MIN(vy.MsgTime)) * 0, 108002) = 0 then DATEDIFF(ms, MIN(vb.MsgTime), MIN(vy.MsgTime)) / 1000.0 else NULL end  as ReproductionDelay,
         -- Clip started to Displaying
         ISNULL(DATEDIFF(ms, MIN(vc.MsgTime), MIN(vy.MsgTime)) * 0, 108002)                                                                                           as PlayoutAccess,
         case when ISNULL(DATEDIFF(ms, MIN(vc.MsgTime), MIN(vy.MsgTime)) * 0, 108002) = 0 then DATEDIFF(ms, MIN(vc.MsgTime), MIN(vy.MsgTime)) / 1000.0 else NULL end  as PlayoutAccessDuration,
         -- Initialized to Buffering started
         ISNULL(DATEDIFF(ms, MIN(vi.MsgTime), MIN(vb.MsgTime)) * 0, 108002)                                                                                           as IPAccess,
         case when ISNULL(DATEDIFF(ms, MIN(vi.MsgTime), MIN(vb.MsgTime)) * 0, 108002) = 0 then DATEDIFF(ms, MIN(vi.MsgTime), MIN(vb.MsgTime)) / 1000.0 else NULL end  as IPAccessDuration,
         -- Buffering started to DL progress: 100%
         ISNULL(DATEDIFF(ms, MIN(vb.MsgTime), MIN(vp.MsgTime)) * 0, 108002)                                                                                           as VideoDownload,
         case when ISNULL(DATEDIFF(ms, MIN(vb.MsgTime), MIN(vp.MsgTime)) * 0, 108002) = 0 then DATEDIFF(ms, MIN(vb.MsgTime), MIN(vp.MsgTime)) / 1000.0 else NULL end  as VideoDownloadDuration,
         -- Clip started to End reached
         ISNULL(DATEDIFF(ms, MIN(vc.MsgTime), MIN(vr.MsgTime)) * 0, 108002)                                                                                           as VideoSession,
         case when ISNULL(DATEDIFF(ms, MIN(vc.MsgTime), MIN(vr.MsgTime)) * 0, 108002) = 0 then DATEDIFF(ms, MIN(vc.MsgTime), MIN(vr.MsgTime)) / 1000.0 else NULL end  as VideoSessionDuration,
         -- Displaying to End reached
         ISNULL(DATEDIFF(ms, MIN(vy.MsgTime), MIN(vr.MsgTime)) * 0, 108002)                                                                                           as VideoPlayout,
         case when ISNULL(DATEDIFF(ms, MIN(vy.MsgTime), MIN(vr.MsgTime)) * 0, 108002) <> 0 then DATEDIFF(ms, MIN(vy.MsgTime), MIN(vr.MsgTime)) / 1000.0 else NULL end as VideoCutoffTime,
         case when ISNULL(DATEDIFF(ms, MIN(vy.MsgTime), MIN(vr.MsgTime)) * 0, 108002) = 0 then DATEDIFF(ms, MIN(vy.MsgTime), MIN(vr.MsgTime)) / 1000.0 else NULL end  as VideoPlayoutDuration,
         -- Initialized to End reached
         ISNULL(DATEDIFF(ms, MIN(vi.MsgTime), MIN(vr.MsgTime)) * 0, 108002)                                                                                           as E2ESession,
         case when ISNULL(DATEDIFF(ms, MIN(vi.MsgTime), MIN(vr.MsgTime)) * 0, 108002) = 0 then DATEDIFF(ms, MIN(vi.MsgTime), MIN(vr.MsgTime)) / 1000.0 else NULL end  as E2ESessionDuration,

         'Player Events'                                                                                                                                              as TriggerType
  from Sessions s	JOIN SessionList sl ON sl.SessionId = s.SessionId
       JOIN TestInfo t ON s.SessionID = t.SessionId and dbo.IsStreamingAppTest(t.typeoftest) = 1
       LEFT JOIN VideoStatusTrace vi ON vi.TestId = t.TestId and vi.Event = 'Initialized'                                           --tr1
       LEFT JOIN VideoStatusTrace vl ON vl.TestId = t.TestId and vl.Event = 'Loading'                                               --tr2
       LEFT JOIN VideoStatusTrace vc ON vc.TestId = t.TestId and vc.Event = 'Clip started'                                          --tr4
       LEFT JOIN VideoStatusTrace vb ON vb.TestId = t.TestId and vb.Event = 'Buffering started'                                     --tr5
       LEFT JOIN VideoStatusTrace vy ON vy.TestId = t.TestId and vy.Event = 'Displaying'                                            --tr6
       LEFT JOIN VideoStatusTrace vp ON vp.TestId = t.TestId and vp.Event = 'DL progress: 100%'
       LEFT JOIN VideoStatusTrace vr ON vr.TestId = t.TestId and vr.Event in ('Clip end reached','Video display duration reached')  --tr8 -- intentional stop as valid end trigger added
  group by t.SessionId, t.TestId, t.TestName;


-- dbo.vEVDOFwdRLPStatistics source

ALTER  VIEW vEVDOFwdRLPStatistics
as
select
	c.sessionID,
	c.testID,
	c.msgTime,
	c.networkID,
	c.posID,
	a.RLPFlow,
	a.RLPForwardInfoID as msgID,
	a.RxTotalBytes,
	b.RxTotalBytes - a.RxTotalBytes as transferredbytes,
	datediff(ms,c.msgtime,d.msgTime)as transferTime,
	case when datediff(ms,c.msgtime,d.msgTime)>0 then (cast((b.RxTotalBytes - a.RxTotalBytes)as float)* 8 / cast(datediff(ms,c.msgtime,d.msgTime) as float)) else 0.0 end as RLPThroughput
from
	EVDORLPForward a,
	EVDORLPForward b,
	EVDORLPForwardInfo c,
	EVDORLPForwardInfo d

where
	c.msgID + 1 = d.msgID and
	a.RLPForwardInfoID = c.RLPForwardInfoID and
	b.RLPForwardInfoID = d.RLPForwardInfoID and
	a.ResetTime = b.resetTime and
	a.RLPFlow = b.RLPFlow;


-- dbo.vEVDOPilot source

ALTER  VIEW vEVDOPilot
AS
SELECT  i.pilotInfoID AS msgID,
        testid,
        sessionID,
        posID,
        networkId,
	PNType,
        PN,
        EcIo,
        MACID,
	DRCCover,
	RPCIndex
FROM    EVDOPilotInfo i, EVDOPilots p
WHERE i.pilotinfoID = p.pilotinfoID;


-- dbo.vEVDORevRLPStatistics source

ALTER VIEW vEVDORevRLPStatistics
as
select
	c.sessionID,
	c.testID,
	c.msgTime,
	c.networkID,
	c.posID,
	a.RLPFlow,
	a.RLPReverseInfoID,
	a.TxTotalBytes,
	b.TxTotalBytes - a.TxTotalBytes as transferredbytes,
	datediff(ms,c.msgtime,d.msgTime)as transferTime,
	case when datediff(ms,c.msgtime,d.msgTime)>0 then (cast((b.TxTotalBytes - a.TxTotalBytes)as float)* 8 / cast(datediff(ms,c.msgtime,d.msgTime) as float)) else 0.0 end as RLPThroughput
from
	EVDORLPReverse a,
	EVDORLPReverse b,
	EVDORLPReverseInfo c,
	EVDORLPReverseInfo d

where
	c.msgID + 1 = d.msgID and
	a.RLPReverseInfoID = c.RLPReverseInfoID and
	b.RLPReverseInfoID = d.RLPReverseInfoID and
	a.ResetTime = b.resetTime and
	a.RLPFlow = b.RLPFlow;


-- dbo.vFactInteractivity source

ALTER VIEW vFactInteractivity
AS
  Select p.PatternName,
         p.Host,
         f.SessionId,
         f.TestId,
         f.QoEScore * 100 as Score,
         f.Connectivity * 100 as Connectivity,
         f.ThroughputKbps / 1000 as Throughput,
         case
           when ErrorCode = 0 then 'Successful'
           else 'Failed' end
         as Status,
         f.RTT10thPercentile as RTT10thPercentile,
         f.RTTMedian as RTTMedian,
         f.PacketDelayVarMedian as PDVMedian,
         f.TotalPacketErrorRate * 100 as TotalPacketErrorRate,
         f.PacketsLostRate * 100 as PacketsLostRate
  from FactInteractivity f
       JOIN ResultsInteractivityParameters p ON p.TestId = f.TestId;


-- dbo.vFactNR5GPDSCHStatisticsInfo source

ALTER VIEW vFactNR5GPDSCHStatisticsInfo
AS
  Select SessionId,
         FactId,
         dbo.DelphiDateTime(FullDate) as dTime,
         CONVERT(varchar, FullDate, 14) as msgTime2,
         SCSNumerology,
         NumSlots,
         BytesTransferred,
         ScheduledThroughput / 125 as SchedThroughput,
         NetThroughput / 125 as NetThroughput,
         BLER,
         ResidualBLER,
         TBRate,
         MaxTBSize,
         MinTBSize,
         AvgTBSize,
         NumTBs,
         MaxRBsTB,
         MinRBsTB,
         AvgRBsTB,
         NumRBs,
         MaxREsTB,
         MinREsTB,
         AvgREsTB,
         NumREs,
         MaxMCSIndex,
         MinMCSIndex,
         AvgMCSIndex,
         AvgCodeRate,
         NumNewData,
         NumCRCPass,
         NumPassOnFirstAttempt,
         NumDiscardedRetransmissions,
         NumNotTransmittedTBs,
         NumAckAsNack,
         NumNackAsAck,
         NumRetrans1,
         NumRetrans2,
         NumRetrans3orMore,
         case
           when TXMode = 0 then 'Scheme 1'
           else 'Invalid'
         end as TXMode,
         MaxNumLayer,
         LTrim(Str(BLER, 10, 2)) as BLERAsString,
         LTrim(Str(ResidualBLER, 10, 2)) as ResidualBLERAsString,
         LTrim(Str(ScheduledThroughput / 125, 10, 2)) as SchedThroughputAsString,
         LTrim(Str(NetThroughput / 125, 10, 2)) as NetThroughputAsString,
         LTrim(Str(TBRate, 10, 2)) as TBRateAsString,
         LTrim(Str(AvgTBSize, 10, 2)) as AvgTBSizeAsString,
         LTrim(Str(AvgMCSIndex, 10, 2)) as AvgMCSIndexAsString,
         LTrim(Str(AvgCodeRate, 10, 2)) as AvgCodeRateAsString,
         LTrim(Str(100 * CONVERT(float, NumNewData) / NULLIF(NumTBs, 0), 10, 1)) + ' %' as NumNewPercent,
         LTrim(Str(100 * CONVERT(float, NumPassOnFirstAttempt) / NULLIF(NumTBs, 0), 10, 1)) + ' %' as NumPass1Percent,
         LTrim(Str(100 * CONVERT(float, NumRetrans1) / NULLIF(NumTBs, 0), 10, 1)) + ' %' as NumRetrans1Percent,
         LTrim(Str(100 * CONVERT(float, NumRetrans2) / NULLIF(NumTBs, 0), 10, 1)) + ' %' as NumRetrans2Percent,
         LTrim(Str(100 * CONVERT(float, NumRetrans3orMore) / NULLIF(NumTBs, 0), 10, 1)) + ' %' as NumRetrans3Percent,
         LTrim(Str(100 * CONVERT(float, NumNotTransmittedTBs) / NULLIF(NumTBs, 0), 10, 1)) + ' %' as NumResidualPercent
  from FactNR5GPDSCHStatisticsInfo;


-- dbo.vFactNR5GPDSCHThroughput source

ALTER VIEW vFactNR5GPDSCHThroughput
AS
  Select SessionId,
         FactId,
         dbo.DelphiDateTime(FullDate) as dTime,
         CONVERT(varchar, FullDate, 14) as msgTime2,
         SchedThroughput / 125 as SchedThroughput,
         NetThroughput / 125 as NetThroughput,
         LTrim(Str(SchedThroughput / 125, 10, 2)) as SchedThroughputAsString,
         LTrim(Str(NetThroughput / 125, 10, 2)) as NetThroughputAsString
  from FactNR5GPDSCHThroughput;


-- dbo.vFactNR5GPUSCHStatisticsInfo source

ALTER VIEW vFactNR5GPUSCHStatisticsInfo
AS
  Select SessionId,
         FactId,
         dbo.DelphiDateTime(FullDate) as dTime,
         CONVERT(varchar, FullDate, 14) as msgTime2,
         SCSNumerology,
         NumSlots,
         BytesTransferred,
         ScheduledThroughput / 125 as SchedThroughput,
         NetThroughput / 125 as NetThroughput,
         RetransmissionRate,
         TBRate,
         MaxTBSize,
         MinTBSize,
         AvgTBSize,
         NumTBs,
         NumRBs,
         MaxRBs,
         MinRBs,
         AvgRBs,
         MaxMCSIndex,
         MinMCSIndex,
         AvgMCSIndex,
         PUSCHTxPower,
         Pathloss,
         LTrim(Str(RetransmissionRate, 10, 2)) as RetransmissionRateAsString,
         LTrim(Str(TBRate, 10, 2)) as TBRateAsString,
         LTrim(Str(AvgTBSize, 10, 2)) as AvgTBSizeAsString,
         LTrim(Str(AvgRBs, 10, 2)) as AvgRBsAsString,
