	FactLTEMACULStatistics.VirtualTestId;


-- dbo.vLTENASQoS source

ALTER VIEW vLTENASQoS
AS
  Select SessionId,
         dbo.DelphiDateTime(MsgTime) as dTime,
         CONVERT(varchar, MsgTime, 14) as msgTime2,

         case
           when QCI is NULL then '---'
           when QCI between 1 and 9  then 'QCI ' + CONVERT(varchar, QCI)
           when QCI between 128 and 254 then 'Operator-specific QCIs'
           else 'Reserved'
         end as QCIString,

         dbo.GetLTENASQoSBitRates(MaxBitRateUL) as ULMaxBitRate,
         dbo.GetLTENASQoSBitRates(MaxBitRateDL) as DLMaxBitRate,
         dbo.GetLTENASQoSBitRates(GuaranteedBitRateUL) as ULGuarBitRate,
         dbo.GetLTENASQoSBitRates(GuaranteedBitRateDL) as DLGuarBitRate,

         dbo.GetLTENASQoSBitRatesExt(MaxBitRateULExt) as ULMaxBitRateExt,
         dbo.GetLTENASQoSBitRatesExt(MaxBitRateDLExt) as DLMaxBitRateExt,
         dbo.GetLTENASQoSBitRatesExt(GuaranteedBitRateULExt) as ULGuarBitRateExt,
         dbo.GetLTENASQoSBitRatesExt(GuaranteedBitRateDLExt) as DLGuarBitRateExt

  from LTENASQoS;


-- dbo.vLTEPDSCHModulationTest source

ALTER VIEW vLTEPDSCHModulationTest
AS
Select
	vLTEPDSCHModulationsTest.SessionID,
	vLTEPDSCHModulationsTest.TestId,
	vLTEPDSCHModulationsTest.CodeMod,
	Sum(vLTEPDSCHModulationsTest.NumTBs) as 'SumOfSample',
	Sum(vLTEPDSCHModulationsTest.NumMod) as 'SumOfMode',
	Convert(float,Sum(vLTEPDSCHModulationsTest.NumMod))/Convert(float,Sum(vLTEPDSCHModulationsTest.NumTBs))*100 as 'Perc'
From
	vLTEPDSCHModulationsTest
Group by
	vLTEPDSCHModulationsTest.SessionID,
	vLTEPDSCHModulationsTest.TestId,
	vLTEPDSCHModulationsTest.CodeMod;


-- dbo.vLTEPDSCHModulationsTest source

ALTER VIEW vLTEPDSCHModulationsTest
AS
Select
	mod.FactId as MsgId,
	mod.SessionId,
	mod.VirtualTestId as TestId,
	mod.FullDate as MsgTime,
	mod.NumTBs,
	Case when mod.NumTBs >0 Then '16QAM' else NULL end as 'CodeMod',
	mod.Num16QAM as 'NumMod',
	Case when mod.NumTBs >0 Then mod.Num16QAM/mod.NumTBs*100 else NULL end as 'PercentMod'
From
	FactLTEPDSCHStatisticsInfo mod
Where
	mod.VirtualTestid >0 and
	mod.NumTBs >0
UNION
SELECT
	mod.FactId as MsgId,
	mod.SessionId,
	mod.VirtualTestId as TestId,
	mod.FullDate as MsgTime,
	mod.NumTBs,
	Case when mod.NumTBs >0 Then '64QAM' else NULL end AS 'CodeMod',
	mod.Num64QAM AS 'NumMod',
	Case when mod.NumTBs >0 Then mod.Num64QAM/mod.NumTBs*100 else NULL end as 'PercentMod'
FROM
	FactLTEPDSCHStatisticsInfo mod
WHERE
	mod.VirtualTestid >0 and
	mod.NumTBs >0
Union
SELECT
	mod.FactId as MsgId,
	mod.SessionId,
	mod.VirtualTestId as TestId,
	mod.FullDate as MsgTime,
	mod.NumTBs,
	Case when mod.NumTBs >0 Then '256QAM' else NULL end AS 'CodeMod',
	mod.Num256QAM AS 'NumMod',
	Case when mod.NumTBs >0 Then mod.Num256QAM/mod.NumTBs*100 else NULL end as 'PercentMod'
FROM
	FactLTEPDSCHStatisticsInfo mod
WHERE
	mod.VirtualTestid >0 and
	mod.NumTBs >0
Union
Select
	mod.FactId as MsgId,
	mod.SessionId,
	mod.VirtualTestId as TestId,
	mod.FullDate as MsgTime,
	mod.NumTBs,
	Case when mod.NumTBs >0 Then 'QPSK' else NULL end as 'CodeMod',
	mod.NumQPSK as 'NumMod',
	Case when mod.NumTBs >0 Then mod.NumQPSK/mod.NumTBs*100 else NULL end as 'PercentMod'
From
	FactLTEPDSCHStatisticsInfo mod
Where
	mod.VirtualTestid >0 and
	mod.NumTBs >0;


-- dbo.vLTEPDSCHRankTest source

ALTER VIEW vLTEPDSCHRankTest
AS
Select
	vLTEPDSCHRanksTest.SessionID,
	vLTEPDSCHRanksTest.TestId,
	vLTEPDSCHRanksTest.Rank,
	Sum(vLTEPDSCHRanksTest.NumRecords) as 'SumOfSample',
	Sum(vLTEPDSCHRanksTest.NumRank) as 'SumOfRank',
	Convert(float,Sum(vLTEPDSCHRanksTest.NumRank))/Convert(float,Sum(vLTEPDSCHRanksTest.NumRecords))*100 as 'Perc'
From
	vLTEPDSCHRanksTest
Group by
	vLTEPDSCHRanksTest.SessionID,
	vLTEPDSCHRanksTest.TestId,
	vLTEPDSCHRanksTest.Rank;


-- dbo.vLTEPDSCHRanksTest source

ALTER VIEW vLTEPDSCHRanksTest
AS
Select
	s.FactId as MsgId,
	s.SessionId,
	s.VirtualTestId as TestId,
	s.FullDate as MsgTime,
	s.NumTBs,
	c.NumRecords + ISNULL(d.NumRecords,0) as NumRecords,
	Case when s.NumTBs >0 Then 'Rank 1' else NULL end as 'Rank',
	c.NumRecords + ISNULL(d.NumRecords,0) - c.NumRank2 - ISNULL(d.numRank2,0) as NumRank,
	Case when s.NumTBs >0 Then (c.NumRecords + ISNULL(d.NumRecords,0) - c.NumRank2 - ISNULL(d.numRank2,0))*1.0/(c.NumRecords + ISNULL(d.NumRecords,0))*100 else NULL end as 'PercentRank'
From
	FactLTEPDSCHStatisticsInfo s Join vHSDPATest On(s.VirtualTestId = vHSDPATest.TestId)
	left join FactLTEPDSCHStatisticsCarrier c on (c.FactIdFactLTEPDSCHStatisticsInfo = s.FactId and c.CarrierIndex = 0 )
	left join FactLTEPDSCHStatisticsCarrier d on (d.FactIdFactLTEPDSCHStatisticsInfo = s.FactId and d.CarrierIndex = 1 )
Where
	s.FullDate between Dateadd(ms,500,vHSDPATest.StartTime) and Dateadd(ms,500,vHSDPATest.EndTime) and
	s.VirtualTestid >0 and
	s.NumTBs >0 
UNION

SELECT
	s.FactId as MsgId,
	s.SessionId,
	s.VirtualTestId as TestId,
	s.FullDate as MsgTime,
	s.NumTBs,
	c.NumRecords + ISNULL(d.NumRecords,0) as NumRecords,
	Case when s.NumTBs >0 Then 'Rank 2' else NULL end AS 'Rank',
	c.NumRank2 + ISNULL(d.numRank2,0) as NumRank,
	Case when s.NumTBs >0 Then (c.NumRank2 + ISNULL(d.numRank2,0))*1.0/(c.NumRecords + ISNULL(d.NumRecords,0))*100 else NULL end as 'PercentRank'
FROM
	FactLTEPDSCHStatisticsInfo s Join vHSDPATest On(s.VirtualTestId = vHSDPATest.TestId)
  left join FactLTEPDSCHStatisticsCarrier c on (c.FactIdFactLTEPDSCHStatisticsInfo = s.FactId and c.CarrierIndex = 0 )
  left join FactLTEPDSCHStatisticsCarrier d on (d.FactIdFactLTEPDSCHStatisticsInfo = s.FactId and d.CarrierIndex = 1 )
WHERE
	s.FullDate between Dateadd(ms,500,vHSDPATest.StartTime) and Dateadd(ms,500,vHSDPATest.EndTime) and
	s.VirtualTestid >0 and
	s.NumTBs >0;


-- dbo.vLTEPDSCHStatisticsInfo source

ALTER VIEW vLTEPDSCHStatisticsInfo
AS
  Select SessionId,
         FactId as LTEPDSCHInfoId,
         dbo.DelphiDateTime(FullDate) as dTime,
         CONVERT(varchar, FullDate, 14) as msgTime2,
         NumRecords,
         NumRank2,
         NumRank3,
         NumRank4,
         MaxRBsFrame,
         MinRBsFrame,
         AvgRBsFrame,
         BytesTransferred,
         RequestedPDSCHThroughputKbps as ReqThroughput,
         ScheduledPDSCHThroughputKbps as SchedThroughput,
         NetPDSCHThroughputKbps as NetThroughput,
         BLER,
         FER,
         TBRate,
         MaxTBSize,
         MinTBSize,
         AvgTBSize,
         NumTBs,
         NumNewData,
         NumCRCPass,
         NumPassOnFirstAttempt,
         NumRecombining,
         NumDiscardedRetransmissions,
         NumRBs,
         AvgMCS,
         NumQPSK,
         Num16QAM,
         Num64QAM,
         Num256QAM,
         NumRetrans1,
         NumRetrans2,
         NumRetrans3orMore,
         NumNotTransmittedTBs,
         MaxNumLayer,
         TransmissionModeAsText as TransmissionMode,
         LTrim(Str(BLER, 10, 2)) as BLERAsString,
         LTrim(Str(FER, 10, 2)) as FERAsString,
         LTrim(Str(RequestedPDSCHThroughputKbps, 10, 2)) as ReqThroughputAsString,
         LTrim(Str(ScheduledPDSCHThroughputKbps, 10, 2)) as SchedThroughputAsString,
         LTrim(Str(NetPDSCHThroughputKbps, 10, 2)) as NetThroughputAsString,
         LTrim(Str(TBRate, 10, 2)) as TBRateAsString,
         LTrim(Str(AvgTBSize, 10, 2)) as AvgTBSizeAsString,
         LTrim(Str(AvgMCS, 10, 2)) as AvgMCSAsString,
         MCSasModulation + ' (' + LTrim(Str(AvgMCS, 10, 1)) + ')'  as AvgMCSAsTxt,
         LTrim(Str(100 * Pass1Rate, 10, 1)) + ' %' as NumPass1Percent,
         LTrim(Str(100 * NewRate, 10, 1)) + ' %' as NumNewPercent,
         LTrim(Str(100 * ResidualRate, 10, 1)) + ' %' as NumResidualPercent,
         LTrim(Str(100 * Retrans1Rate, 10, 1)) + ' %' as NumRetrans1Percent,
         LTrim(Str(100 * Retrans2Rate, 10, 1)) + ' %' as NumRetrans2Percent,
         LTrim(Str(100 * Retrans3Rate, 10, 1)) + ' %' as NumRetrans3Percent,
         LTrim(Str(100 * QPSKRate, 10, 1)) + ' %' as NumQPSKPercent,
         LTrim(Str(100 * QAM16Rate, 10, 1)) + ' %' as Num16QAMPercent,
         LTrim(Str(100 * QAM64Rate, 10, 1)) + ' %' as Num64QAMPercent,
         LTrim(Str(100 * QAM256Rate, 10, 1)) + ' %' as Num256QAMPercent,
         100 * Rank1Rate as NumRank1PercentValue,
         100 * Rank2Rate as NumRank2PercentValue,
         100 * Rank3Rate as NumRank3PercentValue,
         100 * Rank4Rate as NumRank4PercentValue,
         LTrim(Str(100 * Rank1Rate, 10, 1)) + ' %' as NumRank1Percent,
         LTrim(Str(100 * Rank2Rate, 10, 1)) + ' %' as NumRank2Percent,
         LTrim(Str(100 * Rank3Rate, 10, 1)) + ' %' as NumRank3Percent,
         LTrim(Str(100 * Rank4Rate, 10, 1)) + ' %' as NumRank4Percent
  from FactLTEPDSCHStatisticsInfo;


-- dbo.vLTEPDSCHStatisticsInfoRank source

ALTER VIEW vLTEPDSCHStatisticsInfoRank
AS
  Select i.SessionId,
         i.FactId as LTEPDSCHInfoId,
         dbo.DelphiDateTime(i.FullDate) as dTime,
         CONVERT(varchar, i.FullDate, 14) as msgTime2,
         100 * CONVERT(float, SUM(c.NumRecords) - (i.NumRank2 + i.NumRank3 + i.NumRank4)) / NULLIF(SUM(c.NumRecords), 0) as NumRank1PercentValue,
         100 * CONVERT(float, i.NumRank2) / NULLIF(SUM(c.NumRecords), 0) as NumRank2PercentValue,
         100 * CONVERT(float, i.NumRank3) / NULLIF(SUM(c.NumRecords), 0) as NumRank3PercentValue,
         100 * CONVERT(float, i.NumRank4) / NULLIF(SUM(c.NumRecords), 0) as NumRank4PercentValue,
         LTrim(Str(100 * CONVERT(float, SUM(c.NumRecords) - (i.NumRank2 + i.NumRank3 + i.NumRank4)) / NULLIF(SUM(c.NumRecords), 0), 10, 1)) + ' %' as NumRank1Percent,
         LTrim(Str(100 * CONVERT(float, i.NumRank2) / NULLIF(SUM(c.NumRecords), 0), 10, 1)) + ' %' as NumRank2Percent,
         LTrim(Str(100 * CONVERT(float, i.NumRank3) / NULLIF(SUM(c.NumRecords), 0), 10, 1)) + ' %' as NumRank3Percent,
         LTrim(Str(100 * CONVERT(float, i.NumRank4) / NULLIF(SUM(c.NumRecords), 0), 10, 1)) + ' %' as NumRank4Percent
  from FactLTEPDSCHStatisticsInfo i
  JOIN FactLTEPDSCHStatisticsCarrier c ON c.FactIdFactLTEPDSCHStatisticsInfo = i.FactId
  group by i.SessionId, i.FullDate, i.FactId, i.NumRank2, i.NumRank3, i.NumRank4;


-- dbo.vLTEPDSCHTransferModesTest source

ALTER VIEW vLTEPDSCHTransferModesTest
AS
Select
	s.SessionId,
	s.VirtualTestId as TestId,
	m.TransmissionMode,
	case m.TransmissionMode
           when 0 then 'Invalid'
           when 1 then 'Single Antenna Port 0'
           when 2 then 'TD Rank 1'
           when 3 then 'OL SM'
           when 4 then 'CL SM'
           when 5 then 'MU MIMO'
           when 6 then 'CL RANK1 PC'
           when 7 then 'Single Antenna Port 5'
           when 8 then 'Single Antenna Port 7'
           when 9 then 'Dual layer beamforming: Port 7,8'
           when 10 then '3-layer beamforming: Port 7,8,9'
           when 11 then '4-layer beamforming: Port 7,8,9,10'
           else 'unknown'
    end as TM,
	sum(case when m.TransmissionMode = s.TransmissionMode then 1 else 0 end) as Num,
	Max(t.Num) as NumSamp,
	Convert(float,sum(case when m.TransmissionMode = s.TransmissionMode then 1 else 0 end))/Convert(float,Max(t.Num))*100 as 'Perc'
From
	 
	 FactLTEPDSCHStatisticsInfo s Join vHSDPATest On(s.VirtualTestId = vHSDPATest.TestId)
							 Join (Select s.SessionId,s.VirtualTestId,sum(1) as Num
								   From FactLTEPDSCHStatisticsInfo s Join vHSDPATest On(s.VirtualTestId = vHSDPATest.TestId)
								   Where s.FullDate between Dateadd(ms,500,vHSDPATest.StartTime) and Dateadd(ms,500,vHSDPATest.EndTime) and s.VirtualTestId >0
								   group by s.SessionId,s.VirtualTestId) t On (t.VirtualTestId = s.VirtualTestId)
							join  (select 1 as TransmissionMode, TestId from TestInfo union
								   select 2 as TransmissionMode, TestId from TestInfo union
								   select 3 as TransmissionMode, TestId from TestInfo union
								   select 4 as TransmissionMode, TestId from TestInfo union
								   select 5 as TransmissionMode, TestId from TestInfo union
								   select 6 as TransmissionMode, TestId from TestInfo union
								   select 7 as TransmissionMode, TestId from TestInfo ) m  on (m.TestID = s.VirtualTestId)
Where
	s.FullDate between Dateadd(ms,500,vHSDPATest.StartTime) and Dateadd(ms,500,vHSDPATest.EndTime) and
	s.VirtualTestId >0
Group By
	s.SessionId,
	s.VirtualTestId,
	m.TransmissionMode;


-- dbo.vLTEPRACH source

