-- dbo.vLTEPUCCHCQI source

ALTER VIEW vLTEPUCCHCQI
AS
  Select SessionId,
         dbo.DelphiDateTime(FullDate) as dTime,
         CONVERT(varchar, FullDate, 14) as msgTime2,
         CarrierIndex,
         TxModeTxt as TxMode,
