-- dbo.vLTEPUSCHModulationTest source

ALTER VIEW vLTEPUSCHModulationTest
AS
Select
	vLTEPUSCHModulationsTest.SessionID,
	vLTEPUSCHModulationsTest.TestId,
	vLTEPUSCHModulationsTest.CodeMod,
	Sum(vLTEPUSCHModulationsTest.NumTBs) as 'SumOfSample',
	Sum(vLTEPUSCHModulationsTest.NumMod) as 'SumOfMode',
	Convert(float,Sum(vLTEPUSCHModulationsTest.NumMod))/Convert(float,Sum(vLTEPUSCHModulationsTest.NumTBs))*100 as 'Perc'
From
	vLTEPUSCHModulationsTest
Group by
	vLTEPUSCHModulationsTest.SessionID,
	vLTEPUSCHModulationsTest.TestId,
	vLTEPUSCHModulationsTest.CodeMod;


-- dbo.vLTEPUSCHModulationsTest source

ALTER VIEW vLTEPUSCHModulationsTest
AS
Select
	mod.FactId as MsgId,
	mod.SessionId,
	mod.VirtualTestId as TestId,
	mod.FullDate as MsgTime,
	mod.NumTBs,
	Case when mod.NumTBs >0 Then '16QAM' else NULL end as 'CodeMod',
	mod.Num16QAM as 'NumMod',
	Case when mod.NumTBs >0 Then mod.Num16QAM/mod.NumTBs*100 else NULL end as 'PercentMod'
From
	FactLTEPUSCHStatisticsInfo mod
Where
	mod.VirtualTestId >0 and
	mod.NumTBs >0
UNION
SELECT
	mod.FactId as MsgId,
	mod.SessionId,
	mod.VirtualTestId as TestId,
	mod.FullDate as MsgTime,
	mod.NumTBs,
	Case when mod.NumTBs >0 Then '64QAM' else NULL end AS 'CodeMod',
	mod.Num64QAM AS 'NumMod',
	Case when mod.NumTBs >0 Then mod.Num64QAM/mod.NumTBs*100 else NULL end as 'PercentMod'
FROM
	FactLTEPUSCHStatisticsInfo mod
WHERE
	mod.VirtualTestId >0 and
	mod.NumTBs >0
Union
Select
	mod.FactId as MsgId,
	mod.SessionId,
	mod.VirtualTestId as TestId,
	mod.FullDate as MsgTime,
	mod.NumTBs,
	Case when mod.NumTBs >0 Then 'QPSK' else NULL end as 'CodeMod',
	mod.NumQPSK as 'NumMod',
	Case when mod.NumTBs >0 Then mod.NumQPSK/mod.NumTBs*100 else NULL end as 'PercentMod'
From
	FactLTEPUSCHStatisticsInfo mod
Where
	mod.VirtualTestId >0 and
	mod.NumTBs >0;


