-- dbo.vLTEPagingEDRXRequest source

ALTER VIEW vLTEPagingEDRXRequest
AS
  Select SessionId,
         dbo.DelphiDateTime(MsgTime) as dTime,
         CONVERT(varchar, MsgTime, 14) as msgTime2,
         UEId,
         case PagingCycle
           when 0 then 320
           when 1 then 640
           when 2 then 1280
           when 3 then 25660
           when 4 then 5120
         end as PagingCycle,
         case Nb
           when  0 then 'fourT'
           when  1 then 'twoT'
           when  2 then 'oneT'
           when  3 then 'halfT'
           when  4 then 'quarterT'
           when  5 then 'oneEightT'
           when  6 then 'oneSixteenthT'
           when  7 then 'oneThirtySecondT'
           when  8 then 'OnesixtyfourthT'
           when  9 then 'OneonetwentyeighthT'
           when 10 then 'OnetwofiftysixthT'
           when 11 then 'OnefiveonetwelvethT'
           when 12 then 'OnetentwentyfourthtT'
         end as Nb,
         EDRXCycleLength
  from LTEPagingEDRXRequest;


-- dbo.vLTERLCDLThroughput source

ALTER VIEW vLTERLCDLThroughput
AS
Select
	vLTERLCDLThroughputs.SessionId,
	vLTERLCDLThroughputs.TestId,
	Sum(vLTERLCDLThroughputs.TotalDataByte)*0.001 as 'TotalRLCDatakByte',
	Avg(vLTERLCDLThroughputs.DataRLCThrpt) as 'AvgRLCDataThrpt',
	Count(vLTERLCDLThroughputs.DataRLCThrpt) as 'CountRLCDataThrpt',
	Min(vLTERLCDLThroughputs.DataRLCThrpt) as 'MinRLCDataThrpt',
	Max(vLTERLCDLThroughputs.DataRLCThrpt) as 'MaxRLCDataThrpt',
	Avg(vLTERLCDLThroughputs.TotalRLCThrpt) as 'AvgRLCTotalThrpt',
	Count(vLTERLCDLThroughputs.TotalRLCThrpt) as 'CountRLCTotalThrpt',
	Min(vLTERLCDLThroughputs.TotalRLCThrpt) as 'MinRLCTotalThrpt',
	Max(vLTERLCDLThroughputs.TotalRLCThrpt) as 'MaxRLCTotalThrpt',
	Avg(vLTERLCDLThroughputs.RLCBLER) as 'AvgRLCBLER',
	Count(vLTERLCDLThroughputs.RLCBLER) as 'CountRLCBLER',
	Min(vLTERLCDLThroughputs.RLCBLER) as 'MinRLCBLER',
	Max(vLTERLCDLThroughputs.RLCBLER) as 'MaxRLCBLER'
From
	vLTERLCDLThroughputs					  
Group By
	vLTERLCDLThroughputs.SessionId,
	vLTERLCDLThroughputs.TestId;


-- dbo.vLTERLCDLThroughputs source

ALTER VIEW vLTERLCDLThroughputs
AS
Select
	li.SessionId,
	li.VirtualTestId as TestId,
	li.FullDate as MsgTime,
	li.PosId,
	li.NetworkId,
	li.FactId as LTERLCDLStatId,
	SUM(Convert(float, l.NumDataBytes + l.NumStatusBytes + l.NumInvalidBytes)) as 'TotalDataByte',
	SUM(Convert(float, l.NumDataBytes) * 8) / li.Duration as 'DataRLCThrpt',
	SUM(Convert(float, l.NumDataBytes + l.NumStatusBytes + l.NumInvalidBytes) * 8) / li.Duration as 'TotalRLCThrpt',
	Case when SUM(Convert(float, l.NumInvalidPDU)) > 0 then SUM(Convert(float, l.NumDataPDU + l.NumStatusPDU + l.NumInvalidPDU)) / SUM(Convert(float, l.NumInvalidPDU)) / li.Duration else 0.0 end as 'RLCBLER'
From
	FactLTERLCDLStatisticsInfo li JOIN vHSDPATest On li.VirtualTestId = vHSDPATest.TestId
  JOIN FactLTERLCDLStatistics l On li.FactId = l.FactIdFactLTERLCDLStatisticsInfo
Where
	li.FullDate between DATEADD(ms, 1000, vHSDPATest.StartTime) and Dateadd(ms, 1000, vHSDPATest.EndTime)
	and li.Duration > 0
Group By
	li.SessionId,
	li.VirtualTestId,
	li.FactId,
	li.FullDate,
	li.PosId,
	li.NetworkId,
	li.Duration;


-- dbo.vLTERLCULThroughput source

ALTER VIEW vLTERLCULThroughput
AS
Select
	vLTERLCULThroughputs.SessionId,
	vLTERLCULThroughputs.TestId,
	Sum(vLTERLCULThroughputs.TotalDataByte)*0.001 as 'TotalRLCDatakByte',
	Avg(vLTERLCULThroughputs.DataRLCThrpt)as 'AvgRLCDataThrpt',
	Count(vLTERLCULThroughputs.DataRLCThrpt)as 'CountRLCDataThrpt',
	Min(vLTERLCULThroughputs.DataRLCThrpt)as 'MinRLCDataThrpt',
	Max(vLTERLCULThroughputs.DataRLCThrpt)as 'MaxRLCDataThrpt',
	Avg(vLTERLCULThroughputs.TotalRLCThrpt)as 'AvgRLCTotalThrpt',
	Count(vLTERLCULThroughputs.TotalRLCThrpt)as 'CountRLCTotalThrpt',
	Min(vLTERLCULThroughputs.TotalRLCThrpt)as 'MinRLCTotalThrpt',
	Max(vLTERLCULThroughputs.TotalRLCThrpt)as 'MaxRLCTotalThrpt',
	Avg(vLTERLCULThroughputs.RLCRetrRate)as 'AvgRLCRetr',
	Count(vLTERLCULThroughputs.RLCRetrRate)as 'CountRLCRetr',
	Min(vLTERLCULThroughputs.RLCRetrRate)as 'MinRLCRetr',
	Max(vLTERLCULThroughputs.RLCRetrRate)as 'MaxRLCRetr'
From
	vLTERLCULThroughputs				  
Group By
	vLTERLCULThroughputs.SessionId,
	vLTERLCULThroughputs.TestId;


-- dbo.vLTERLCULThroughputs source

ALTER VIEW vLTERLCULThroughputs
AS
Select
	li.SessionId,
	li.VirtualTestId as TestId,
	li.FullDate as MsgTime,
	li.PosId,
	li.NetworkId,
	li.FactId as LTERLCULStatId,
	SUM(Convert(float, l.NumDataBytes + l.NumCtrlBytes + l.NumReTxBytes) * 8) as 'TotalDataByte',
	SUM(Convert(float, l.NumDataBytes * 8)) / li.Duration as 'DataRLCThrpt',
	SUM(Convert(float, l.NumDataBytes + l.NumCtrlBytes + l.NumReTxBytes) * 8) / li.Duration as 'TotalRLCThrpt',
	Case when Convert(float, SUM(l.NumReTxPDU + l.NumCtrlPDUReTx)) > 0 then SUM(Convert(float, l.NumDataPDU + l.NumCTRLPDU + l.NumReTxPDU)) / SUM(Convert(float, l.NumReTxPDU + l.NumCtrlPDUReTx)) / li.Duration else 0.0 end as 'RLCRetrRate'
From
	FactLTERLCULStatisticsInfo li JOIN vHSDPATest On li.VirtualTestId = vHSDPATest.TestId
  JOIN FactLTERLCULStatistics l On li.FactId = l.FactIdFactLTERLCULStatisticsInfo
Where
	li.FullDate between DATEADD(ms, 1000, vHSDPATest.StartTime) and Dateadd(ms, 1000, vHSDPATest.EndTime)
	and li.Duration > 0
Group By
	li.SessionId,
	li.VirtualTestId,
	li.FactId,
	li.FullDate,
	li.PosId,
	li.NetworkId,
	li.Duration;


-- dbo.vLTERRCMessages source

ALTER VIEW vLTERRCMessages
AS
  Select FactId as MsgId,
         SessionId,
         VirtualTestId as TestId,
         FullDate as MsgTime,
         PosId,
         NetworkId,
         L3Release as RRCRelease,
         L3Version as RRCVersion,
         NULL as RB_Id,
         CONVERT(int, Identifier3) as PhyCellId,
         CONVERT(int, Identifier4) as Freq,
         NULL as SFN,
         Identifier as ChnType,
         Identifier2 as MsgType,
         SimpleMsgName as MsgTypeName,
         Message as Msg,
         Direction,
         MsgName
  from FactL3Messages
  where Technology = 'LTE' and
        Layer = 'LTE-RRC';


-- dbo.vLTESINRCorrelation source

ALTER VIEW vLTESINRCorrelation
AS
Select
	Report.SessionId,
	Report.TestId,
	Report.msgtime,
	Report.PosId,
	Report.NetworkId,
	Report.RSRP,
	Report.RSRQ,
	Report.RSSI,
	Report.SINR0,
	Report.SINR1,
	Report.SINR2,
	Report.SINR3,
	Report.RSRP_Rx0,
	Report.RSRP_Rx1,
	Report.RSRP_Rx2,
	Report.RSRP_Rx3,
	Report.RSRQ_Rx0,
	Report.RSRQ_Rx1,
	Report.RSRQ_Rx2,
	Report.RSRQ_Rx3,
	Report.RSSI_Rx0,
	Report.RSSI_Rx1,
	Report.RSSI_Rx2,
	Report.RSSI_Rx3,
	Round(f.AvgMCS,1) as 'AvgMCS',
	Round(f.RequestedPDSCHThroughput*0.008,1) as 'ReqPDSCHThrpt',
	Round(f.ScheduledPDSCHThroughput*0.008,1) as 'SchPDSCHThrpt',
	Round(f.NetPDSCHThroughput*0.008,1) as 'NetPDSCHThrpt',
	f.AvgTBSize,
	f.TBRate,
	f.BLER*0.01 as 'BLER',
	f.FER*0.01 as 'FER',
	f.NumRBs,
	f.AvgRBsFrame,
	f.AvgRBsFrame*f.TBRate as 'Usage',
	Round(Convert(float,f.NumRank2) / Convert(float,NULLIF(f.NumRecords, 0)), 2) as 'Rank2Mimo',
	Round(Convert(float,f.NumRank3) / Convert(float,NULLIF(f.NumRecords, 0)), 2) as 'Rank3Mimo',
	Round(Convert(float,f.NumRank4) / Convert(float,NULLIF(f.NumRecords, 0)), 2) as 'Rank4Mimo',
	Round(Convert(float,f.BytesTransferred*8) / Convert(float,NULLIF(f.NumRBs, 0)), 2) as 'BitPerRB',
	Round(Convert(float,f.NumQPSK) / Convert(float,NULLIF(f.NumTBs, 0)),2) as 'QPSKUse',
	Round(Convert(float,f.Num16QAM) / Convert(float,NULLIF(f.NumTBs, 0)),2) as 'CS16QAMUse',
	Round(Convert(float,f.Num64QAM) / Convert(float,NULLIF(f.NumTBs, 0)),2) as 'CS64QAMUse',
	Round(Convert(float,f.Num256QAM) / Convert(float,NULLIF(f.NumTBs, 0)),2) as 'CS256QAMUse',
	Round(Convert(float,(f.Num256QAM +
			     f.Num64QAM +
			     f.Num16QAM +
			     f.NumQPSK)) / Convert(float,NULLIF(f.NumTBs, 0)), 2) as 'Use'
From
	LTEMeasurementReport Report
  Join vHSDPATest On Report.TestId = vHSDPATest.TestId
  Join FactLTEPDSCHStatisticsInfo f On Report.SessionId = f.SessionId
Where
	Report.msgtime between Dateadd(ms,500,vHSDPATest.Starttime) and Dateadd(ms,500,vHSDPATest.Endtime) and
	f.FactId = (Select Max(info.FactId) From FactLTEPDSCHStatisticsInfo info Where Report.SessionId = info.SessionId and info.FullDate <= Report.MsgTime);


-- dbo.vLTEServingCellInfo source

ALTER VIEW vLTEServingCellInfo
AS
  Select SessionId,
         dbo.DelphiDateTime(s.MsgTime) as dTime,
         CONVERT(varchar, s.MsgTime, 14) as msgTime2,
         s.PhyCellId,
         s.DL_EARFCN,
         s.UL_EARFCN,
         Convert(varchar, s.DLBandWidth) + ' MHz' as DLBW,
         Convert(varchar, s.ULBandWidth) + ' MHz' as ULBW,
         s.CellIdentity,
         s.TAC,
         s.BandIndicator,
         case s.AllowedAccess
           when 0 then 'Full'
           else 'Limited'
         end as AllowedAccess,
         s.DetectedAntennas,
         s.QRxLevMin,
         s.PMax,
         s.MaxTxPower,
         s.SRxLev,
         s.SIntraSearch,
         s.SNonIntraSearch,
         dbo.GetLTEDuplexMode(n.RFBand) as DuplexMode,
         case ISNULL(s.CEMode, -1)
           when 0 then 'Mode A'
           when 1 then 'Mode B'
           else '-'
         end as CEMode
  from LTEServingCellInfo s
       JOIN NetworkInfo n ON n.NetworkId = s.NetworkId;


-- dbo.vLTEULInstThroughput source

ALTER VIEW vLTEULInstThroughput
AS
Select
	f.SessionId,
	f.VirtualTestId as TestId,
	f.FullDate as MsgTime,
	f.NetworkId,
	f.PosId,
	f.GrantedPUSCHThroughput*0.008 as 'GrantedThrpt',
	f.ScheduledPUSCHThroughput*0.008 as 'SchPUSCHThrpt',
	f.AvgTBSize as 'AvgTBSizeByte',
	f.AvgTBSize*8 as 'AvgTBSizeBit',
	Convert(float,f.TBRate) as 'PUSCHTBRate',
	f.NetPUSCHThroughput*0.008 as 'NetPUSCHThrpt',
	f.RetransmissionRate as 'PUSCHRetr',
	f.PuschTxPower as 'PUSCHTxPwr',
	f.NumBPSK,
	f.NumQPSK,
	f.Num16QAM,
	f.Num64QAM,
	f.NumBPSK + f.NumQPSK +
	f.Num16QAM + f.Num64QAM as SumMod,
	f.AvgMCS,
	f.NumRecords,
	f.NumULGrant,
	f.NumRBs as PUSCHNumRBs

From
	FactLTEPUSCHStatisticsInfo f Join vHSDPATest On f.VirtualTestId = vHSDPATest.TestId
Where
	f.FullDate between Dateadd(ms,500,vHSDPATest.Starttime) and Dateadd(ms,500,vHSDPATest.Endtime);


-- dbo.vLTEULThroughput source

ALTER VIEW vLTEULThroughput
AS
Select
	f.SessionId,
	f.VirtualTestId as TestId,
	Avg(f.GrantedPUSCHThroughput*0.008) as 'AvgGrantedThrpt',
	Count(f.GrantedPUSCHThroughput) as 'CountGrantedThrpt',
	Min(f.GrantedPUSCHThroughput*0.008) as 'MinGrantedThrpt',
	Max(f.GrantedPUSCHThroughput*0.008) as 'MaxGrantedThrpt',
	Avg(f.ScheduledPUSCHThroughput*0.008) as 'AvgSchThrpt',
	Count(f.ScheduledPUSCHThroughput) as 'CountSchThrpt',
	Min(f.ScheduledPUSCHThroughput*0.008) as 'MinSchThrpt',
	Max(f.ScheduledPUSCHThroughput*0.008) as 'MaxSchThrpt',
	Avg(f.AvgTBSize) as 'AvgTBSizeByte',
	Count(f.AvgTBSize) as 'CountTBSizeByte',
	Min(f.AvgTBSize) as 'MinTBSizeByte',
	Max(f.AvgTBSize) as 'MaxTBSizeByte',
	Avg(f.AvgTBSize*8) as 'AvgTBSizeBit',
	Count(f.AvgTBSize*8) as 'CountTBSizeBit',
	Min(f.AvgTBSize*8) as 'MinTBSizeBit',
	Max(f.AvgTBSize*8) as 'MaxTBSizeBit',
	Sum(Convert(float,f.TBRate)) as 'AvgPUSCHTBRate',
	Avg(f.NetPUSCHThroughput*0.008) as 'AvgPUSCHThrpt',
	Count(f.NetPUSCHThroughput) as 'CountPUSCHThrpt',
	Min(f.NetPUSCHThroughput*0.008) as 'MinPUSCHThrpt',
	Max(f.NetPUSCHThroughput*0.008) as 'MaxPUSCHThrpt',
	Avg(f.RetransmissionRate) as 'AvgPUSCHRetr',
	Count(f.RetransmissionRate) as 'CountPUSCHRetr',
	Min(f.RetransmissionRate) as 'MinPUSCHRetr',
	Max(f.RetransmissionRate) as 'MaxPUSCHRetr',
	Avg(f.PuschTxPower) as 'AvgPUSCHTxPwr',
	Count(f.PuschTxPower) as 'CountPUSCHTxPwr',
	Min(f.PuschTxPower) as 'MinPUSCHTxPwr',
	Max(f.PuschTxPower) as 'MaxPUSCHTxPwr'
From
	FactLTEPUSCHStatisticsInfo f Join vHSDPATest On f.VirtualTestId = vHSDPATest.TestId
Where
	f.FullDate between Dateadd(ms,500,vHSDPATest.Starttime) and Dateadd(ms,500,vHSDPATest.Endtime)
Group By
	f.SessionId,
	f.VirtualTestId;


-- dbo.vLTEULThroughputLayer source

ALTER VIEW vLTEULThroughputLayer
AS
Select
	thrpt.SessionId,
	thrpt.TestId,
	Case when thrpt.AvgSchThrpt>0 then 'Scheduled PUSCH throughput'
		else NULL end as 'Layer',
	Case when thrpt.AvgSchThrpt>0 then thrpt.AvgSchThrpt
		else NULL end as 'Throughput'
From
	vLTEULThroughput thrpt
	JOIN vHSDPATest On thrpt.TestId = vHSDPATest.TestId
	JOIN dbo.GetULDataTestKPIs() ON GetULDataTestKPIs.KPIId = vHSDPATest.KPIId

Union
Select
	thrpt.SessionId,
	thrpt.TestId,
	Case when thrpt.AvgPUSCHThrpt>0 then 'Net-PUSCH throughput'
		else NULL end as 'Layer',
	Case when thrpt.AvgPUSCHThrpt>0 then thrpt.AvgPUSCHThrpt
		else NULL end as 'Throughput'
From
	vLTEULThroughput thrpt
	JOIN vHSDPATest On thrpt.TestId = vHSDPATest.TestId
	JOIN dbo.GetULDataTestKPIs() ON GetULDataTestKPIs.KPIId = vHSDPATest.KPIId

Union
Select
	mac.SessionId,
	mac.TestId,
	Case when mac.AvgMACThrpt>0 then 'MAC throughput'
		else NULL end as 'Layer',
	Case when mac.AvgMACThrpt>0 then mac.AvgMACThrpt
		else NULL end as 'Throughput'
From
	vLTEMACULThroughput mac
	JOIN vHSDPATest On mac.TestId = vHSDPATest.TestId
	JOIN dbo.GetULDataTestKPIs() ON GetULDataTestKPIs.KPIId = vHSDPATest.KPIId

Union
Select
	rlc.SessionId,
	rlc.TestId,
	Case when rlc.AvgRLCTotalThrpt>0 then 'RLC throughput'
		else NULL end as 'Layer',
	Case when rlc.AvgRLCTotalThrpt>0 then rlc.AvgRLCTotalThrpt
		else NULL end as 'Throughput'
From
	vLTERLCULThroughput rlc
	JOIN vHSDPATest On rlc.TestId = vHSDPATest.TestId
	JOIN dbo.GetULDataTestKPIs() ON GetULDataTestKPIs.KPIId = vHSDPATest.KPIId

Union
Select
	kpi.SessionId,
	kpi.TestId,
	Case
		when kpi.KPIID=30200 then 'Application throughput Email send'
		when kpi.KPIID=30300 then 'Application throughput FTP uplink'
		when kpi.KPIID=30302 then 'Application throughput FTPS uplink'
		when kpi.KPIID=30310 then 'Application throughput FTP uplink fixed duration'
		when kpi.KPIID=30312 then 'Application throughput FTPS uplink fixed duration'
		when kpi.KPIID=30402 then 'Application throughput HTTP transfer uplink'
		when kpi.KPIID=30412 then 'Application throughput HTTP transfer uplink fixed duration'
		when kpi.KPIID=30432 then 'Application throughput HTTPS transfer uplink'
		when kpi.KPIID=30442 then 'Application throughput HTTPS transfer uplink fixed duration'
		when kpi.KPIID=30462 then 'Application throughput Capacity uplink'
		when kpi.KPIID=30463 then 'Application throughput Capacity DL/UL uplink'
		else NULL
	end as 'Layer',
	Case
		when kpi.KPIID=30463 then kpi.APULThroughput
		else kpi.APThroughput
	end as 'Throughput'
From
	vHSDPATest kpi
	JOIN dbo.GetULDataTestKPIs() ON GetULDataTestKPIs.KPIId = kpi.KPIId;


-- dbo.vMMSE2E source

ALTER VIEW vMMSE2E AS

Select
	max(CASE when event = 'START' AND sendReceive = 'S' then ResultsMMSTrace.SessionID else NULL end) as SessionID,
	max(CASE when event = 'START' AND sendReceive = 'S' then ResultsMMSTrace.TestID else NULL end) as TestID,
	max(CASE when event = 'START' AND sendReceive = 'S' then ResultsMMSTrace.NetworkID else NULL end) as NetworkID,
	max(CASE when event = 'START' AND sendReceive = 'S' then ResultsMMSTrace.PosID else NULL end) as PosID,

	max(CASE when event = 'START' AND sendReceive = 'S' then ResultsMMSTrace.msgTime else NULL end) AS StartTime,
	max(CASE when event = 'TRANSMISSION FINISHED' AND sendReceive = 'R' then ResultsMMSTrace.msgTime else NULL end) AS EndTime,
	STR(CONVERT(float,DATEDIFF(ms,max(CASE when event = 'START' AND sendReceive = 'S' AND ErrorCode = 0 then ResultsMMSTrace.msgTime else NULL end),
	    max(CASE when event = 'TRANSMISSION FINISHED' AND sendReceive = 'R' AND ErrorCode = 0 then (case when ASideDevice like 'Samsung %' then DateADD(s,-8,ResultsMMSTrace.msgTime) else ResultsMMSTrace.msgTime end ) else NULL end))),20,0) AS Duration,
	case when max(CASE when event = 'START' AND sendReceive = 'S' then 1 else 0 end)+
	    max(CASE when event = 'TRANSMISSION FINISHED' AND sendReceive = 'R' AND ErrorCode = 0 then 1 else 0 end) > 1 then 'Successful' else 'Failed' end AS Status,
	SUM(case when event = 'START' AND sendReceive = 'S' then 1 else 0 end) AS Counter,

	max(CASE when event = 'TRANSMISSION FINISHED' AND sendReceive = 'S' then ResultsMMSTrace.msgTime else NULL end) AS NStartTime,
	max(CASE when event = 'NOTIFICATION RECEIVED' AND sendReceive = 'R' then ResultsMMSTrace.msgTime else NULL end) AS NEndTime,
	STR(CONVERT(float,DATEDIFF(ms,max(CASE when event = 'TRANSMISSION FINISHED' AND sendReceive = 'S' AND ErrorCode = 0 then ResultsMMSTrace.msgTime else NULL end),
	    max(CASE when event = 'NOTIFICATION RECEIVED' AND sendReceive = 'R' AND ErrorCode = 0 then ResultsMMSTrace.msgTime else NULL end))),20,0) AS NDuration,
	case when max(CASE when event = 'TRANSMISSION FINISHED' AND sendReceive = 'S' then 1 else 0 end)+
	    max(CASE when event = 'NOTIFICATION RECEIVED' AND sendReceive = 'R'  then 1 else 0 end) > 1 then 'Successful' else 'Failed' end AS NStatus,
	SUM(case when event = 'TRANSMISSION FINISHED' AND sendReceive = 'S' AND ErrorCode = 0 then 1 else 0 end) AS NCounter,

ResultsMMSParameters.identifier
FROM
	TestInfo,
	ResultsMMSTrace,
	ResultsMMSParameters,
	ResultsMMSRslt,
	Sessions,
	Filelist
WHERE
	TestInfo.valid = 1 and
	TestInfo.TestID = ResultsMMSTrace.TestId and
	ResultsMMSTrace.TestId = ResultsMMSParameters.TestId  AND
	ResultsMMSTrace.TestId = ResultsMMSRslt.TestId  AND
	ResultsMMSRslt.SessionId = Sessions.SessionId AND
	Sessions.FileId = FileList.FileId
GROUP BY
	ResultsMMSParameters.identifier;


-- dbo.vMRABSessionType source

ALTER VIEW vMRABSessionType
AS
  Select case MRABMode
           when 0 then 'Single transfer mode'
           when 1 then 'Multi transfer mode'
         end + ' - ' +
         case
           when COUNT(SessionId) >= 2 then 'Call & Data'
           else case MAX(SessTyp)
                  when 2 then 'Idle'
                  when 1 then 'Data'
                  else 'Call'
                end
         end as TransferMode,
         SessionId
  from vMRABSessions
  where Side is not NULL
  group by SessionId, MRABMode

  UNION ALL

  Select case MRABMode
           when 0 then 'Single transfer mode'
           when 1 then 'Multi transfer mode'
         end + ' - ' +
         case ISNULL(s.sessionType, sb.sessionType)
            when 'CALL' then 'Call'
            when 'DATA' then 'Data'
            else 'Idle'
         end as TransferMode,
         v.SessionId
  from vMRABSessions v
  LEFT JOIN Sessions s ON s.SessionId = v.SessionId
  LEFT JOIN SessionsB sb ON sb.SessionId = v.SessionId
  where Side is NULL and v.SessionId not in (Select SessionId from vMRABSessions where Side is not NULL)
  group by v.SessionId, MRABMode, s.sessionType, sb.sessionType;


-- dbo.vMRABSessions source

ALTER VIEW vMRABSessions
AS
  Select DISTINCT 0 as SessTyp,
         dbo.IsMultiTransferModeFile(f.FileId) as MRABMode,
         s.SessionId,
		 t.Side
  from CallSession c
       JOIN Sessions s ON s.SessionId = c.SessionId
       JOIN FileList f ON f.FileId = s.FileId
	   LEFT JOIN TestInfo t ON t.SessionId = s.SessionId and t.JobType IN (0, 2, 3, 9, 18)

  UNION ALL

  Select DISTINCT 0 as SessTyp,
         dbo.IsMultiTransferModeFile(f.FileId) as MRABMode,
         s.SessionId,
		 t.Side
  from CallSession c
       JOIN SessionsB s ON s.SessionIdA = c.SessionId
       JOIN FileList f ON f.FileId = s.FileId
	   LEFT JOIN TestInfo t ON t.SessionId = s.SessionIdA and t.JobType IN (0, 2, 3, 9, 18)

  UNION ALL

  Select DISTINCT 1 as SessTyp,
         dbo.IsMultiTransferModeFile(f.FileId) as MRABMode,
         s.SessionId,
		 t.Side
  from DataSession c
       JOIN Sessions s ON s.SessionId = c.SessionId
       JOIN FileList f ON f.FileId = s.FileId
	   LEFT JOIN TestInfo t ON t.SessionId = s.SessionId and t.JobType NOT IN (0, 2, 3, 9, 18) and t.Side = 'A'

  UNION ALL

  Select DISTINCT 1 as SessTyp,
         dbo.IsMultiTransferModeFile(f.FileId) as MRABMode,
         s.SessionId,
		 t.Side
  from DataSession c
       JOIN SessionsB s ON s.SessionIdA = c.SessionId
       JOIN FileList f ON f.FileId = s.FileId
	   LEFT JOIN TestInfo t ON t.SessionId = s.SessionIdA and t.JobType NOT IN (0, 2, 3, 9, 18) and t.Side = 'B'

  UNION ALL

  Select 2 as SessTyp,
         dbo.IsMultiTransferModeFile(f.FileId) as MRABMode,
         s.SessionId,
		 NULL
  from Sessions s
       JOIN FileList f ON f.FileId = s.FileId and s.sessionType = 'IDLE'

  UNION ALL

  Select 2 as SessTyp,
         dbo.IsMultiTransferModeFile(f.FileId) as MRABMode,
         s.SessionId,
		 NULL
  from SessionsB s
       JOIN FileList f ON f.FileId = s.FileId and s.sessionType = 'IDLE';


-- dbo.vMessagingKPI source

ALTER VIEW vMessagingKPI
AS
  Select k.*, p.ServiceProvider, p.ServiceProfileName,
         case MediaType
           when 1 then 'Text'
           when 3 then 'Picture'
           when 5 then 'Video'
           else '---'
         end as MediaType,
         p.FileName, p.FileSize
  from vResultsKPI k
  JOIN ResultsMessagingParameters p ON p.TestId = k.TestId
  where k.KPIId in (20910, 30911, 30912);


-- dbo.vMsgCDMAScannerBestServer source

ALTER VIEW vMsgCDMAScannerBestServer
as
select 
		i.SessionID,
		i.TestID,
		i.MsgTime,
		i.PosID,
		i.NetworkID,
		i.RFBand,
		rfb.Name as Technology,
		i.Channel,
		i.IO as RxLev,
		p.Number as PN,
		p.EcIoData as EcIo,
		i.IO + p.EcIoData as RSCP
from
		MsgWCDMAScannerPilotInfo i join MsgWCDMAScannerPilot p on (p.WPilotId = i.WPilotId and p.OrderId = 1)
								   join vSQDefinitionsRFBand rfb ON (rfb.RFBand = i.RFBand and
                                        (rfb.Tech = 'CDMA' or rfb.Tech like 'IS%'))

UNION all
select 
		vsc.SessionId,
		vsc.TestID,
		vsc.MsgTime,
		vsc.PosId,
		vsc.NetworkID,
		vsc.RFBand,
		vsc.Band as Technology,
		vsc.Channel,
		vsc.rxlev,
		dbo.HexToInt(SUBSTRING(message,35,2)+ SUBSTRING(message,33,2)) as PN,
		Convert(float,dbo.HexToInt(SUBSTRING(message,53,2)))/-2.0 as EcIo,
		Convert(float,vsc.rxlev) + Convert(float,dbo.HexToInt(SUBSTRING(message,53,2)))/-2.0 as RSCP

from 
		vMsgCDMAScannerChnStatus vsc

where 
		vsc.parseCode = 'UPMM' AND
		len(vsc.message)> 32;


-- dbo.vMsgCDMAScannerChannelNo source

ALTER VIEW vMsgCDMAScannerChannelNo
AS
  Select distinct Channel
  From MsgWCDMAScannerChnStatus 
			Join vSQDefinitionsRFBand rfb On(rfb.RFBand=MsgWCDMAScannerChnStatus.RFBand and (rfb.Tech = 'CDMA' or rfb.Tech like 'IS%'))
  Where ParseCode = 'UPMM' and Len(message) > 32
  UNION
  Select distinct Channel
  From MsgWCDMAScannerPilotInfo
			Join vSQDefinitionsRFBand rfb On(rfb.RFBand=MsgWCDMAScannerPilotInfo.RFBand and (rfb.Tech = 'CDMA' or rfb.Tech like 'IS%'))
  Where Version in (100);


-- dbo.vMsgCDMAScannerChnStatus source

ALTER VIEW vMsgCDMAScannerChnStatus
as
  Select MsgWCDMAScannerChnStatus.*,
         rfb.Name as Band
  from MsgWCDMAScannerChnStatus
       JOIN vSQDefinitionsRFBand rfb ON rfb.RFBand = MsgWCDMAScannerChnStatus.RFBand and
                                        (rfb.Tech = 'CDMA' or rfb.Tech like 'IS%');


-- dbo.vMsgGSMReport source

ALTER VIEW vMsgGSMReport
AS
Select
	MsgGSMReport.MsgId,
	MsgGSMReport.SessionId,
	MsgGSMReport.TestId,
	MsgGSMReport.MsgTime,
	MsgGSMReport.PosId,
	MsgGSMReport.NetworkId,
	MsgGSMReport.BCCH,
	MsgGSMReport.RFBand as 'BCCHRFBand',
	dbo.GetRFBand(MsgGSMReport.RFBand) as 'BCCHTechnology',
	MsgGSMReport.TCH,
	dbo.GetTCHRFBand(TCH,RFBand) as 'TCHRFBand',
	dbo.GetRFBand(dbo.GetTCHRFBand(TCH,RFBand)) as 'TCHTechnology'
From
	MsgGSMReport;


-- dbo.vMsgGSMScannerBCCHInterfered source

ALTER VIEW vMsgGSMScannerBCCHInterfered
AS
  Select i.MsgId,
         i.SessionId,
         i.TestId,
         i.MsgTime,
         i.PosId,
         i.NetworkId,
         i.BCCHScanId,

         sc1.RSSI,
         sc1.Channel as ARFCN,
         sc1.CoI,
         sc1.CC1 as NCC,
         sc1.CC2 as BCC,
         CONCAT(sc1.CC1, '-', sc1.CC2) as BSIC,

         sc2.CoI as CoI_2,
         sc2.CC1 as NCC_2,
         sc2.CC2 as BCC_2,
         CONCAT(sc2.CC1, '-', sc2.CC2) as BSIC_2,

         sc3.CoI as CoI_3,
         sc3.CC1 as NCC_3,
         sc3.CC2 as BCC_3,
         CONCAT(sc3.CC1, '-', sc3.CC2) as BSIC_3,

         case when (ISNULL(sc1.CoI, 0) >= ISNULL(sc2.CoI, 0) and ISNULL(sc1.CoI, 0) >= ISNULL(sc3.CoI, 0)) then sc1.CoI
              else case when ISNULL(sc2.CoI, 0) >= ISNULL(sc3.CoI, 0) then sc2.CoI
                        else sc3.CoI
                   end
         end as MaxCoI,
         case when ISNULL(sc1.CoI, 0) >= ISNULL(sc2.CoI, 0) and ISNULL(sc1.CoI, 0) >= ISNULL(sc3.CoI, 0) then
                   case when ISNULL(sc2.CoI, 0) >= ISNULL(sc3.CoI, 0) then sc2.CoI
                        else sc3.CoI
                   end
              else case when ISNULL(sc2.CoI, 0) >= ISNULL(sc3.CoI, 0) then
                             case when ISNULL(sc1.CoI, 0) >= ISNULL(sc3.CoI, 0) then sc1.CoI
                                  else sc3.CoI
                             end
                        else case when ISNULL(sc1.CoI, 0) >= ISNULL(sc2.CoI, 0) then sc1.CoI
                                  else sc2.CoI
                             end
                   end
         end as SecCoI
  from MsgScannerBCCHInfo i
       JOIN MsgScannerBCCH sc1 ON i.BCCHScanId = sc1.BCCHScanId and sc1.OrderId = (Select MIN(c.OrderId) from MsgScannerBCCH c
                                                                                   where c.BCCHScanId = i.BCCHScanId and c.Channel = sc1.Channel)
       JOIN MsgScannerBCCH sc2 ON i.BCCHScanId = sc2.BCCHScanId and sc2.Channel = sc1.Channel
                                                                and sc2.OrderId = (Select MIN(c.OrderId) from MsgScannerBCCH c
                                                                                   where c.BCCHScanId = i.BCCHScanId and c.Channel = sc1.Channel and c.OrderId > sc1.OrderId)
       LEFT JOIN MsgScannerBCCH sc3 ON i.BCCHScanId = sc3.BCCHScanId and sc3.Channel = sc1.Channel and sc3.OrderId > sc2.OrderId and sc3.OrderId > sc1.OrderId;


-- dbo.vMsgGSMScannerTopBCCHInterfered source

ALTER VIEW vMsgGSMScannerTopBCCHInterfered
AS
  Select i.MsgId,
         i.SessionId,
         i.TestId,
         i.MsgTime,
         i.PosId,
         i.NetworkId,
         i.BCCHScanId,

         sc1.RSSI,
         sc1.Channel as ARFCN,
         sc1.CoI,
         sc1.CC1 as NCC,
         sc1.CC2 as BCC,
         CONCAT(sc1.CC1, '-', sc1.CC2) as BSIC,

         sc2.CoI as CoI_2,
         sc2.CC1 as NCC_2,
         sc2.CC2 as BCC_2,
         CONCAT(sc2.CC1, '-', sc2.CC2) as BSIC_2,

         sc3.CoI as CoI_3,
         sc3.CC1 as NCC_3,
         sc3.CC2 as BCC_3,
         CONCAT(sc3.CC1, '-', sc3.CC2) as BSIC_3,

         case when (ISNULL(sc1.CoI, 0) >= ISNULL(sc2.CoI, 0) and ISNULL(sc1.CoI, 0) >= ISNULL(sc3.CoI, 0)) then sc1.CoI
              else case when ISNULL(sc2.CoI, 0) >= ISNULL(sc3.CoI, 0) then sc2.CoI
                        else sc3.CoI
                   end
         end as MaxCoI,
         case when ISNULL(sc1.CoI, 0) >= ISNULL(sc2.CoI, 0) and ISNULL(sc1.CoI, 0) >= ISNULL(sc3.CoI, 0) then
                   case when ISNULL(sc2.CoI, 0) >= ISNULL(sc3.CoI, 0) then sc2.CoI
                        else sc3.CoI
                   end
              else case when ISNULL(sc2.CoI, 0) >= ISNULL(sc3.CoI, 0) then
                             case when ISNULL(sc1.CoI, 0) >= ISNULL(sc3.CoI, 0) then sc1.CoI
                                  else sc3.CoI
                             end
                        else case when ISNULL(sc1.CoI, 0) >= ISNULL(sc2.CoI, 0) then sc1.CoI
                                  else sc2.CoI
                             end
                   end
         end as SecCoI
  from MsgScannerBCCHInfo i
       JOIN MsgScannerBCCH sc1 ON i.BCCHScanId = sc1.BCCHScanId and sc1.RSSI = (Select MAX(c.RSSI) from MsgScannerBCCH c where c.BCCHScanId = i.BCCHScanId)
                                                                and sc1.OrderId = (Select MIN(c.OrderId) from MsgScannerBCCH c
                                                                                   where c.BCCHScanId = i.BCCHScanId and c.Channel = sc1.Channel)
       JOIN MsgScannerBCCH sc2 ON i.BCCHScanId = sc2.BCCHScanId and sc2.Channel = sc1.Channel
                                                                and sc2.OrderId = (Select MIN(c.OrderId) from MsgScannerBCCH c
                                                                                   where c.BCCHScanId = i.BCCHScanId and c.Channel = sc1.Channel and c.OrderId > sc1.OrderId)
       LEFT JOIN MsgScannerBCCH sc3 ON i.BCCHScanId = sc3.BCCHScanId and sc3.Channel = sc1.Channel and sc3.OrderId > sc2.OrderId and sc3.OrderId > sc1.OrderId;


-- dbo.vMsgGSMScannerTopCovI source

ALTER VIEW vMsgGSMScannerTopCovI
AS
	Select
		info.MsgId,
		info.SessionId,
		info.TestId,
		info.PosId,
		info.NetworkID,
		info.msgTime,
		op.Display,
		sc.Chn_GSM850,
		sc.CovI_GSM850,
		sc.RxLev_GSM850,
		sc.Chn_GSM900,
		sc.CovI_GSM900,
		sc.RxLev_GSM900,
		sc.Chn_GSM1800,
		sc.CovI_GSM1800,
		sc.RxLev_GSM1800,
		sc.Chn_GSM1900,
		sc.CovI_GSM1900,
		sc.RxLev_GSM1900,
		rfb.Name as Band,
		sc.TopChn,
		sc.TopCovI,
		sc.TopRxLev
	From
		MsgGSMScannerTopCovI sc 
		JOIN MsgGSMScannerTopCovIInfo info ON sc.TopCovIId = info.TopCovIId
		JOIN Operators op On op.MCC = sc.MCC and op.MNC = sc.MNC
		JOIN vSQDefinitionsRFBand rfb ON rfb.RFBand = sc.TopRFBand;


-- dbo.vMsgGsmL3Data source

ALTER VIEW vMsgGsmL3Data
AS
  Select FactId as MsgId,
         SessionId,
         VirtualTestId as TestId,
         FullDate as MsgTime,
         PosId,
         NetworkId,
         Direction,
         Identifier2 as ProtDiscr,
         SUBSTRING(Message, 4, 1) as TrSkInd,
         Identifier3 as MsgType,
         SUBSTRING(Message, 8, 500) as L3Data,
         SimpleMsgName as Msg,
         Message,
         Layer
  from FactL3Messages
  where Technology = 'GSM' and
        Identifier in (0, 1);


-- dbo.vMsgHotChannels source

ALTER VIEW vMsgHotChannels
AS
  Select MsgHotChannels.*,
         rfb.Name as Band
  from MsgHotChannels
       JOIN vSQDefinitionsRFBand rfb ON rfb.RFBand = MsgHotChannels.RFBand;


-- dbo.vMsgHotChannelsBestOpOverall source

ALTER VIEW vMsgHotChannelsBestOpOverall
AS
  Select MsgHotChannels.*,
         rfb.Name as Band
  from MsgHotChannels
       JOIN vSQDefinitionsRFBand rfb ON rfb.RFBand = MsgHotChannels.RFBand
	   where
Convert(integer,substring(MsgHotChannels.top20op,6,4)) = (Select max(Convert(integer,substring(o.top20op,6,4)))From MsgHotChannels o where MsgHotChannels.msgtime = o.msgtime AND MsgHotChannels.Sessionid = o.Sessionid) AND
Convert(integer,substring(MsgHotChannels.top20op,6,4)) is not NULL;


-- dbo.vMsgLTEScannerBestRefS source

ALTER VIEW vMsgLTEScannerBestRefS
AS
Select
	Info.SessionId,
	Info.TestId,
	Info.MsgTime,
	Info.NetworkId,
	Info.PosId,
	Info.Channel as 'EARFCN',
	Case when Info.Bandwidth<2000 then 1.4 else Info.Bandwidth/1000 end as 'Bandwidth',
	Info.RSSI_0 as 'RSSI0',
	Info.RSSI_1 as 'RSSI1',
	Pilot.PCI,
	Pilot.MIMO,
	Case when Pilot.MIMO=1 then 'MIMO'
		when Pilot.MIMO=0 then 'NoMIMO'
		else NULL end as 'MIMOOrNoMIMO',
	Pilot.RSRP,
	Pilot.RSRQ,
	Pilot.CINR,
	Pilot.CN,
	Pilot.PeakEThp,
	Convert(varchar, Info.Channel) + ' ' + Convert(varchar, Pilot.PCI) as 'ChannelAndPhCId'
From
	MsgLTEScannerTopNInfo Info
	Join MsgLTEScannerTopNRef Pilot On(Info.LTETopNId=Pilot.LTETopNId)
Where 
	Pilot.OrderId=1;


-- dbo.vMsgLTEScannerBestSyncS source

ALTER VIEW vMsgLTEScannerBestSyncS
AS
Select
	Info.SessionId,
	Info.TestId,
	Info.MsgTime,
	Info.NetworkId,
	Info.PosId,
	Info.Channel as 'EARFCN',
	Case when Info.Bandwidth<2000 then 1.4 else Info.Bandwidth/1000 end as 'Bandwidth',
	Info.RSSI_0 as 'RSSI0',
	Info.RSSI_1 as 'RSSI1',
	Pilot.PCI,
	Pilot.PSCHRP,
	Pilot.PSCHRQ,
	Pilot.SCHCINR,
	Convert(varchar, Info.Channel) + ' ' + Convert(varchar, Pilot.PCI) as 'ChannelAndPhCId'
From
	MsgLTEScannerTopNInfo Info
	Join MsgLTEScannerTopNSync Pilot On(Info.LTETopNId=Pilot.LTETopNId)
Where 
	Pilot.OrderId=1;


-- dbo.vMsgLTEScannerNBIoT source

ALTER VIEW vMsgLTEScannerNBIoT
AS
  Select i.MsgId,
         i.SessionId,
         i.TestId,
         i.MsgTime,
         i.PosId,
         i.NetworkId,
         i.ScannerId,
         i.Version,
         i.RFBand,
         i.OperationMode,
         i.CenterFrequency,
         i.EARFCN,
         i.NumCells,
         i.MessageVersion,
         case when t.CyclicPrefix  = 6 then 'Extended'
              when t.CyclicPrefix  = 7 then 'Normal'
              else 'unknown'
         end as CP,
         case when t.FrameStruct  = 1 then 'FDD'
              when t.FrameStruct  = 2 then 'TDD'
              else 'unknown'
         end as FS,
         t.*
  from vMsgLTEScannerNBIoTInfo i
       LEFT JOIN (Select ROW_NUMBER() OVER(PARTITION BY LTENBIoTId ORDER BY ISNULL(NRSRP_A0, ISNULL(NRSRP_A1, -150)) DESC) as RSRPOrderId,
                         ISNULL(NRSRP_A0, ISNULL(NRSRP_A1, -150)) as NRSRPChart,
                         nbiot.LTENBIoTId,
                         nbiot.OrderId,
                         nbiot.LTENBIoTSIBId,
                         nbiot.PCI,
                         nbiot.UniqueId,
                         nbiot.CyclicPrefix,
                         nbiot.FrameStruct,
                         nbiot.NRSSI,
                         nbiot.NSSSCINR,
                         nbiot.NSSSPower,
                         nbiot.NRSRQ_A0,
                         nbiot.NRSRQ_A1,
                         nbiot.NRSRP_A0,
                         nbiot.NRSRP_A1,
                         nbiot.NRSCINR_A0,
                         nbiot.NRSCINR_A1,
                         nbiot.NRSRSSI_A0,
                         nbiot.NRSRSSI_A1
                  from MsgLTEScannerNBIoT nbiot) t ON t.LTENBIoTId = i.LTENBIoTId;


-- dbo.vMsgLTEScannerNBIoTInfo source

ALTER VIEW vMsgLTEScannerNBIoTInfo
AS
  Select MsgId,
         SessionId,
         TestId,
         MsgTime,
         PosId,
         NetworkId,
         LTENBIoTId,
         ScannerId,
         Version,
         RFBand,
         case when OperationMode = 1 then 'In band'
              when OperationMode = 2 then 'Guard band'
              when OperationMode = 3 then 'Stand alone'
              else 'unknown'
         end as OperationMode,
         CenterFrequency / 1000000.0 as CenterFrequency,
         EARFCN,
         NumCells,
         MessageVersion
  from MsgLTEScannerNBIoTInfo;


-- dbo.vMsgLTEScannerTopChOperator source

ALTER VIEW vMsgLTEScannerTopChOperator
AS
  Select t.SessionId,
         t.TestId,
         t.MsgTime,
         t.PosId,
         t.NetworkId,
         t.TopChnId,
         o.Display as Operator,
         h.MCC,
         h.MNC,
         CONVERT(varchar, h.MCC) + ' - ' + CONVERT(varchar, h.MNC) as PLMN,
         rfb.Name as Band,
         h.Channel as EARFCN,
         h.PCI,
         CONVERT(varchar, h.Channel) + ' - ' + CONVERT(varchar, h.PCI) as Server,
         h.RQ as RSRQ,
         h.RP as RSRP,
         h.RSSI,
         h.CINR,
         case when h.GroupMode in (2, 3) then 'All Operator' else o.Display end as SelectOperator,
         case when h.GroupMode in (0, 2) then 'All Bands' else rfb.Name end as SelectBand,
         CONVERT(varchar, h.SortMode) + '-' + CONVERT(varchar, h.GroupMode) as	Mode,
         h.GroupMode,
         h.SortMode
  from Sessions s
       JOIN MsgLTEScannerTopChInfo t ON s.SessionId = t.SessionId
       JOIN MsgLTEScannerTopCh h ON t.TopChnId = h.TopChnId
       LEFT JOIN Operators o ON o.MCC = h.MCC and o.MNC = h.MNC
       JOIN vSQDefinitionsRFBand rfb ON rfb.RFBand = h.RFBand;


-- dbo.vMsgLTEScannerTopMIMO source

ALTER VIEW vMsgLTEScannerTopMIMO
AS
select 
		Info.MsgId,
		Info.SessionId,
		Info.TestId,
		Info.MsgTime,
		Info.NetworkId,
		Info.PosID,
		case when Info.Bandwidth < 2000 then 1.4 else Info.Bandwidth/1000 end as Bandwidth,
		Info.Channel as EARFCN,
		Info.RFBand,
		Info.RSSI_0,
		Info.RSSI_1,
		Pilot.CINR,
		Pilot.CN,
		Pilot.PeakEThp,
		Pilot.PCI,
		pilot.RSRP,
		pilot.RSRQ,
		pilot.MIMO,
		pilot.ECQI_TM3_DL2

from		
		MsgLTEScannerTopNInfo info,
		MsgLTEScannerTopNRef pilot

where
		info.LTETopNId = pilot.LTETopNId and
		pilot.OrderId = 1 and
		pilot.MIMO = 1;


-- dbo.vMsgLTEScannerTopRSRQ source

ALTER VIEW vMsgLTEScannerTopRSRQ
As
Select
	i.SessionId,
	i.TestId,
	i.MsgTime,
	i.PosId,
	i.NetworkId,
	i.LTETopNId,
	i.RFBand,
	i.Channel,
	i.Bandwidth,
	i.RSSI_0,
	i.RSSI_1,
	i.NumRecords,

	t1.RSRQ as 'RSRQ01',
	t1.RSRP as 'RSRP01',
	t1.CINR as 'CINR01',
	t1.CN as 'CN01',
	t1.PCI as 'PhCId01',
	t1.MIMO as 'MIMO01',
	t1.PeakEThp as 'PeakEthp01',

	t2.RSRQ as 'RSRQ02',
	t1.RSRQ-t2.RSRQ as 'RSRQ_Delta_02',
	t2.RSRP as 'RSRP02',
	t1.RSRP-t2.RSRP as 'RSRP_Delta_02',
	t2.CINR as 'CINR02',
	t2.CN as 'CN02',
	t2.PCI as 'PhCId02',
	t2.MIMO as 'MIMO02',
	t2.PeakEThp as 'PeakEthp02',

	t3.RSRQ as 'RSRQ03',
	t1.RSRQ-t3.RSRQ as 'RSRQ_Delta_03',
	t3.RSRP as 'RSRP03',
	t1.RSRP-t3.RSRP as 'RSRP_Delta_03',
	t3.CINR as 'CINR03',
	t3.CN as 'CN03',
	t3.PCI as 'PhCId03',
	t3.MIMO as 'MIMO03',
	t3.PeakEThp as 'PeakEthp03',

	t4.RSRQ as 'RSRQ04',
	t1.RSRQ-t4.RSRQ as 'RSRQ_Delta_04',
	t4.RSRP as 'RSRP04',
	t1.RSRP-t4.RSRP as 'RSRP_Delta_04',
	t4.CINR as 'CINR04',
	t4.CN as 'CN04',
	t4.PCI as 'PhCId04',
	t4.MIMO as 'MIMO04',
	t4.PeakEThp as 'PeakEthp04',

	t5.RSRQ as 'RSRQ05',
	t1.RSRQ-t4.RSRQ as 'RSRQ_Delta_05',
	t5.RSRP as 'RSRP05',
	t1.RSRP-t5.RSRP as 'RSRP_Delta_05',
	t5.CINR as 'CINR05',
	t5.CN as 'CN05',
	t5.PCI as 'PhCId05',
	t5.MIMO as 'MIMO05',
	t5.PeakEThp as 'PeakEthp05'

From
	MsgLTEScannerTopNInfo i 
	Join MsgLTEScannerTopNRef t1 on (i.LTETopNId=t1.LTETopNId and t1.OrderId=1)
	Left Join MsgLTEScannerTopNRef t2 on (i.LTETopNId=t2.LTETopNId and t2.OrderId=2)
	Left Join MsgLTEScannerTopNRef t3 on (i.LTETopNId=t3.LTETopNId and t3.OrderId=3)
	Left Join MsgLTEScannerTopNRef t4 on (i.LTETopNId=t4.LTETopNId and t4.OrderId=4)
	Left Join MsgLTEScannerTopNRef t5 on (i.LTETopNId=t5.LTETopNId and t5.OrderId=5);


-- dbo.vMsgScannerBCCHLayer3Info source

ALTER VIEW vMsgScannerBCCHLayer3Info
AS
  SELECT i.SessionID,
         i.testID,
         i.NetworkId,
         i.msgTime,
         i.PosId,
         s.RFBand,
         s.Channel,
         s.RSSI,
         s.CoI,
         s.MCC,
         s.MNC,
         s.LAC,
         s.CID,
         s.CC1 as NCC,
         s.CC2 as BCC,
         o.Display,
         CONVERT(varchar, s.CC1) + '-' + CONVERT(varchar, s.CC2) as BSIC,
         CONVERT(varchar, s.Channel) + ' ' + CONVERT(varchar, s.CC1) + '-' + convert(varchar, s.CC2) as ChBSIC
  from MsgScannerBCCH s
  JOIN MsgScannerBCCHInfo i ON i.BCCHScanID = s.BCCHScanID
  JOIN Operators o ON o.MCC = s.MCC AND  o.MNC = s.MNC;


-- dbo.vMsgScannerBCCHTopBandOperator source

ALTER VIEW vMsgScannerBCCHTopBandOperator
AS
  Select i.MsgId,
         i.SessionId,
         i.TestId,
         i.MsgTime,
         i.PosId,
         i.NetworkId,
         t.BCCHScanId,
         t.RFBand,
         t.RSSI,
         t.Channel,
         t.CoI,
         t.BSIC,
         t.MCC,
         t.MNC,
         t.Display,
         t.OrderId,
         t.BandOrderId,
         t.OperatorOrderId,
         t.OperatorBandOrderId
  From (Select ROW_NUMBER() OVER(PARTITION BY BCCHScanId, Operator ORDER BY RSSI DESC) as OperatorOrderId,
               ROW_NUMBER() OVER(PARTITION BY BCCHScanId, Operator, RFBand ORDER BY RSSI DESC) as OperatorBandOrderId,
               ROW_NUMBER() OVER(PARTITION BY BCCHScanId, RFBand ORDER BY RSSI DESC) as BandOrderId,
               bcch.*,  CONCAT(bcch.CC1, '-', bcch.CC2) as BSIC, o.Display
        From MsgScannerBCCH bcch LEFT JOIN Operators o ON o.MCC = bcch.MCC AND o.MNC = bcch.MNC) t
       JOIN MsgScannerBCCHInfo i ON t.BCCHScanId = i.BCCHScanId
	LEFT JOIN Operators o ON o.MCC = t.MCC AND  o.MNC = t.MNC;


-- dbo.vMsgScannerTopChannel source

ALTER VIEW vMsgScannerTopChannel
AS

  Select i.MsgId,
         i.SessionId,
         i.TestId,
         i.PosId,
         i.NetworkID,
         i.msgTime,
         o.Display,
         c.Chn_GSM850,
         c.RxLev_GSM850,
         c.Chn_GSM900,
         c.RxLev_GSM900,
         c.Chn_EGSM900,
         c.RxLev_EGSM900,
         c.Chn_GSM1800,
         c.RxLev_GSM1800,
         c.Chn_GSM1900,
         c.RxLev_GSM1900,
         rfb.Name as Band,
         c.TopChn,
         c.TopRxLev
  From MsgScannerTopChannel c
       JOIN MsgScannerTopChannelinfo i ON c.TopChnId = i.TopChnId
       JOIN Operators o ON o.MCC = c.MCC and o.MNC = c.MNC
       JOIN vSQDefinitionsRFBand rfb ON rfb.RFBand = c.TopRFBand;


-- dbo.vMsgScannerTopChannelRG source

ALTER VIEW vMsgScannerTopChannelRG
AS

  Select *,
	c.Display as 'Operator Scanner'
  From vMsgScannerTopChannel c;


-- dbo.vMsgWCDMAScannerBCHLayer3Info source

ALTER VIEW vMsgWCDMAScannerBCHLayer3Info
AS
  SELECT i.SessionID,
         i.testID,
         i.NetworkId,
         i.msgTime,
         i.PosId,
         i.channel,
         i.PNThreshold,
         s.Number as PSC,
         o.Display,
         s.MCC,
         s.MNC,
         s.LAC,
         s.CID,
         CONVERT(varchar, i.channel) + ' ' + CONVERT(varchar, s.Number) AS ChPSC,
         CONVERT(varchar, s.MCC)     + ' ' + CONVERT(varchar, s.MNC) + ' ' +
         CONVERT(varchar, i.channel) + ' ' + CONVERT(varchar, s.Number) AS OpChPSC,
         i.[IO] ,
         s.EcIoData as EcIo,
         i.[IO] + s.EcIoData as RSCP,
         s.SigIntRatio as SIR,
         s.ULInterference
  from MsgWCDMAScannerPilot s
       JOIN MsgWCDMAScannerPilotInfo i ON i.WPilotId = s.WPilotId
       JOIN Operators o ON o.MCC = s.MCC AND o.MNC = s.MNC;


-- dbo.vMsgWCDMAScannerBestServer source

ALTER VIEW vMsgWCDMAScannerBestServer
AS
  Select SessionId,
         TestId,
         MsgTime,
         NetworkId,
         PosId,
         Channel,
         RxLev as 'RSSI',
         Convert(float, Rxlev) + Convert(float, dbo.MaxCPich(message)) as 'MaxCPICHRSCP',
         Convert(float, dbo.MaxCPich(message)) as 'MaxCPICHEcNo',
         Convert(float, dbo.SCodeOfMaxCpich(message)) as 'PSCMaxCPICH',
         Convert(varchar, Channel) + ' ' + Convert(varchar, dbo.SCodeOfMaxCpich(message)) as 'ChannelAndPSC',
         NULL as MCC, NULL as MNC, NULL as LAC, NULL as CID,
         NULL as CGI,
         rfb.Tech as Technology
  from MsgWCDMAScannerChnStatus
		Join  vSQDefinitionsRFBand rfb On(rfb.RFBand=MsgWCDMAScannerChnStatus.RFBand and rfb.Tech='UMTS')
  where ParseCode = 'UPMM' and Len(message) > 32

  UNION

  Select Info.SessionId,
         Info.TestId,
         Info.Msgtime,
         Info.NetworkId,
         Info.PosId,
         Info.Channel,
         Info.IO as 'RSSI',
         Info.IO + Pilot.EcIoData as 'MaxCPICHRSCP',
         Pilot.EcIoData as 'MaxCPICHEcNo',
         Pilot.Number as 'PSCMaxCPICH',
         Convert(varchar, Info.Channel) + ' ' + Convert(varchar, Pilot.Number) as 'ChannelAndPSC',
         Pilot.MCC, Pilot.MNC, Pilot.LAC, Pilot.CID,
         CONVERT(varchar, Pilot.CID) + '-' + CONVERT(varchar, Pilot.LAC) + '-' + CONVERT(varchar, Pilot.MNC) + '-' + CONVERT(varchar, Pilot.MCC) COLLATE Latin1_General_CI_AS as CGI,
         rfb.Tech as Technology
  from MsgWCDMAScannerPilotInfo Info 
       JOIN MsgWCDMAScannerPilot Pilot ON Info.WPilotId = Pilot.WPilotId
       JOIN vSQDefinitionsRFBand rfb On(rfb.RFBand=Info.RFBand and rfb.Tech='UMTS')
  where Info.Version in (2, 16) and Pilot.OrderId = 1;


-- dbo.vMsgWCDMAScannerChnStatus source

ALTER VIEW vMsgWCDMAScannerChnStatus
as
  Select MsgWCDMAScannerChnStatus.*,
         rfb.Name as Band
  from MsgWCDMAScannerChnStatus
       JOIN vSQDefinitionsRFBand rfb ON rfb.RFBand = MsgWCDMAScannerChnStatus.RFBand and
                                        rfb.Tech = 'UMTS';


-- dbo.vMsgWCDMAScannerTopChHomeOperator source

ALTER VIEW vMsgWCDMAScannerTopChHomeOperator
AS
  SELECT
		i.MsgID,
		i.SessionID,
		i.TestID,
		i.MsgTime,
		i.PosID,
		i.NetworkID,
		t.CPICH,
		t.SCode,
		t.RSSI as RxLev,
		t.channel,
		t.RFBand

  FROM
		MsgWCDMAScannerTopChInfo i
		JOIN MsgWCDMAScannerTopCh t ON t.TopChnId = i.TopChnId
		JOIN NetworkInfo n ON n.NetworkId = i.NetworkId and n.HOMCC = t.MCC and n.HOMNC = t.MNC
		JOIN vSQDefinitionsRFBand rfb ON rfb.RFBand = t.RFBand and rfb.Tech = 'UMTS'
  WHERE t.SortMode = 0 and t.GroupMode = 0;


-- dbo.vMsgWCDMAScannerTopChOperator source

ALTER VIEW vMsgWCDMAScannerTopChOperator
AS
  Select t.SessionId,
         t.TestId,
         t.MsgTime,
         t.PosId,
         t.NetworkId,
         t.TopChnId,
         o.Display as Operator,
         h.MCC,
         h.MNC,
         CONVERT(varchar, h.MCC) + ' - ' + CONVERT(varchar, h.MNC) as PLMN,
         rfb.Name as Band,
         h.Channel as UARFCN,
         h.SCode,
         CONVERT(varchar, h.Channel) + ' - ' + CONVERT(varchar, h.SCode) as Server,
         h.CPICH as ECIO,
         h.CPICH + h.RSSI as RSCP,
         h.RSSI,
         case when h.GroupMode in (2, 3) then 'All Operator' else o.Display end as SelectOperator,
         case when h.GroupMode in (0, 2) then 'All Bands' else rfb.Name end as SelectBand,
         CONVERT(varchar, h.SortMode) + '-' + CONVERT(varchar,h.GroupMode) as	Mode,
         h.GroupMode,
         h.SortMode
  from Sessions s
       JOIN MsgWCDMAScannerTopChInfo t ON s.SessionId = t.SessionId
       JOIN MsgWCDMAScannerTopCh h ON t.TopChnId = h.TopChnId
       LEFT JOIN Operators o ON o.MCC = h.MCC and o.MNC = h.MNC
       JOIN vSQDefinitionsRFBand rfb ON rfb.RFBand = h.RFBand;


-- dbo.vMsgWCDMAScannerTopChannel source

ALTER VIEW vMsgWCDMAScannerTopChannel
AS
  SELECT i.MsgId,
         i.SessionId,
         i.TestId,
         i.PosId,
         i.NetworkID,
         i.msgTime,
         o.Display,
         c.Channel,
         c.RSSI,
         c.SCode,
         c.TmRef,
         c.SChip,
         c.P_SCH,
         c.S_SCH,
         c.CPICH,
         c.B_CCH,
         rfb.Name AS Band
  FROM MsgWCDMAScannerTopCh c
       JOIN MsgWCDMAScannerTopChInfo i ON c.TopChnId = i.TopChnId
       JOIN Operators o ON o.MCC = c.MCC AND o.MNC = c.MNC
       JOIN vSQDefinitionsRFBand rfb ON rfb.RFBand = c.RFBand
  WHERE c.SortMode = 0 and c.GroupMode = 0;


-- dbo.vMsgWCDMAScannerUARFCN source

ALTER VIEW vMsgWCDMAScannerUARFCN
AS
  Select distinct Channel
  From MsgWCDMAScannerChnStatus 
			Join vSQDefinitionsRFBand rfb On(rfb.RFBand=MsgWCDMAScannerChnStatus.RFBand and rfb.Tech='UMTS')
  Where ParseCode = 'UPMM' and Len(message) > 32
  UNION
  Select distinct Channel
  From MsgWCDMAScannerPilotInfo
			Join vSQDefinitionsRFBand rfb On(rfb.RFBand=MsgWCDMAScannerPilotInfo.RFBand and rfb.Tech='UMTS')
  Where Version in (2, 16);


-- dbo.vNBIoTPDSCHStatisticsInfoThroughput source

ALTER VIEW vNBIoTPDSCHStatisticsInfoThroughput
AS
  Select SessionId, TestId, MsgTime, PosId, NetworkId,
	 dbo.DelphiDateTime(MsgTime) as dTime,
	 CONVERT(varchar, MsgTime, 14) as msgTime2,
         ThroughputWhenScheduled / 1000 as ThroughputWhenScheduled,
         Throughput / 1000 as Throughput,
         LTrim(Str(ThroughputWhenScheduled / 1000, 10, 2)) as ThroughputWhenScheduledAsString,
         LTrim(Str(Throughput / 1000, 10, 2)) as ThroughputAsString
  from NBIoTPDSCHStatisticsInfo;


-- dbo.vNBIoTPUSCHStatisticsInfo source

ALTER VIEW vNBIoTPUSCHStatisticsInfo
AS
  SELECT SessionId,
         VirtualTestId AS Testid,
         FullDate AS MsgTime,
         PosId,
         NetworkId,
         dbo.DelphiDateTime(FullDate) AS dTime,
         CONVERT(varchar, FullDate, 14) AS msgTime2,
         CASE WHEN SubCarrierSpace IS NULL THEN '---'
              ELSE CONVERT(varchar, SubCarrierSpace)
         END AS SubCarrierSpace,
         ACKRate * 100 AS ACKRate,
         RetransmissionRate * 100 AS RetransmissionRate,
         AvgRU,
         AvgNumTone1,
         AvgNumTone2,
         MinTBSize,
         MaxTBSize,
         AvgTBSize,
         MinMCS,
         MaxMCS,
         AvgMCS,
         AvgRepetition1 * 100 AS AvgRepetition1,
         AvgRepetition2 * 100 AS AvgRepetition2,
         Format1Rate * 100 AS Format1Rate,
         Format2Rate * 100 AS Format2Rate,
         PRACHCollisions * 100 AS PRACHCollisions,
         PRACHCollisions7680ms * 100 AS PRACHCollisions7680ms,
         LTrim(Str(ACKRate * 100, 10, 2)) AS ACKRateAsString,
         LTrim(Str(RetransmissionRate * 100, 10, 2)) AS RetransmissionRateAsString,
         LTrim(Str(AvgRU, 10, 2)) AS AvgRUAsString,
         LTrim(Str(AvgNumTone1, 10, 2)) AS AvgNumTone1AsString,
         LTrim(Str(AvgNumTone2, 10, 2)) AS AvgNumTone2AsString,
         LTrim(Str(AvgRepetition1 * 100, 10, 2)) AS AvgRepetition1AsString,
         LTrim(Str(AvgRepetition2 * 100, 10, 2)) AS AvgRepetition2AsString,
         LTrim(Str(Format1Rate * 100, 10, 2)) AS Format1RateAsString,
         LTrim(Str(Format2Rate * 100, 10, 2)) AS Format2RateAsString,
         LTrim(Str(PRACHCollisions * 100, 10, 2)) AS PRACHCollisionsAsString,
         LTrim(Str(PRACHCollisions7680ms * 100, 10, 2)) AS PRACHCollisions7680msAsString
  FROM FactNBIoTPUSCHStatisticsInfo;


