-- dbo.vNBIoTServingCellInfo source

ALTER VIEW vNBIoTServingCellInfo
AS
  Select SessionId, VirtualTestId as TestId, FullDate as MsgTime, PosId, NetworkId,
         dbo.DelphiDateTime(FullDate) as dTime,
         CONVERT(varchar, FullDate, 14) as msgTime2,
         PCI,
         DLEARFCN,
         ULEARFCN,
         DLBandWidth,
         ULBandWidth,
         CellIdentity,
         TAC,
         BandIndicator,
         MCC,
         MNC,
         case
           when ServiceState is NULL then '---'
           else ServiceState
         end as ServiceState,
         eNBAntennas,
         UEAntennas,
         case
           when NBOpMode is NULL then '---'
           else NBOpMode
         end as OpMode,
         case
           when NBMeasBW is NULL then '---'
           else CONVERT(varchar, NBMeasBW)
         end as MeasBW,
         NBRank,
         LTrim(Str(Srxlev, 10, 2)) as Srxlev,
         LTrim(Str(Qrxlevmin, 10, 2)) as Qrxlevmin,
         LTrim(Str(PMax, 10, 2)) as PMax,
         LTrim(Str(MaxUETxPower, 10, 2)) as MaxUETxPower
  from FactNBIoTCellInfo;


-- dbo.vNR5GMIBMessage source

ALTER VIEW vNR5GMIBMessage
AS
  Select SessionId, VirtualTestId, MsgTime, PosId, NetworkId,
         dbo.DelphiDateTime(MsgTime) as dTime,
         CONVERT(varchar, MsgTime, 14) as msgTime2,
         PCI,
         NRARFCN,
         SFN,
         BlockIndex,
         HalfNumber,
         case IntraFreqResel
           when 0 then 'Allowed'
           when 1 then 'Not allowed'
           else '---'
         end as IntraFreqResel,
         case CellBarred
           when 0 then 'Barred'
           when 1 then 'Not barred'
           else '---'
         end as CellBarred,
         PDCCHConfigSIB1ControlRSZ,
         PDCCHConfigSIB1SearchSPZ,
         case DMRSTypeAPos
           when 0 then 'Pos 0'
           when 1 then 'Pos 1'
           when 2 then 'Pos 2'
           when 3 then 'Pos 3'
           else '---'
         end as DMRSTypeAPos,
         SSBSubcarrierOffset,
         SubcarrierSpacingCommon
from NR5GMIBMessage;


