-- dbo.vNetworkInfo source

ALTER VIEW vNetworkInfo
As
  Select NetworkId,
         FileId,
         MsgTime,
         CID,
         MCC,
         MNC,
         LAC,
         CGI,
         Case when CGI = '' then Convert(varchar, CID) + '-' + Convert(varchar, LAC) + '-' +
                                 Convert(varchar, MNC) + '-' + Convert(varchar, MCC)
              else CGI
         end as CGIUpdate,
         technology,
         RFBand,
         Operator,
         HomeOperator,
         case when Status in (6, 8) then Technology
              else dbo.GetNetworkStatusDescription(Status)
         end as TechnologyStatus,
         Duration
  From NetworkInfo;


-- dbo.vOperatorWCDMAPilotScan source

ALTER VIEW vOperatorWCDMAPilotScan
AS
  Select 'All Operators' as SelectOperator
  UNION ALL
  Select op.Display AS SelectOperator
  from Operators op
       INNER JOIN (Select DISTINCT mnc, mcc FROM MsgWCDMAScannerPilot) ps ON ps.MNC = op.MNC AND ps.MCC = op.MCC;


-- dbo.vPCAPSummary source

ALTER VIEW vPCAPSummary
AS
  Select dbo.DelphiDateTime(t.startTime) as dTime,
         p.SessionId,
         p.TestId,
         p.FrameCount,
         p.Bytes,
         p.FramesLost,
         p.FramesOutOfOrder,
         p.WindowFullEvent,
         case when p.FrameCount > 0 then CAST(100.0 * p.FramesLost / p.FrameCount as Decimal(5, 1))
              else 0
         end as PacketLoss,
         case when p.FrameCount > 0 then CAST(100.0 * p.FramesOutOfOrder / p.FrameCount as Decimal(5, 1))
              else 0
         end as PacketsOoO
  from TestInfo t
       JOIN PCAPSummary p ON p.TestId = t.TestId;


