-- dbo.vRRCEstablishmentCause source

ALTER  VIEW vRRCEstablishmentCause
AS
SELECT
	sessionID,
	MsgTime,
	case (dbo.HexToTinyInt(substring(Msg, 11, 1)) & 0x07)
	     when 1  then case ((dbo.HexToTinyInt(substring(Msg,23, 1)) & 0x08) / 8) -- TMSI + LAI
		     when 1 then (dbo.HexToInt(substring(Msg,30,2))& 0x7C) /4 	--  3rd digit of MNC present
		     else 	 (dbo.HexToInt(substring(Msg,29,2))& 0x7C) /4  end --  3rd digit of MNC not present
	     when 2  then case ((dbo.HexToTinyInt(substring(Msg,21, 1)) & 0x08) / 8)	-- P-TMSI + RAI
		     when 1 then (dbo.HexToInt(substring(Msg,32,2))& 0x7C) /4 	--  3rd digit of MNC present
		     else 	 (dbo.HexToInt(substring(Msg,31,2))& 0x7C) /4  end  --  3rd digit of MNC not present
	     else   255 end
		      as CauseNumber,
	case (case (dbo.HexToTinyInt(substring(Msg, 11, 1)) & 0x07)
	     when 1  then case ((dbo.HexToTinyInt(substring(Msg,23, 1)) & 0x08) / 8) -- TMSI + LAI
		     when 1 then (dbo.HexToInt(substring(Msg,30,2))& 0x7C) /4 	--  3rd digit of MNC present
		     else 	 (dbo.HexToInt(substring(Msg,29,2))& 0x7C) /4  end --  3rd digit of MNC not present
	     when 2  then case ((dbo.HexToTinyInt(substring(Msg,21, 1)) & 0x08) / 8)	-- P-TMSI + RAI
		     when 1 then (dbo.HexToInt(substring(Msg,32,2))& 0x7C) /4 	--  3rd digit of MNC present
		     else 	 (dbo.HexToInt(substring(Msg,31,2))& 0x7C) /4  end  --  3rd digit of MNC not present
	     else   255 end)
	 	when 0 then 'originatingConversationalCall'
		when 1 then 'originatingStreamingCall'
		when 2 then 'originatingInteractiveCall'
		when 3 then 'originatingBackgroundCall'
		when 4 then 'originatingSubscribedTrafficCall'
		when 5 then 'terminatingConversationalCall'
		when 6 then 'terminatingStreamingCall'
		when 7 then 'terminatingInteractiveCall'
		when 8 then 'terminatingBackgroundCall'
		when 9 then 'emergencyCall'
		when 10 then 'interRAT-CellReselection'
		when 11 then 'interRAT-CellChangeOrder'
		when 12 then 'registration'
		when 13 then 'detach'
		when 14 then 'originatingHighPrioritySignalling'
		when 15 then 'originatingLowPrioritySignalling'
		when 16 then 'callRe-establishment'
		when 17 then 'terminatingHighPrioritySignalling'
		when 18 then 'terminatingLowPrioritySignalling'
		when 19 then 'terminatingCauseUnknown'
		when 20 then 'spare1'
		when 255 then 'RCCRequest not decoded'
		else 'not defined' end as EstablishmentCause

FROM	WCDMARRCMessages
WHERE	LogChanType = 0
and	(dbo.HexToTinyInt(substring(Msg, 1, 1)) & 0x08) = 8		-- integrityCheckInfo
and	((dbo.HexToTinyInt(substring(Msg, 10, 1)) & 0x06) / 2) = 1	-- RRCConnectionRequest

UNION ALL

SELECT
	sessionID,
	MsgTime,
	case (dbo.HexToTinyInt(substring(Msg, 2, 1)) & 0x07)
	     when 1  then case ((dbo.HexToTinyInt(substring(Msg,14, 1)) & 0x08) / 8) -- TMSI + LAI
		     when 1 then (dbo.HexToInt(substring(Msg,21,2))& 0x7C) /4 	--  3rd digit of MNC present
		     else 	 (dbo.HexToInt(substring(Msg,20,2))& 0x7C) /4  end --  3rd digit of MNC not present
	     when 2  then case ((dbo.HexToTinyInt(substring(Msg,12, 1)) & 0x08) / 8)	-- P-TMSI + RAI
		     when 1 then (dbo.HexToInt(substring(Msg,23,2))& 0x7C) /4 	--  3rd digit of MNC present
		     else 	 (dbo.HexToInt(substring(Msg,22,2))& 0x7C) /4  end  --  3rd digit of MNC not present
	     else   255 end
		      as CauseNumber,
	case (case (dbo.HexToTinyInt(substring(Msg, 2, 1)) & 0x07)
	     when 1  then case ((dbo.HexToTinyInt(substring(Msg,14, 1)) & 0x08) / 8) -- TMSI + LAI
		     when 1 then (dbo.HexToInt(substring(Msg,21,2))& 0x7C) /4 	--  3rd digit of MNC present
		     else 	 (dbo.HexToInt(substring(Msg,20,2))& 0x7C) /4  end --  3rd digit of MNC not present
	     when 2  then case ((dbo.HexToTinyInt(substring(Msg,12, 1)) & 0x08) / 8)	-- P-TMSI + RAI + 8 Bit
		     when 1 then (dbo.HexToInt(substring(Msg,23,2))& 0x7C) /4 	--  3rd digit of MNC present
		     else 	 (dbo.HexToInt(substring(Msg,22,2))& 0x7C) /4  end  --  3rd digit of MNC not present
	     else   255 end)
	 	when 0 then 'originatingConversationalCall'
		when 1 then 'originatingStreamingCall'
		when 2 then 'originatingInteractiveCall'
		when 3 then 'originatingBackgroundCall'
		when 4 then 'originatingSubscribedTrafficCall'
		when 5 then 'terminatingConversationalCall'
		when 6 then 'terminatingStreamingCall'
		when 7 then 'terminatingInteractiveCall'
		when 8 then 'terminatingBackgroundCall'
		when 9 then 'emergencyCall'
		when 10 then 'interRAT-CellReselection'
		when 11 then 'interRAT-CellChangeOrder'
		when 12 then 'registration'
		when 13 then 'detach'
		when 14 then 'originatingHighPrioritySignalling'
		when 15 then 'originatingLowPrioritySignalling'
		when 16 then 'callRe-establishment'
		when 17 then 'terminatingHighPrioritySignalling'
		when 18 then 'terminatingLowPrioritySignalling'
		when 19 then 'terminatingCauseUnknown'
		when 20 then 'spare1'
		when 255 then 'RCCRequest not decoded'
		else 'not defined' end as EstablishmentCause
FROM	WCDMARRCMessages
WHERE	LogChanType = 0
and	(dbo.HexToTinyInt(substring(Msg, 1, 1)) & 0x08) = 0		-- no integrityCheckInfo
and	((dbo.HexToTinyInt(substring(Msg, 1, 1)) & 0x06) / 2) = 1	-- RRCConnectionRequest;


-- dbo.vRTPStatistics source

ALTER VIEW vRTPStatistics
AS
  Select i.MsgId,
         i.SessionId,
         i.TestId,
         i.MsgTime,
         i.PosId,
         i.NetworkId,
         i.RTPStatId,
         i.Type,
         i.NumRecords,
         case when t.Mode = 0 then 'DL' else 'UL' end as Direction,
         t.Mode,
         t.SSRC,
         case
           when t.Codec is not NULL then case
	                                   when t.Codec = 'H264' then 'Video'
                                           else 'Audio'
                                         end
           else case
                  when t.payload = 120 then 'Video'
                  else 'Audio'
                end
         end as PayloadType,
         t.Payload,
         t.Codec,
         t.CodecRate,
         t.AvgIPDV,
         t.AvgJitter,
         t.AvgPDV,
         case when t.NumPackets <> 0 then ((t.NumLostPackets*1.0)/((t.NumPackets + t.NumLostPackets)*1.0))*100.0 else NULL end PacketLoss,
         case when t.NumPackets <> 0 then ((t.NumOutOfOrderPackets*1.0) /(t.NumPackets*1.0))*100.0 else NULL end OutOfOrder
  from RTPStatisticsInfo i
       JOIN RTPStatistics t ON i.RTPStatId = t.RTPStatId;


-- dbo.vRelatedSessions source

ALTER VIEW vRelatedSessions
AS
  Select SessionId,
         sessionType,
         FileId,
         PosId,
         NetworkId,
         startTime,
         duration,
         info,
         numOfTests,
         valid,
         prevSessionId,
         nextSessionId,
         jtId,
         jtIdString,
         InvalidReason,
         SpeedAvg,
         SpeedCategory,
         Tech,
         StartPosId,
         StartNetworkId,
         SessionId as SessionIdA, -- the same SessionId as sessionIdA
         1 as FileType            -- FileType of b-side set to 1
  from Sessions

  UNION

  Select sb.SessionId,
         sb.sessionType,
         sb.FileId,
         sb.PosId,
         sb.NetworkId,
         sb.startTime,
         sb.duration,
         s.info,
         s.numOfTests,
         s.valid,
         sb.prevSessionId,
         sb.nextSessionId,
         s.jtId,
         s.jtIdString,
         s.InvalidReason,
         sb.SpeedAvg,
         sb.SpeedCategory,
         s.Tech,
         sb.StartPosId,
         sb.StartNetworkId,
         sb.sessionIdA,
         sb.FileType
  from SessionsB sb
       JOIN Sessions s ON s.SessionId = sb.SessionIdA
  where FileType = 1;


-- dbo.vResultsAppActionParams source

ALTER VIEW vResultsAppActionParams
AS
  Select p.SessionId,
         p.TestId,
         PosId,
         NetworkId,
         dbo.DelphiDateTime(MsgTime) as dTime,
         CONVERT(varchar, MsgTime, 14) as msgTime2,
         ActionId,
         'Upload' as ActionName,
         ap.ServiceProvider as ActionType,
         LocalFile as DataFile,
         2 as ServiceClass,
         'Cloud Storage Service' as ServiceClassName
  from ResultsAppActionUploadFileParams p
       JOIN vResultsAppParameters ap ON ap.TestId = p.TestId

  UNION ALL

  Select p.SessionId,
         p.TestId,
         PosId,
         NetworkId,
         dbo.DelphiDateTime(MsgTime) as dTime,
         CONVERT(varchar, MsgTime, 14) as msgTime2,
         ActionId,
         'Download' as ActionName,
         ap.ServiceProvider as ActionType,
         RemoteFilePath as DataFile,
         2 as ServiceClass,
         'Cloud Storage Service' as ServiceClassName
  from ResultsAppActionDownloadFileParams p
       JOIN vResultsAppParameters ap ON ap.TestId = p.TestId

  UNION ALL

  Select p.SessionId,
         p.TestId,
         PosId,
         NetworkId,
         dbo.DelphiDateTime(MsgTime) as dTime,
         CONVERT(varchar, MsgTime, 14) as msgTime2,
         ActionId,
         ActionName,
         case
           when ap.AppTestType is NULL then ap.ServiceProvider
           when ap.AppTestType = 45 then 'Ookla(R)'
           when ap.AppTestType = 47 then 'Facebook'
           when ap.AppTestType = 48 then 'Line Send'
           when ap.AppTestType = 49 then 'Line Receive'
           when ap.AppTestType = 50 then 'WhatsApp Send'
           when ap.AppTestType = 51 then 'WhatsApp Receive'
           when ap.AppTestType = 62 then 'FCC Speed'
           when ap.AppTestType = 67 then 'Instagram'
           when ap.AppTestType = 74 then 'Facebook'
           else ap.ServiceProvider
         end as ActionType,
         NULL as DataFile,
         ap.ServiceClass,
         ap.AppClass as ServiceClassName
  from ResultsAppActionParams p
       JOIN vResultsAppParameters ap ON ap.TestId = p.TestId;


-- dbo.vResultsAppParameters source

ALTER VIEW vResultsAppParameters
AS
  Select atp.SessionId,
         atp.TestId,
         case
           when atp.ServiceClass = 2 then 'Cloud Storage Service'
           when atp.ServiceClass = 3 then 'Messaging'
           when atp.ServiceClass = 4 then 'Social media'
           when atp.ServiceClass = 6 then 'Network Performance'
           else 'unknown'
         end COLLATE Latin1_General_CI_AS as AppClass,
         atp.ServiceClass,
         atp.ServiceProvider,
         atp.ServiceProfileName,
         ISNULL(at.NumActions, LEN(atp.ActionNames) - LEN(REPLACE(atp.ActionNames, ';', '')) + 1) as NumActions,
         CAST(at.Duration / 1000.0 as Decimal (9, 1)) as Duration,
         dbo.GetErrorMsg(at.ErrorCode, 0) as Error,
         atp.AppTestType
  from ResultsAppTestParameters atp
       JOIN ResultsAppTest at ON at.TestId = atp.TestId;


-- dbo.vResultsApplicationFCCTest source

ALTER VIEW  vResultsApplicationFCCTest 
AS
SELECT  

		app.*,
		case when ErrorCode = 0 then 'Successful' else 'Failed' end as Status,
		p.AppTestType,
		p.ActionNames,
		p.ServiceProvider

  FROM  TestInfo t  join ResultsAppActionPerformance app on (t.TestID = app.TestId)
					join ResultsAppTestParameters p on (t.TestId = p.TestId and p.ServiceProvider = 'FCC');


-- dbo.vResultsApplicationOoklaTest source

ALTER VIEW vResultsApplicationOoklaTest
AS
SELECT  

		app.*,
		case when ErrorCode = 0 then 'Successful' else 'Failed' end as Status,
		p.ServiceProvider

  FROM  TestInfo t  join ResultsAppActionPerformance app on (t.TestID = app.TestId)
					join ResultsAppTestParameters p on (t.TestId = p.TestId and p.ServiceProvider like 'Ookla%');


-- dbo.vResultsCapacityTestDLULGET source

ALTER VIEW vResultsCapacityTestDLULGET
As
	Select
		ResultsCapacityTest.*,
		ResultsCapacityTest.ThroughputGet as Throughput,
		Case When ResultsCapacityTest.ErrorCode = 0 Then 'Successful' Else 'Failed' End as 'Status',
		ResultsCapacityTestParameters.Direction,
		ResultsCapacityTestParameters.URIList,
		Case when CHARINDEX(';',ResultsCapacityTestParameters.URIList) > 0
			 then SUBSTRING(ResultsCapacityTestParameters.URIList,1,CHARINDEX(';',ResultsCapacityTestParameters.URIList)-1)
			 else ResultsCapacityTestParameters.URIList end as Host,
		ResultsCapacityTestParameters.URICount,
		Case when AccessPoints.APN is NULL then 'No APN available' else AccessPoints.APN end as 'APN'
	From
		ResultsCapacityTest Join ResultsCapacityTestParameters On(ResultsCapacityTest.TestId=ResultsCapacityTestParameters.TestId)
								Left Join AccessPoints On(ResultsCapacityTest.TestId=AccessPoints.TestId)
	Where
		ResultsCapacityTest.lastBlock=1 And
		ResultsCapacityTestParameters.Direction like 'GETANDPUT';


