		ResultsCapacityTest Join ResultsCapacityTestParameters On(ResultsCapacityTest.TestId=ResultsCapacityTestParameters.TestId)
								Left Join AccessPoints On(ResultsCapacityTest.TestId=AccessPoints.TestId)
	Where
		ResultsCapacityTest.lastBlock=0 And
		ResultsCapacityTestParameters.Direction like 'GET';


-- dbo.vResultsCapacityTestInstantPut source

ALTER VIEW vResultsCapacityTestInstantPut
As
	Select
		ResultsCapacityTest.*,
		ResultsCapacityTest.ThroughputPut as Throughput,
		Case When ResultsCapacityTest.ErrorCode = 0 Then 'Successful' Else 'Failed' End as 'Status',
		ResultsCapacityTestParameters.LocalFilename,
		ResultsCapacityTestParameters.Direction,
		ResultsCapacityTestParameters.URICount,
		ResultsCapacityTestParameters.URIList,
		case when CHARINDEX(';',ResultsCapacityTestParameters.URIList) > 0
