-- dbo.vResultsKPI source

ALTER VIEW vResultsKPI
AS
SELECT vResultsKPI1.*,
       Convert(varchar,vResultsKPI1.KPIId) + ' - ' + vResultsKPI1.KpiName as IdName,
       KPIName + ' / ' + KPIStatus as KpiNameStatus
FROM vResultsKPI1;


-- dbo.vResultsKPI1 source

ALTER VIEW vResultsKPI1
AS
Select *,
       dbo.GetKPIGroup(KPIId) + ' - ' +
       case ResultsKPI.Options
         when 0 then dbo.GetKPIName(KPIId)
         else ResultsKPI.Description
       end COLLATE Latin1_General_CI_AS as KPIName,

       case when ResultsKPI.ErrorCode = 0 then 'Successful'
       else 'Failed'
       end COLLATE Latin1_General_CI_AS as KPIStatus,

       case when ResultsKPI.ErrorCode = 0   then 'Normal'
            when ResultsKPI.ErrorCode = 108001 then 'Rejected'
            when ResultsKPI.ErrorCode = 108002 then 'Failed'
            when ResultsKPI.ErrorCode = 108003 then 'Timeout'
            when ResultsKPI.ErrorCode = 108004 then 'Start Trigger missing'
            when ResultsKPI.ErrorCode = 108005 then 'End Trigger missing'
            when ResultsKPI.ErrorCode = 108006 then 'Timing mismatch'
            when ResultsKPI.ErrorCode = 108010 then 'No Start Trigger'
            when ResultsKPI.ErrorCode = 108015 then 'End Trigger missing (Test unsuccessful)'
       -- all others
       else errorcodes.msg
       end COLLATE Latin1_General_CI_AS as KPICause

from 	ResultsKPI
        LEFT JOIN ErrorCodes ON ErrorCodes.Code = ResultsKPI.ErrorCode;


-- dbo.vResultsKPIForPlots source

ALTER VIEW vResultsKPIForPlots
AS
Select MsgId,
       SessionId,
       TestId,
       NetworkId,
       PosId,
       KPIId,
       StartTime,
       EndTime,
       Duration,
       ErrorCode,
       KPIName,
       KPIStatus,
       KPICause,
       Value1 as AverageValue,
       Value3 as StartTrigger,
       Value4 as EndTrigger,
       Value5 as AdditionalInfo,
       Counter as NumOfEndTrigger
from vResultsKPI1;


-- dbo.vResultsKPINameStatus source

ALTER VIEW vResultsKPINameStatus
AS
  Select ResultsKPI.SessionId,
         ResultsKPI.TestId,
         ResultsKPI.KPIId,
         case ResultsKPI.Options
           when 0 then dbo.GetKPIName(ResultsKPI.KPIId)
           else ResultsKPI.Description
         end COLLATE Latin1_General_CI_AS as KPIName,

         case when ResultsKPI.ErrorCode in (0, 108004) then 'Successful'
         else 'Failed'
         end COLLATE Latin1_General_CI_AS as KpiStatus,

         CONVERT(varchar, ResultsKPI.KPIId) + ' - ' +
         case ResultsKPI.Options
           when 0 then dbo.GetKPIName(ResultsKPI.KPIId)
           else ResultsKPI.Description
         end COLLATE Latin1_General_CI_AS as KPIIdName,

         case ResultsKPI.Options
           when 0 then dbo.GetKPIName(ResultsKPI.KPIId)
           else ResultsKPI.Description
         end COLLATE Latin1_General_CI_AS + ' / ' +
         case when ResultsKPI.ErrorCode in (0, 108004) then 'Successful'
         else 'Failed'
         end COLLATE Latin1_General_CI_AS as KpiNameStatus
from ResultsKPI;


-- dbo.vResultsLQAvg source

ALTER VIEW vResultsLQAvg
AS
Select ResultsLQ08Avg.TestId,
       ResultsLQ08Avg.SessionId,
       1                                                                         as LQ08,
       Appl % 10                                                                 as WideBand,
       CAST(case
              when (Appl / 10) % 10 = 0 then               -- SQuad 08
                case Appl % 10
                  when 0 then LQNB                         -- SQuad NB
                  when 2 then LQWB                         -- SQuad WB
                end
              when (Appl / 10) % 10 in (1, 2, 3) then      -- POLQA v1.1, v2.4, v3
                case Appl % 10
                  when 0 then OptionalNB                   -- POLQA NB
                  when 2 then OptionalWB                   -- POLQA WB
                end
            end as Decimal (5, 2))                                               as LQ,
       case
         when (Appl / 10) % 10 = 0 then                    -- SQuad 08
           case Appl % 10
             when 0 then LQNB                              -- SQuad NB
             when 2 then LQWB                              -- SQuad WB
           end
         when (Appl / 10) % 10 in (1, 2, 3) then           -- POLQA v1.1, v2.4, v3
           case Appl % 10
             when 0 then OptionalNB                        -- POLQA NB
             when 2 then OptionalWB                        -- POLQA WB
           end
       end                                                                       as LQFloat,
       CAST(FrontClipping as Decimal (5, 1))                                     as timeClipping,
       CAST(PosFreqShift as Decimal (5, 1))                                      as posFreqShift,
       CAST(NegFreqShift as Decimal (5, 1))                                      as negFreqShift,
       CAST(ReferDCOffset as Decimal (5, 1))                                     as refDCOffset,
       CAST(CodedDCOffset as Decimal (5, 1))                                     as codedDcOffset,
       CAST(DelaySpread as Decimal (5, 0))                                       as delaySpread,
       CAST(TotalGain as Decimal (5, 1))                                         as codedLevel,
       CAST(DelayDeviation as Decimal (5, 0))                                    as delayDeviation,
       CAST(ASLrcvP56 as Decimal (5, 1))                                         as aSLrcvP56,
       CAST(ActivityRcvP56 as Decimal (5, 0))                                    as activityRcvP56,
       CAST(NoiseRcv as Decimal (5, 1))                                          as noiseRcv,
       CAST(StaticSNR as Decimal (5, 1))                                         as staticSNR,
       CAST(P862LQ as Decimal (5,2))                                             as p862LQ,
       p862LQ                                                                    as p862LQFloat,
       CAST(P862 as Decimal (5,2))                                               as p862,
       CAST(case
              when (Appl / 10) % 10 in (1, 2, 3) then      -- POLQA v1.1, v2.4, v3
                case Appl % 10
                  when 0 then OptionalNB                   -- POLQA NB
                  when 2 then OptionalWB                   -- POLQA WB
                end
            end as Decimal (5, 2))                                               as P863,
       case
         when (Appl / 10) % 10 in (1, 2, 3) then           -- POLQA v1.1, v2.4, v3
           case Appl % 10
             when 0 then OptionalNB                        -- POLQA NB
             when 2 then OptionalWB                        -- POLQA WB
           end
       end                                                                       as P863Float,
       dbo.DecodeQualityCode(RTrim(QualityCode)) COLLATE Latin1_General_CI_AS    as qualityCode,
       Appl,
       RcvDelay * 1000                                                           as ReceiveDelay,
       CAST(AmplClipping as Decimal (5, 1))                                      as AmplClipping,
       dbo.GetQualityCategory(case
                                when (Appl / 10) % 10 = 0 then                -- SQuad 08
                                  case Appl % 10
                                    when 0 then LQNB       -- SQuad NB
                                    when 2 then LQWB       -- SQuad WB
                                  end
                                when (Appl / 10) % 10 in (1, 2, 3) then -- POLQA v1.1, v2.4, v3
                                  case Appl % 10
                                    when 0 then OptionalNB -- POLQA NB
                                    when 2 then OptionalWB -- POLQA WB
                                  end
                              end, 'Audio')                                      as LQCat,
       dbo.GetQualityCategory(p862LQ, 'Audio')                                   as p862Cat,
       CAST(MissedVoice as Decimal (5, 1))                                       as MissedVoice,
       LowerFilterLimit,
       UpperFilterLimit,
       ErrCode,
       case Bandwidth
         when 0 then 'narrowband'
         when 1 then 'wideband'
         when 2 then 'super-wideband'
         when 3 then 'fullband'
       else 'unknown'
       end                                                                       as Bandwidth,
       CAST(Optional1 as Decimal (5, 1))                                         as Resampling
FROM ResultsLQ08Avg;


-- dbo.vResultsLQAvgErrorCode source

ALTER VIEW vResultsLQAvgErrorCode
AS
SELECT ResultsLQ08Avg.TestId,
       ResultsLQ08Avg.SessionId,
       1                                                                         as LQ08,
       Appl % 10                                                                 as WideBand,
       CAST(case
              when (Appl / 10) % 10 = 0 then               -- SQuad 08
                case Appl % 10
                  when 0 then LQNB                         -- SQuad NB
                  when 2 then LQWB                         -- SQuad WB
                end
              when (Appl / 10) % 10 in (1, 2, 3) then      -- POLQA v1.1, v2.4, v3
                case Appl % 10
                  when 0 then OptionalNB                   -- POLQA NB
                  when 2 then OptionalWB                   -- POLQA WB
                end
            end as Decimal (5, 2))                                               as LQ,
       case
         when (Appl / 10) % 10 = 0 then                    -- SQuad 08
           case Appl % 10
             when 0 then LQNB                              -- SQuad NB
             when 2 then LQWB                              -- SQuad WB
           end
         when (Appl / 10) % 10 in (1, 2, 3) then           -- POLQA v1.1, v2.4, v3
           case Appl % 10
             when 0 then OptionalNB                        -- POLQA NB
             when 2 then OptionalWB                        -- POLQA WB
           end
       end                                                                       as LQFloat,
       CAST(P862LQ as Decimal (5, 2))                                            as p862LQ,
       p862LQ                                                                    as p862LQFloat,
       CAST(P862 as Decimal (5, 2))                                              as p862,
       CAST(case
              when (Appl / 10) % 10 in (1, 2, 3) then      -- POLQA v1.1, v2.4, v3
                case Appl % 10
                  when 0 then OptionalNB                   -- POLQA NB
                  when 2 then OptionalWB                   -- POLQA WB
                end
            end as Decimal (5, 2))                                               as P863,
       case
         when (Appl / 10) % 10 in (1, 2, 3) then           -- POLQA v1.1, v2.4, v3
           case Appl % 10
             when 0 then OptionalNB                        -- POLQA NB
             when 2 then OptionalWB                        -- POLQA WB
           end
       end                                                                       as P863Float,
       dbo.DecodeQualityCode(RTrim(QualityCode)) COLLATE Latin1_General_CI_AS    as qualityCode,
       ErrCode
FROM ResultsLQ08Avg
     JOIN TestInfo ON TestInfo.TestId = ResultsLQ08Avg.TestId;


-- dbo.vResultsLQAvgP8621SimpleCodec source

ALTER VIEW vResultsLQAvgP8621SimpleCodec
As
	Select vResultsLQAvgSimple.*,
		   Case when vvct.CodecName is Null then 'no codec rate'
				when vvct.CodecName = '-' then 'no codec rate'
				else vvct.CodecName
		   end as 'Codec Rate'
	From vResultsLQAvgSimple
		 JOIN TestInfo On TestInfo.TestId = vResultsLQAvgSimple.TestId
		 LEFT JOIN vVoiceCodecTest vvct On vResultsLQAvgSimple.TestId = vvct.TestId and
										   ((TestInfo.Direction = 'A->B' and vvct.Direction = 'U') or
											(TestInfo.Direction = 'B->A' and vvct.Direction = 'D'))
	Where
		vResultsLQAvgSimple.p862LQFloat is not NULL;


-- dbo.vResultsLQAvgP863NBSimpleCodec source

ALTER VIEW vResultsLQAvgP863NBSimpleCodec
AS
	Select
		ResultsLQ08Avg.SessionId,
		ResultsLQ08Avg.TestId,
		Appl,
		Case
				   When (Appl / 10) % 10 = 0 Then              -- SQuad 08
					 Case Appl % 10
					   When 0 Then 'SQuad08-NB'            -- SQuad NB
					   When 2 Then 'SQuad08-WB'            -- SQuad WB
					 End
				   When (Appl / 10) % 10 in (1, 2, 3) Then     -- POLQA v1.1, v2.4, v3
					 Case Appl % 10
					   When 0 Then 'P.863-NB'              -- POLQA NB
					   When 2 Then 'P.863-SWB'             -- POLQA WB
					 End
				 end as 'Model',
		Case
			when (SUBSTRING(Reverse(ResultsLq08Avg.QualityCode),10,1) like '1')then 'Silence'
			when Appl=10 or Appl=20   then 'P.863-NB'
			when Appl=110 or Appl=120 then 'P.863-NB/P.862.1'
			when Appl=1010            then 'QP P.863-NB'
			else '-'
			end as 'LQType',
		LQNB as 'LQNBfloat',
		CAST(LQNB as Decimal (5, 2)) as 'LQNB',
		LQWB as 'LQWBfloat',
		CAST(LQWB as Decimal (5, 2)) as 'LQWB',
		OptionalNB as 'LQNBP863float',
		CAST(OptionalNB as Decimal (5,2)) as 'LQNBP863',
		OptionalWB as 'LQWBP863float',
		CAST(OptionalWB as Decimal (5,2)) as 'LQWBP863',
		p862LQ as 'LQ8621float',
		CAST(P862LQ as Decimal (5, 2)) as 'LQ8621',
		p862 as 'LQ862float',
		CAST(p862 as Decimal (5, 2)) as 'LQ862',
		Case when vvct.CodecName is Null then 'no codec rate'
			when vvct.CodecName = '-' then 'no codec rate'
			else vvct.CodecName
		end as 'Codec Rate'
	From
		ResultsLQ08Avg Join TestInfo On (TestInfo.TestId = ResultsLQ08Avg.TestId)
					Left Join vVoiceCodecTest vvct On ResultsLQ08Avg.TestId = vvct.TestId and
											   ((TestInfo.Direction = 'A->B' and vvct.Direction = 'U') or
												(TestInfo.Direction = 'B->A' and vvct.Direction = 'D'))
	Where
		(Appl / 10) % 10 in (1, 2, 3) and
		Appl % 10 = 0;


-- dbo.vResultsLQAvgP863SWBSimpleCodec source

ALTER VIEW vResultsLQAvgP863SWBSimpleCodec
AS
	Select
		ResultsLQ08Avg.SessionId,
		ResultsLQ08Avg.TestId,
		Appl,
		Case
				   When (Appl / 10) % 10 = 0 Then              -- SQuad 08
					 Case Appl % 10
					   When 0 Then 'SQuad08-NB'            -- SQuad NB
					   When 2 Then 'SQuad08-WB'            -- SQuad WB
					 End
				   When (Appl / 10) % 10 in (1, 2, 3) Then     -- POLQA v1.1, v2.4, v3
					 Case Appl % 10
					   When 0 Then 'P.863-NB'              -- POLQA NB
					   When 2 Then 'P.863-SWB'             -- POLQA WB
					 End
				 end as 'Model',
		Case
			when (SUBSTRING(Reverse(ResultsLq08Avg.QualityCode),10,1) like '1') then 'Silence'
			when Appl=12 or Appl=22   then 'P.863-SWB'
			when Appl=1012            then 'QP P.863-SWB'
			else '-'
			end as 'LQType',
		LQNB as 'LQNBfloat',
		CAST(LQNB as Decimal (5, 2)) as 'LQNB',
		LQWB as 'LQWBfloat',
		CAST(LQWB as Decimal (5, 2)) as 'LQWB',
		OptionalNB as 'LQNBP863float',
		CAST(OptionalNB as Decimal (5,2)) as 'LQNBP863',
		OptionalWB as 'LQWBP863float',
		CAST(OptionalWB as Decimal (5,2)) as 'LQWBP863',
		p862LQ as 'LQ8621float',
		CAST(P862LQ as Decimal (5, 2)) as 'LQ8621',
		p862 as 'LQ862float',
		CAST(p862 as Decimal (5, 2)) as 'LQ862',
		Case when vvct.CodecName is Null then 'no codec rate'
			when vvct.CodecName = '-' then 'no codec rate'
			else vvct.CodecName
		end as 'Codec Rate'
	From
		ResultsLQ08Avg Join TestInfo On (TestInfo.TestId = ResultsLQ08Avg.TestId)
					Left Join vVoiceCodecTest vvct On ResultsLQ08Avg.TestId = vvct.TestId and
											   ((TestInfo.Direction = 'A->B' and vvct.Direction = 'U') or
												(TestInfo.Direction = 'B->A' and vvct.Direction = 'D'))
	Where
		(Appl / 10) % 10 in (1, 2, 3) and
		Appl % 10 = 2;


