-- dbo.vResultsLQAvgSimple source

ALTER VIEW vResultsLQAvgSimple
AS
Select ResultsLQ08Avg.TestId,
       ResultsLQ08Avg.SessionId,
       1                                                                         as LQ08,
       Appl % 10                                                                 as WideBand,
       CAST(case
              when (Appl / 10) % 10 = 0 then               -- SQuad 08
                case Appl % 10
                  when 0 then LQNB                         -- SQuad NB
                  when 2 then LQWB                         -- SQuad WB
                end
              when (Appl / 10) % 10 in (1, 2, 3) then      -- POLQA v1.1, v2.4, v3
                case Appl % 10
                  when 0 then OptionalNB                   -- POLQA NB
                  when 2 then OptionalWB                   -- POLQA WB
                end
            end as Decimal (5, 2))                                               as LQ,
       case
         when (Appl / 10) % 10 = 0 then                    -- SQuad 08
           case Appl % 10
             when 0 then LQNB                              -- SQuad NB
             when 2 then LQWB                              -- SQuad WB
           end
         when (Appl / 10) % 10 in (1, 2, 3) then           -- POLQA v1.1, v2.4, v3
           case Appl % 10
             when 0 then OptionalNB                        -- POLQA NB
             when 2 then OptionalWB                        -- POLQA WB
           end
       end                                                                       as LQFloat,
       CAST(P862LQ as Decimal (5, 2))                                            as p862LQ,
       p862LQ                                                                    as p862LQFloat,
       CAST(P862 as Decimal (5, 2))                                              as p862,
       CAST(case
              when (Appl / 10) % 10 in (1, 2, 3) then      -- POLQA v1.1, v2.4, v3
                case Appl % 10
                  when 0 then OptionalNB                   -- POLQA NB
                  when 2 then OptionalWB                   -- POLQA WB
                end
            end as Decimal (5, 2))                                               as P863,
       case
         when (Appl / 10) % 10 in (1, 2, 3) then           -- POLQA v1.1, v2.4, v3
           case Appl % 10
             when 0 then OptionalNB                        -- POLQA NB
             when 2 then OptionalWB                        -- POLQA WB
           end
       end                                                                       as P863Float
FROM ResultsLQ08Avg;


-- dbo.vResultsLQClipAvg source

ALTER VIEW vResultsLQClipAvg
AS
  Select ResultsLQ08ClipAvg.ClipId,
         ResultsLQ08ClipAvg.TestId,
         1                                                                         as LQ08,
         Appl % 10                                                                 as WideBand,
         CAST(case
                when (Appl / 10) % 10 = 0 then               -- SQuad 08
                  case Appl % 10
                    when 0 then LQNB                         -- SQuad NB
                    when 2 then LQWB                         -- SQuad WB
                  end
                when (Appl / 10) % 10 in (1, 2, 3) then      -- POLQA v1.1, v2.4, v3
                  case Appl % 10
                    when 0 then OptionalNB                   -- POLQA NB
                    when 2 then OptionalWB                   -- POLQA WB
                  end
              end as Decimal (5, 2))                                               as LQ,
         case
           when (Appl / 10) % 10 = 0 then                    -- SQuad 08
             case Appl % 10
               when 0 then LQNB                              -- SQuad NB
               when 2 then LQWB                              -- SQuad WB
             end
           when (Appl / 10) % 10 in (1, 2, 3) then           -- POLQA v1.1, v2.4, v3
             case Appl % 10
               when 0 then OptionalNB                        -- POLQA NB
               when 2 then OptionalWB                        -- POLQA WB
             end
         end                                                                       as LQFloat,
         CAST(FrontClipping as Decimal (5, 1))                                     as timeClipping,
         CAST(PosFreqShift as Decimal (5, 1))                                      as posFreqShift,
         CAST(NegFreqShift as Decimal (5, 1))                                      as negFreqShift,
         CAST(ReferDCOffset as Decimal (5, 1))                                     as refDCOffset,
         CAST(CodedDCOffset as Decimal (5, 1))                                     as codedDcOffset,
         CAST(DelaySpread as Decimal (5, 0))                                       as delaySpread,
         CAST(TotalGain as Decimal (5, 1))                                         as codedLevel,
         CAST(DelayDeviation as Decimal (5, 0))                                    as delayDeviation,
         CAST(ASLrcvP56 as Decimal (5, 1))                                         as aSLrcvP56,
         CAST(ActivityRcvP56 as Decimal (5, 0))                                    as activityRcvP56,
         CAST(NoiseRcv as Decimal (5, 1))                                          as noiseRcv,
         CAST(StaticSNR as Decimal (5, 1))                                         as staticSNR,
         CAST(P862LQ as Decimal (5,2))                                             as p862LQ,
         p862LQ                                                                    as p862LQFloat,
         CAST(P862 as Decimal (5,2))                                               as p862,
         CAST(case
                when (Appl / 10) % 10 in (1, 2, 3) then      -- POLQA v1.1, v2.4, v3
                  case Appl % 10
                    when 0 then OptionalNB                   -- POLQA NB
                    when 2 then OptionalWB                   -- POLQA WB
                  end
              end as Decimal (5, 2))                                               as P863,
         case
           when (Appl / 10) % 10 in (1, 2, 3) then           -- POLQA v1.1, v2.4, v3
             case Appl % 10
               when 0 then OptionalNB                        -- POLQA NB
               when 2 then OptionalWB                        -- POLQA WB
             end
         end                                                                       as P863Float,
         dbo.DecodeQualityCode(RTrim(QualityCode)) COLLATE Latin1_General_CI_AS    as qualityCode,
         Appl,
         RcvDelay * 1000                                                           as ReceiveDelay,
         CAST(AmplClipping as Decimal (5, 1))                                      as AmplClipping,
         dbo.GetQualityCategory(case
                                  when (Appl / 10) % 10 = 0 then           -- SQuad 08
                                    case Appl % 10
                                      when 0 then LQNB                     -- SQuad NB
                                      when 2 then LQWB                     -- SQuad WB
                                    end
                                  when (Appl / 10) % 10 in (1, 2, 3) then  -- POLQA v1.1, v2.4, v3
                                    case Appl % 10
                                      when 0 then OptionalNB               -- POLQA NB
                                      when 2 then OptionalWB               -- POLQA WB
                                    end
                                end, 'Audio')                                      as LQCat,
         dbo.GetQualityCategory(p862LQ, 'Audio')                                   as p862Cat,
         CAST(MissedVoice as Decimal (5, 1))                                       as MissedVoice,
         LowerFilterLimit,
         UpperFilterLimit,
         ErrCode,
         case Bandwidth
           when 0 then 'narrowband telephony'
           when 1 then 'wideband'
           when 2 then 'super wideband'
         else 'unknown'
         end                                                                       as Bandwidth,
         CAST(Optional1 as Decimal (5, 1))                                         as Resampling
  FROM ResultsLQ08ClipAvg
       JOIN TestInfo ON TestInfo.TestId = ResultsLQ08ClipAvg.TestId;


-- dbo.vResultsNetworkPerformanceTest source

ALTER VIEW vResultsNetworkPerformanceTest
As
	Select
	    ResultsNetworkPerformanceTest.SessionId,
		ResultsNetworkPerformanceTest.TestId,
		ResultsNetworkPerformanceTest.PosId,
		ResultsNetworkPerformanceTest.NetworkId,
		ResultsNetworkPerformanceTest.MsgTime,
		ResultsNetworkPerformanceTest.ErrorCode,
		Case When ResultsNetworkPerformanceTest.ErrorCode = 0 Then 'Successful' Else 'Failed' End as 'Status',
		Case when ResultsNetworkPerformanceTest.Direction = 0 then 'Put' Else 'Get' end as Dir,
		ResultsNetworkPerformanceTest.AvgThputCapacity*0.008 as AvgThputCapacity,
		ResultsNetworkPerformanceTest.AvgThputSustainableCapacity*0.008 as AvgThputSustainableCapacity,
		ResultsNetworkPerformanceTest.Thput30thPercentile*0.008 as Thput30thPercentile,
		ResultsNetworkPerformanceTest.AvgRoundTripTime,
		ResultsNetworkPerformanceTest.PercentageLimitedConnectivityUL,
		ResultsNetworkPerformanceTest.PercentageNoConnectivityUL,
		ResultsNetworkPerformanceTest.PercentageLimitedConnectivityDL,
		ResultsNetworkPerformanceTest.PercentageNoConnectivityDL,
		ResultsNetworkPerformanceParameters.CapacityBufferSize,
		ResultsNetworkPerformanceParameters.CapacityPeakDuration,
		ResultsNetworkPerformanceParameters.CapacityPeakInterval,
		ResultsNetworkPerformanceParameters.CapacityPeakStartOffset,
		ResultsNetworkPerformanceParameters.LimitedConnectivityThreshold,
		ResultsNetworkPerformanceParameters.TCPFloorLevel,
		AccessPoints.APType,
		AccessPoints.Name,
		Case when AccessPoints.APN is NULL then 'No APN available' else AccessPoints.APN end as 'APN'
	From
		ResultsNetworkPerformanceTest Join ResultsNetworkPerformanceParameters On(ResultsNetworkPerformanceTest.TestId=ResultsNetworkPerformanceParameters.TestId)
								Left Join AccessPoints On(ResultsNetworkPerformanceTest.TestId=AccessPoints.TestId);


-- dbo.vResultsPingTest source

ALTER VIEW vResultsPingTest
