-- dbo.vResultsVMon08Avg source

ALTER VIEW vResultsVMon08Avg
As
	Select
		ResultsVQ08ClipAvg.MsgId,
		Testinfo.SessionId,
		ResultsVQ08ClipAvg.TestId,
		ResultsVQ08ClipAvg.ClipId,
		Testinfo.sampleId as 'SampleId',
		ResultsVQ08ClipAvg.Model,
		ResultsVQ08ClipAvg.VisualQuality,
		ResultsVQ08ClipAvg.ProblemCode,
		ResultsVQ08ClipAvg.SignalDist,
		ResultsVQ08ClipAvg.FrameRateCalc,
		ResultsVQ08ClipAvg.Black,
		ResultsVQ08ClipAvg.Freezing,
		ResultsVQ08ClipAvg.Jerkiness,
		ResultsVQ08ClipAvg.MatchedFrames,
		ResultsVQ08ClipAvg.FrameJitter,
		ResultsVQ08ClipAvg.Blurring,
		ResultsVQ08ClipAvg.Blockiness,
		ResultsVQ08ClipAvg.Tiling,
		ResultsVQ08ClipAvg.PSNR,
		ResultsVQ08ClipAvg.LumOffset,
		Case when ResultsVQ08ClipAvg.Model='FR' Then 'FR'
			when ResultsVQ08ClipAvg.Model='NR' Then 'NR'
			else Null end as 'VQModel',
		Case when VideoSettingsinfo.AlgoVersion=0 Then 'VMon05'
			when VideoSettingsinfo.AlgoVersion=1 Then 'VMon06'
			when VideoSettingsinfo.AlgoVersion=2 Then 'VMon08'
			else NULL end as 'Series',
		Case when VideoSettingsinfo.AlgoVersion=0 Then ResultsVQ08ClipAvg.VisualQuality else NULL end as 'VMon05',
		Case when VideoSettingsinfo.AlgoVersion=1 Then ResultsVQ08ClipAvg.VisualQuality else NULL end as 'VMon06',
		Case when VideoSettingsinfo.AlgoVersion=2 Then ResultsVQ08ClipAvg.VisualQuality else NULL end as 'VMon08'
	From
		ResultsVQ08ClipAvg Join Testinfo On(ResultsVQ08ClipAvg.TestId=Testinfo.TestId)
							Join VideoSettingsinfo On(VideoSettingsinfo.SampleId=Testinfo.SampleId)
	Where
		ResultsVQ08ClipAvg.Model='NR' and
		VideoSettingsinfo.AlgoVersion=2;


