-- dbo.vResultsVQTest source

ALTER VIEW vResultsVQTest
AS
  Select NULL as MsgId,
         ResultsVideoStream.SessionId,
         ResultsVideoStream.TestId,
         StartTime as startRec,
         MsgTime as endRec,
         NULL as Offset,
         NULL as LipSync,
         NULL as VideoRecDelay,
         StartTime as StreamStartTime,
         DATEDIFF(ms, case when DATEDIFF(d, StartTime, MsgTime) > 1 then NULL else StartTime end, MsgTime) as StreamDuration,
         MsgTime as StreamEndTime,
         NULL as StreamId,
         Player,
         Setup,
         Protocol,
         URL,
         NULL as ErrorCode,
         HorResolution,
         VerResolution,
         NULL as CapturingDevice,
         State as Status,
         ResultsVideoStream.TimeToFirstPicture as FirstDelay,
         AudioCodec,
         VideoCodec,
         case 
           when CHARINDEX('YouTube App', Player) > 0 then 'native'
           when CHARINDEX('App Netflix', Player) > 0 then 'native'
           when CHARINDEX('DirecTv', Player) > 0 then 'native'
           when CHARINDEX('App Facebook', Player) > 0 then 'native'
           when ImageSize is NULL then CONVERT(varchar, HorResolution) + ' x ' + CONVERT(varchar, VerResolution)
           else ImageSize
         end as ImageSize,
         Technology,
         case
           when r.ResCount > 1 then 'multiple'
           when t.Container = 'proprietary' then 'adaptive'
           else
             case
               when ResultsVideoStream.ImageSize is NULL then ResultsVideoStream.VideoResolution
               else ResultsVideoStream.ImageSize
             end
         end as VideoResolution
  from ResultsVideoStream
       LEFT JOIN ResultsVideoStreamTCPData t ON t.TestId = ResultsVideoStream.TestId
       LEFT JOIN vResultsVQTimeDomResolutions r ON r.TestId = ResultsVideoStream.TestId;


-- dbo.vResultsVQTimeDomResolutions source

ALTER VIEW vResultsVQTimeDomResolutions
AS
  Select COUNT(DISTINCT VerResolution) as ResCount, TestId
  from ResultsVq06TimeDom
  group by TestId;


-- dbo.vResultsVideoClip source

ALTER View vResultsVideoClip
AS
	Select
		ClipInfo.SessionId,
		ClipInfo.TestId,
		ClipInfo.ClipId,
		ClipInfo.MsgTime,
		ClipInfo.PosId,
		ClipInfo.NetworkId,
		ClipInfo.StartTime as 'ClipStartTime',
		ClipInfo.LipSync,
		ClipInfo.VideoRecDelay,
		vstream.StartTime as 'StreamStartTime',
		vstream.Player,
		vstream.setup,
		vstream.Protocol,
		vstream.URL,
		cvi.HorResolution,
		cvi.VerResolution,
		vstream.State,
		vstream.AudioCodec,
		vstream.VideoCodec,
		vstream.ImageSize,
		vstream.Technology
	From
	   ClipInfo JOIN ClipVideoInfo cvi ON cvi.ClipId = ClipInfo.ClipId
	   JOIN ResultsVideoStream vstream On(ClipInfo.TestId=vstream.TestId);


-- dbo.vResultsVideoStreamAvg source

ALTER View vResultsVideoStreamAvg
AS
	Select
		stream.SessionId,
		stream.TestId,
		stream.SessionQuality,
		stream.TestQualityAvg,
		stream.TestQualityMax,
		stream.TestQualityMin,
		stream.Freezing,
		stream.FreezingPercent,
		stream.Status,
		max(clip.ClipId) as 'FirstClipofTest',
		clip.Model
	From
		ResultsVideoStreamAvg stream Left Join ResultsVQ08ClipAvg clip On(stream.TestId=clip.TestId)
	Group by
		stream.SessionId,
		stream.TestId,
		stream.SessionQuality,
		stream.TestQualityAvg,
		stream.TestQualityMax,
		stream.TestQualityMin,
		stream.Freezing,
		stream.FreezingPercent,
		stream.Status,
		clip.Model;


-- dbo.vResultsVideoStreamFreezingsAvg source

ALTER VIEW vResultsVideoStreamFreezingsAvg
AS
select
		t.SessionID,
		t.TestID,
		t.startTime,
		t.typeoftest,
		t.NetworkId,
		t.PosId,
		f.MinFreezeDuration,
		case when t.qualityIndication like '%Completed%' then 'Completed' else
		     case when t.qualityIndication like '%Failed%' then 'Failed' else 'Dropped' end end as StreamReproduction,
		count(f.MsgID)  as NumFreezings,
		avg(f.Duration)  as AvgFreezingTime,
		max(f.Duration)  as MaxFreezingTime,
		sum(f.Duration)  as AccFreezingTime
from
		TestInfo t left join ResultsVqFreezings f on (t.TestID = f.testID and f.Duration >= f.MinFreezeDuration and f.Duration < 36000000 )
where
		dbo.IsStreamingAppTest(t.typeofTest) = 1

group by
		t.SessionID,
		t.TestID,
		t.startTime,
		t.typeoftest,
		t.NetworkId,
		t.PosId,
		f.MinFreezeDuration,
		t.qualityIndication;


-- dbo.vResultsYouTubeVideo source

ALTER VIEW vResultsYouTubeVideo
AS
select 
		s.sessionID,
		t.testID,
		t.startTime as MsgTime,
		t.NetworkId,
		t.PosId,
		t.typeoftest,
		t.qualityIndication,
		st.SuccessState,
		case when st.SuccessState = 1 then 'Successful' else 'Failed' end as Status,
		vs.Model,
		st.Player,
		st.URL,
		d.TimeToReadytoPlay, 
		d.TimeToFirstPicturePlayer as TimeToFirstPicture,
		'Player' as TimeToFirstPictureTrigger,
		d.TimeToStartBufferingPlayer as TimeToStartBuffering,
		'Player' as TimeToStartBufferingTrigger,
		d.PreBufferingTimePlayer as PreBufferingTime,
		'Player' as PreBufferingTimeTrigger,
		d.TimeToFirstPicturePlayer / 1000.0 + st.VideoDuration as VideoSessionTime,
		st.VideoDuration,
		vs.Freezing,
		vs.FreezingPercent,
		vs.TestQualityAvg,
		vs.TestQualityMax,
		vs.TestQualityMin,
		case when st.SuccessState = 1 and vs.Freezing = 0 then 'Successful' else 'Failed' end as ImpairmentFree,
		d.BytesTotal,
		d.BytesReceived
from 
		Sessions s join TestInfo t on (s.SessionId = t.SessionId and dbo.IsStreamingAppTest(t.typeoftest) = 1)
				   left join ResultsVideoStreamTCPData d on (d.TestId = t.TestId) 
				   left join ResultsVideoStream st on (st.TestId = t.TestId) 
				   left join vResultsVideoStreamAvg vs on (vs.TestId = t.TestId);


-- dbo.vRunTestOn source

ALTER VIEW vRunTestOn
AS
  Select fl.FileId, s.SessionId, t.TestId,
         case
           when t.Direction = 'A->B' then
             case fib.Id when 1 then 'Phone' else 'PC' end
           else
             case fia.Id when 1 then 'Phone' else 'PC' end
         end as RunTestOn
  from Sessions s
       JOIN FileList fl ON fl.FileId = s.FileId
       LEFT JOIN TestInfo t ON t.SessionId = s.SessionId
       LEFT JOIN FileInfo fia ON fia.FileId = fl.FileId and fia.InfoName = 'RunTestOnPhone'
       LEFT JOIN FileInfo fib ON fib.FileId = fl.BFileId and fib.InfoName = 'RunTestOnPhone';


-- dbo.vSMSE2E source

ALTER VIEW vSMSE2E AS

SELECT
	max(CASE when event = 'SEND SMS START' AND sendReceive = 'S' then ResultsSMSTrace.SessionID else NULL end) AS SessionID,
	max(CASE when event = 'SEND SMS START' AND sendReceive = 'S' then ResultsSMSTrace.TestID else NULL end) AS TestID,
	max(CASE when event = 'SEND SMS START' AND sendReceive = 'S' then ResultsSMSTrace.NetworkID else NULL end) AS NetworkID,
	max(CASE when event = 'SEND SMS START' AND sendReceive = 'S' then ResultsSMSTrace.PosID else NULL end) AS PosID,

	max(CASE when event = 'SEND SMS START' AND sendReceive = 'S' then ResultsSMSTrace.msgTime else NULL end) AS StartTime,
	max(CASE when event = 'SMS RECEIVED'   AND sendReceive = 'R' then ResultsSMSTrace.msgTime else NULL end )AS EndTime,
	STR(CONVERT(float,DATEDIFF(ms,max(CASE when event = 'SEND SMS START' AND sendReceive = 'S' AND ErrorCode = 0 then ResultsSMSTrace.msgTime else NULL end),
	    min(CASE when event = 'SMS RECEIVED' AND sendReceive = 'R' AND ErrorCode = 0 then ResultsSMSTrace.msgTime else NULL end))),10,0) AS Duration,
	case when max(CASE when event = 'START' AND sendReceive = 'S' AND ErrorCode = 0 then 1 else 0 end)+
	    max(CASE when event = 'SMS RECEIVED' AND sendReceive = 'R' AND ErrorCode = 0 then 1 else 0 end) > 1 then 'Successful' else 'Failed' end AS Status,
	SUM(case when event = 'START' AND sendReceive = 'S' then 1 else 0 end) AS Counter
FROM
	TestInfo,
	ResultsSMSTrace,
	ResultsSMSParameters,
	ResultsSMSRslt
WHERE
	TestInfo.valid = 1 and
	TestInfo.TestID = ResultsSMSTrace.TestId and
	ResultsSMSTrace.TestId = ResultsSMSParameters.TestId  AND
	ResultsSMSTrace.TestId = ResultsSMSRslt.TestId
GROUP BY
	ResultsSMSParameters.identifier;


-- dbo.vSQDefinitionsRFBand source

ALTER VIEW vSQDefinitionsRFBand
AS
  Select Id as RFBand,
         Str_1 as Tech,
         CASE WHEN Id = 149 THEN 'LTE E-UTRA Unknown'
              WHEN Id = 5999 THEN '5G NR Unknown'
              ELSE RTRIM(Str_1 + ISNULL(Str_2, '') + case when Id < 1000 then ' ' else '' end + ISNULL(CONVERT(varchar, Int_1), '')) END as Name,
         Int_1 as BandId,
         Int_2 as Mode
  from SQDefinitions
  where DefinitionId = 1   -- RFBand Definitions;


