-- dbo.vSQSAETLProcessorLogAnalysis source

ALTER VIEW [dbo].[vSQSAETLProcessorLogAnalysis]
AS
SELECT ServerName, DatabaseName, SnowflakeVersion, Run, ProcessingOption, ProcessingResult, Id, LogTime, LogMessage, Date, 'DwGroup' AS ScriptType,ScriptGroup, ScriptGroup AS Script,Duration FROM vSQSAETLProcessorLogDwGroups UNION
SELECT ServerName, DatabaseName, SnowflakeVersion, Run, ProcessingOption, ProcessingResult, Id, LogTime, LogMessage, Date, 'DwScript' AS ScriptType,ScriptGroup, Script,Duration FROM vSQSAETLProcessorLogDwScripts UNION
SELECT ServerName, DatabaseName, SnowflakeVersion, Run, ProcessingOption, ProcessingResult, Id, LogTime, LogMessage, Date, 'Cube' AS ScriptType,ScriptGroup, Script,Duration FROM vSQSAETLProcessorLogCube;


-- dbo.vSQSAETLProcessorLogCube source

ALTER VIEW [dbo].[vSQSAETLProcessorLogCube]
AS
SELECT CONVERT(NVARCHAR(255), SERVERPROPERTY('ServerName')) AS ServerName,
  DB_NAME() AS DatabaseName,
  runs.SnowflakeVersion,
  runs.Run,
  runs.ProcessingOption,
  runs.ProcessingResult,
  Id,
  SUBSTRING(CONVERT(VARCHAR(50), LogTime), 0, LEN(CONVERT(VARCHAR(50), LogTime)) - 3) AS LogTime,
  LogMessage,
  CONVERT(VARCHAR(25), LogTime, 23) AS [Date],
  'Cube' AS ScriptGroup,
  SUBSTRING(LogMessage, 0, CHARINDEX('successfully processed Elapsed:', LogMessage) + 22) AS Script,
  ROUND(dbo.FdwTimeSpanToDuration(SUBSTRING(LogMessage, CHARINDEX('Elapsed: ', LogMessage) + LEN('Elapsed: '), LEN(LogMessage)), 'MI'), 2) AS Duration
FROM SQSAETLProcessorLog logs
LEFT JOIN vSQSAETLProcessorLogRuns runs ON logs.Id BETWEEN runs.StartId
    AND runs.EndId
WHERE LogMessage LIKE '%Cube % successfully processed Elapsed:%' AND LogTime >= DATEADD(DAY, -60, GETDATE());


-- dbo.vSQSAETLProcessorLogDwGroups source

ALTER VIEW [dbo].[vSQSAETLProcessorLogDwGroups]
AS
SELECT
  runs.ServerName,
  runs.DatabaseName,
  runs.SnowflakeVersion,
  runs.Run,
  runs.ProcessingOption,
  runs.ProcessingResult,
  Id,
  LogTime,
  LogMessage,
  CONVERT(VARCHAR(25), LogTime, 23) AS [Date],
  SUBSTRING(LogMessage, 0, CHARINDEX('.sql Elapsed (S):', LogMessage) - 1) AS ScriptGroup,
  ROUND(dbo.FdwTimeSpanToDuration(SUBSTRING(LogMessage, CHARINDEX('.sql Elapsed (S): ', LogMessage) + LEN('.sql Elapsed (S): '), LEN(LogMessage)), 'MI'), 2) AS Duration
FROM SQSAETLProcessorLog logs 
LEFT JOIN vSQSAETLProcessorLogRuns runs ON logs.Id BETWEEN runs.StartId AND runs.EndId
WHERE LogMessage LIKE '%.sql Elapsed (S):%' AND LogTime >= DATEADD(DAY, -60, GETDATE());


-- dbo.vSQSAETLProcessorLogDwScripts source

ALTER VIEW [dbo].[vSQSAETLProcessorLogDwScripts]
AS
SELECT CONVERT(NVARCHAR(255), SERVERPROPERTY('ServerName')) AS ServerName,
  DB_NAME() AS DatabaseName,
  runs.SnowflakeVersion,
  runs.Run,
  runs.ProcessingOption,
  runs.ProcessingResult,
  Id,
  LogTime,
  LogMessage,
  CONVERT(VARCHAR(25), LogTime, 23) AS [Date],
  SUBSTRING(LogMessage, 17, 4) AS ScriptGroup,
  SUBSTRING(LogMessage, 17, CHARINDEX('.sql:', LogMessage) - 17) AS Script,
  ROUND(dbo.FdwTimeSpanToDuration(SUBSTRING(LogMessage, CHARINDEX('.sql: ', LogMessage) + LEN('.sql: '), LEN(LogMessage)), 'MI'), 2) AS Duration
FROM SQSAETLProcessorLog logs
LEFT JOIN vSQSAETLProcessorLogRuns runs ON logs.Id BETWEEN runs.StartId
    AND runs.EndId
WHERE LogMessage LIKE '%Elapsed script:%' AND LogTime >= DATEADD(DAY, -60, GETDATE());


-- dbo.vSQSAETLProcessorLogRuns source

ALTER VIEW [dbo].[vSQSAETLProcessorLogRuns]
AS
SELECT DISTINCT ServerName, DatabaseName
,MAX(ValueStoreBuildVersion) OVER (PARTITION BY Run) AS ValueStoreBuildVersion
,MAX(SnowflakeVersion) OVER (PARTITION BY Run) AS SnowflakeVersion
,Run,StartId,EndId,StartLogTime, EndLogTime, Duration
--,MAX(OptionInitialize)  OVER (PARTITION BY Run) AS OptionInitialize
--,MAX(OptionProcessData) OVER (PARTITION BY Run) AS OptionProcessData
--,MAX(OptionProcessCube) OVER (PARTITION BY Run) AS OptionProcessCube
,CASE 
  WHEN MAX(OptionProcessPartial) OVER (PARTITION BY Run) IS NOT NULL THEN 'Partial/Incremental Processing'
  WHEN MAX(OptionIncrementalUpgrade) OVER (PARTITION BY Run) IS NOT NULL THEN 'Incremental Upgrade'
  WHEN MAX(OptionInitialize) OVER (PARTITION BY Run) IS NOT NULL AND MAX(OptionProcessData) OVER (PARTITION BY Run) IS NOT NULL AND MAX(OptionProcessCube) OVER (PARTITION BY Run) IS NOT NULL THEN 'Full Processing'
  WHEN MAX(OptionInitialize) OVER (PARTITION BY Run) IS NULL AND MAX(OptionProcessData)     OVER (PARTITION BY Run) IS NOT NULL AND MAX(OptionProcessCube) OVER (PARTITION BY Run) IS NOT NULL THEN 'Incremental Processing'
  WHEN MAX(OptionInitialize) OVER (PARTITION BY Run) IS NOT NULL AND MAX(OptionProcessData) OVER (PARTITION BY Run) IS NOT NULL AND MAX(OptionProcessCube) OVER (PARTITION BY Run) IS NULL THEN 'Initialize/ProcessSnowflake'
  WHEN MAX(OptionInitialize) OVER (PARTITION BY Run) IS NOT NULL AND MAX(OptionProcessData) OVER (PARTITION BY Run) IS NULL AND MAX(OptionProcessCube)     OVER (PARTITION BY Run) IS NULL THEN 'Initialize'
  WHEN MAX(OptionInitialize) OVER (PARTITION BY Run) IS NULL AND MAX(OptionProcessData)     OVER (PARTITION BY Run) IS NOT NULL AND MAX(OptionProcessCube) OVER (PARTITION BY Run) IS NULL THEN 'ProcessSnowflake'
  WHEN MAX(OptionInitialize) OVER (PARTITION BY Run) IS NULL AND MAX(OptionProcessData)     OVER (PARTITION BY Run) IS NULL AND MAX(OptionProcessCube)     OVER (PARTITION BY Run) IS NOT NULL THEN 'ProcessCube'
  ELSE 'Unknown'
END AS ProcessingOption
,ISNULL(MAX(ProcessingResult) OVER (PARTITION BY Run), 'Unknown') AS ProcessingResult
,MAX(Files) OVER (PARTITION BY Run) AS Files
,MAX(FilesToAdd) OVER (PARTITION BY Run) AS FilesToAdd
,MAX(FilesToDelete) OVER (PARTITION BY Run) AS FilesToDelete
 FROM (
SELECT Runs.*, logInfo.LogMessage,
CASE WHEN logInfo.LogMessage LIKE ('%> ETLProcessor build version: %') THEN SUBSTRING(logInfo.LogMessage, CHARINDEX('> ETLProcessor build version: ', logInfo.LogMessage) + LEN('> ETLProcessor build version: ') + 1, LEN(logInfo.LogMessage)) END AS ValueStoreBuildVersion
,CASE WHEN logInfo.LogMessage LIKE ('%> SqsaDatabaseVersion: %') THEN SUBSTRING(logInfo.LogMessage, CHARINDEX('> SqsaDatabaseVersion: ', logInfo.LogMessage) + LEN('> SqsaDatabaseVersion: ') + 1, LEN(logInfo.LogMessage)) END AS SnowflakeVersion
,CASE WHEN logInfo.LogMessage LIKE ('%Elapsed script: Dw9900SetSQSADatabaseStatusSuccess.sql:%') THEN 'Successfull'
WHEN logInfo.LogMessage LIKE ('%Elapsed script: Dw9901SetSQSADatabaseStatusFail.sql:%') THEN 'Failed' END AS ProcessingResult
,CASE WHEN logInfo.LogMessage LIKE ('%> Initialize Snowflake structure') THEN 'yes' END AS OptionInitialize
,CASE WHEN logInfo.LogMessage LIKE ('%> Process Snowflake data') THEN 'yes' END AS OptionProcessData
,CASE WHEN logInfo.LogMessage LIKE ('%%  > % cube') THEN 'yes' END AS OptionProcessCube
,CASE WHEN logInfo.LogMessage LIKE ('%  > Partial/Incremental processing') THEN 'yes' END AS OptionProcessPartial
,CASE WHEN logInfo.LogMessage LIKE ('%> Starting incremental database upgrade%') THEN 'yes' END AS OptionIncrementalUpgrade
,CASE WHEN logInfo.LogMessage LIKE ('%  > FileInfo: %') THEN CONVERT(INT, SUBSTRING(LEFT(logInfo.LogMessage, CHARINDEX(', files to add:', logInfo.LogMessage)-1), CHARINDEX('  > FileInfo: files: ', logInfo.LogMessage) + LEN('  > FileInfo: files: ') + 1, LEN(logInfo.LogMessage))) END AS Files
,CASE WHEN logInfo.LogMessage LIKE ('%  > FileInfo: %') THEN CONVERT(INT, SUBSTRING(LEFT(logInfo.LogMessage, CHARINDEX(', files to delete:', logInfo.LogMessage)-1), CHARINDEX('files to add: ', logInfo.LogMessage) + LEN('files to add: ') + 1, LEN(logInfo.LogMessage))) END AS FilesToAdd
,CASE WHEN logInfo.LogMessage LIKE ('%  > FileInfo: %') THEN CONVERT(INT, SUBSTRING(logInfo.LogMessage, CHARINDEX('files to delete: ', logInfo.LogMessage) + LEN('files to delete: ') + 1, LEN(logInfo.LogMessage))) END AS FilesToDelete
FROM (
SELECT 
CONVERT(NVARCHAR(255), SERVERPROPERTY('ServerName')) AS ServerName,
DB_NAME() AS DatabaseName,
ROW_NUMBER() OVER(ORDER BY StartId ASC) AS Run, StartId, EndId, StartLogTime, EndLogTime, ROUND(CONVERT(REAL,DATEDIFF(SS,StartLogTime, EndLogTime))/60,2) AS Duration
FROM (
SELECT DISTINCT 
StartId, EndId, StartLogTime, EndLogTime FROM (
SELECT Id,
CASE WHEN LogMessage LIKE 'Overall elapsed:%' THEN LAG (Id) OVER (ORDER BY Id ASC) ELSE Id END AS StartId,
CASE WHEN LogMessage LIKE '> Rohde & Schwarz SwissQual AG ETLProcessor Copyright%' THEN LEAD (Id) OVER (ORDER BY Id ASC) ELSE Id END AS EndId,
CASE WHEN LogMessage LIKE 'Overall elapsed:%' THEN LAG (LogTime) OVER (ORDER BY Id ASC) ELSE LogTime END AS StartLogTime,
CASE WHEN LogMessage LIKE '> Rohde & Schwarz SwissQual AG ETLProcessor Copyright%' THEN LEAD (LogTime) OVER (ORDER BY Id ASC) ELSE LogTime END AS EndLogTime
, LogTime, LogMessage FROM SQSAETLProcessorLog
WHERE (LogMessage LIKE '> Rohde & Schwarz SwissQual AG ETLProcessor Copyright%' OR LogMessage LIKE 'Overall elapsed:%') AND LogTime >= DATEADD(DAY, -60, GETDATE())
) AS base
) AS baseDuration
) AS Runs
LEFT JOIN SQSAETLProcessorLog logInfo ON logInfo.Id BETWEEN Runs.StartId AND Runs.EndId AND
(logInfo.LogMessage LIKE ('%> Initialize Snowflake structure') 
OR logInfo.LogMessage LIKE ('%> Process Snowflake data')
OR logInfo.LogMessage LIKE ('%  > % cube')
OR logInfo.LogMessage LIKE ('%  > Partial/Incremental processing')
OR logInfo.LogMessage LIKE ('%Elapsed script: Dw9900SetSQSADatabaseStatusSuccess.sql:%')
OR logInfo.LogMessage LIKE ('%Elapsed script: Dw9901SetSQSADatabaseStatusFail.sql:%')
OR logInfo.LogMessage LIKE ('%> ETLProcessor build version: %')
OR logInfo.LogMessage LIKE ('%> SqsaDatabaseVersion: %')
OR logInfo.LogMessage LIKE ('%  > FileInfo: %')
OR logInfo.LogMessage LIKE ('%> Starting incremental database upgrade%')
)
) AS RunsInfo;


-- dbo.vSQSAFactTablesFilledBy source

ALTER VIEW [dbo].[vSQSAFactTablesFilledBy]
AS
SELECT DISTINCT FactTabelName,
  CASE 
    WHEN FactTabelName IN (
        'FactNetworkScore',
        'FactProblemSpot',
        'FactEvent',
        'FactDataApplications',
        'FactCoverageClassification',
        'FactFile',
        'FactAdvancedTriggerEvent'
        )
      THEN 'ETL'
    WHEN FactTabelName IN (
        'FactAnomaly',
        'FactAnomalyFeatureDeviation',
        'FactCSS',
        'FactNUR',
		'FactNURv2'
        )
      THEN 'Machine Learning'
    WHEN NqdiTable IS NOT NULL
      THEN 'NQDI'
    WHEN EtlTable IS NOT NULL
      THEN 'ETL'
    WHEN FactTabelName IN (
        'FactAnomaly',
        'FactAnomalyFeatureDeviation',
        'FactCSS',
        'FactNUR',
		'FactNURv2'
        )
      THEN 'Machine Learning'
    END AS FilledBy
FROM (
  SELECT TABLE_NAME AS FactTabelName,
    nqdi.FactTableName AS NqdiTable,
    etl.FactTableName AS EtlTable
  FROM INFORMATION_SCHEMA.TABLES t
  LEFT JOIN (
    SELECT FactTableName
    FROM FdwFactTableSourceInformation()
    WHERE NqdiSourceTableName LIKE 'Fact%'
    ) AS nqdi ON t.TABLE_NAME = nqdi.FactTableName
  LEFT JOIN (
    SELECT FactTableName
    FROM FdwFactTableSourceInformation()
    WHERE NqdiSourceTableName NOT LIKE 'Fact%'
    ) AS etl ON t.TABLE_NAME = etl.FactTableName
  WHERE TABLE_TYPE = 'BASE TABLE'
    AND TABLE_NAME LIKE 'Fact%'
  ) AS a;


-- dbo.vSQSATempDbSpace source

ALTER VIEW [dbo].[vSQSATempDbSpace]
AS
SELECT mf.file_id,
  mf.name AS FileName,
  mf.type_desc AS FileType,
  ISNULL(file_space.total_page_count * 1.0 / 128, mf.size * 8 / 1024) AS TotalSizeMB,
  CASE 
    WHEN mf.type_desc = 'ROWS'
      THEN file_space.unallocated_extent_page_count * 1.0 / 128
    ELSE ISNULL(file_space.total_page_count * 1.0 / 128, mf.size * 8 / 1024) - (log_space.used_log_space_in_bytes * 1.0 / 1024 / 1024)
    END AS FreeSpaceMB,
  CASE 
    WHEN mf.type_desc = 'ROWS'
      THEN CONVERT(NUMERIC(10, 2), (file_space.unallocated_extent_page_count * 1.0 / 128) / (ISNULL(file_space.total_page_count * 1.0 / 128, mf.size * 8 / 1024)) * 100)
    ELSE CONVERT(NUMERIC(10, 2), 100 - log_space.used_log_space_in_percent)
    END AS FreeSpacePercent
FROM tempdb.sys.master_files AS mf
LEFT JOIN tempdb.sys.dm_db_file_space_usage file_space ON mf.file_id = file_space.file_id
LEFT JOIN tempdb.sys.dm_db_log_space_usage log_space ON mf.database_id = log_space.database_id
WHERE mf.database_id = DB_ID('tempdb');


-- dbo.vSessionBBands source

ALTER VIEW vSessionBBands
AS
  Select sess.SessionId,
         STUFF((Select '/' + n.technology
                from SessionsB s
                     JOIN NetworkInfo n ON n.NetworkId between s.StartNetworkId and s.NetworkId
                where s.SessionId = sess.SessionId
                group by n.technology
                order by n.technology
                for xml path('')), 1, 1, '') as SessionBands
  from SessionsB sess;


-- dbo.vSessionBands source

ALTER VIEW vSessionBands
AS
  Select sess.SessionId,
         STUFF((Select '/' + n.technology
                from Sessions s
                     JOIN NetworkInfo n ON n.NetworkId between s.StartNetworkId and s.NetworkId
                where s.SessionId = sess.SessionId
                group by n.technology
                order by n.technology
                for xml path('')), 1, 1, '') as SessionBands
  from Sessions sess;


