-- dbo.vSocialMediaKPI source

ALTER VIEW vSocialMediaKPI
AS
  Select k.*, p.ServiceProvider, p.ServiceProfileName,
         case MediaType
           when 1 then 'Text'
           when 3 then 'Picture'
           when 5 then 'Video'
           else '---'
         end as MediaType,
