-- dbo.vSpreadingFactor source

ALTER VIEW vSpreadingFactor
as
SELECT
	b.SessionId,
	b.TestId,
	b.MsgId,
	b.PosId,
	b.NetworkId,
	'DL' AS Link,
	b.SFDL as SF,
	convert(float,datediff(ms,a.msgTime,b.msgTime))/1000 as Duration
FROM
	WCDMAValues a,
	WCDMAValues b

WHERE
	a.MsgID + 1 = b.MsgID AND
	a.SessionId = b.SessionId AND
	b.SFDL IS not NULL

UNION

SELECT
	b.SessionId,
	b.TestId,
	b.MsgId,
	b.PosId,
	b.NetworkId,
	'UL' AS Link,
	b.SFUL as SF,
	convert(float,datediff(ms,a.msgTime,b.msgTime))/1000 as Duration
FROM
	WCDMAValues a,
	WCDMAValues b

WHERE
	a.MsgID + 1 = b.MsgID AND
	a.SessionId = b.SessionId AND
	b.SFDL IS not NULL;


-- dbo.vTechnology source

ALTER VIEW vTechnology
As
  Select *,
    case
    when CurrTechnology is not NULL and PrevTechnology is NULL then  1  -- start of a technology
    when CurrTechnology is NULL and PrevTechnology is not NULL then  2  -- end of a technology
    when CurrTechnology is not NULL and PrevTechnology is not NULL and
         CurrTechnology <> PrevTechnology then  3                       -- change of technology
    when CurrTechnology is NULL and PrevTechnology is NULL and
         TriggerMsg is NULL and Summary is NULL then  4                 -- deleted voice call technology
    else 0 end as Tech
  from Technology;


-- dbo.vTechnologyDurationSession source

ALTER VIEW vTechnologyDurationSession
AS
  -- Duration per Technology for each Session
  Select s.SessionId, s.StartTime as SessionStart, DATEADD(ms, s.Duration, s.StartTime) as SessionEnd, s.Duration as SessionDuration,
         case when n.Status in (6, 8) then dbo.GetRFBand(n.RFBand)
              else dbo.GetNetworkStatusDescription(n.Status)
         end as Technology,
         SUM(n.Duration) - case
                             when s.StartNetworkId = MIN(n.NetworkId) then DATEDIFF(ms, MIN(n.MsgTime), s.StartTime)
                             else 0
                           end
                         + case
                             when s.NetworkId = MAX(n.NetworkId) then DATEDIFF(ms, MAX(n.MsgTime), DATEADD(ms, s.Duration, s.StartTime)) - nEnd.Duration
                             else 0
                           end
         as TechnologyDuration
  from NetworkInfo n, Sessions s
       JOIN NetworkInfo nEnd ON nEnd.NetworkId = s.NetworkId
  where n.NetworkId between (Select StartNetworkId from Sessions where SessionId = s.SessionId) and
                            (Select NetworkId from Sessions where SessionId = s.SessionId)
  group by s.SessionId, s.startTime, s.duration, n.RFBand, n.Status, s.StartNetworkId, s.NetworkId, nEnd.Duration;


-- dbo.vTechnologyDurationTest source

ALTER VIEW vTechnologyDurationTest
AS
  -- Duration per Technology for each Test
  Select t.SessionId, t.TestId, t.StartTime as TestStart, DATEADD(ms, t.Duration, t.StartTime) as TestEnd, t.Duration as TestDuration,
         case when n.Status in (6, 8) then dbo.GetRFBand(n.RFBand)
              else dbo.GetNetworkStatusDescription(n.Status)
         end as Technology,
         SUM(n.Duration) - case
                             when t.StartNetworkId = MIN(n.NetworkId) then DATEDIFF(ms, MIN(n.MsgTime), t.StartTime)
                             else 0
                           end
                         + case
                             when t.NetworkId = MAX(n.NetworkId) then DATEDIFF(ms, MAX(n.MsgTime), DATEADD(ms, t.Duration, t.StartTime)) - nEnd.Duration
                             else 0
                           end
         as TechnologyDuration
  from NetworkInfo n, TestInfo t
       JOIN NetworkInfo nEnd ON nEnd.NetworkId = t.NetworkId
  where n.NetworkId between (Select StartNetworkId from TestInfo where TestId = t.TestId) and
                            (Select NetworkId from TestInfo where TestId = t.TestId)
  group by t.SessionId, t.TestId, t.startTime, t.duration, n.RFBand, n.Status, t.StartNetworkId, t.NetworkId, nEnd.Duration;


-- dbo.vTechnologySession source

ALTER VIEW vTechnologySession
AS
  Select DISTINCT s.SessionId,
         case when n.RFBand = 0 then NULL
              else COALESCE(band.Tech, 'unknown')
         end as Technology
  from Sessions s
       JOIN NetworkInfo n ON n.NetworkId BETWEEN s.StartNetworkId AND s.NetworkId
       LEFT JOIN vSQDefinitionsRFBand band ON band.RFBand = n.RFBand;


-- dbo.vTechnologyTest source

ALTER VIEW vTechnologyTest
AS
  Select DISTINCT t.TestId,
         case when n.RFBand = 0 then NULL
              else COALESCE(band.Tech, 'unknown')
         end as Technology
  from TestInfo t
       JOIN NetworkInfo n ON n.NetworkId BETWEEN t.StartNetworkId AND t.NetworkId
       LEFT JOIN vSQDefinitionsRFBand band ON band.RFBand = n.RFBand;


-- dbo.vTechnologyTestCount source

ALTER VIEW vTechnologyTestCount
AS

Select
	Testinfo.SessionId,
	Technology.Testid,
	Testinfo.Typeoftest+' '+Testinfo.Direction as 'Test Type',
	Case when Technology.Summary is not Null then Technology.Summary else 'no Technology available' end as 'TechnologyperTest',
	Count(Technology.testid) as 'TestCount' 
From
	Technology Join Testinfo On(Technology.TestId=Testinfo.TestId and Technology.TriggerMsg like '%Test end%')
Group By
	Testinfo.SessionId,
	Technology.Testid,
	Testinfo.Typeoftest,
	Testinfo.Direction,
	Technology.Summary;


-- dbo.vTestInfoTechnology source

ALTER VIEW vTestInfoTechnology
AS
  Select Sessions.FileId,
         TestInfo.SessionId,
         TestInfo.TestId,
         Sessions.sessionType,
         TestInfo.startTime,
         DATEADD(ms, TestInfo.duration, TestInfo.startTime) as Endtime,
         dbo.GetAllNetworkBandTechPerSession(TestInfo.StartNetworkId, TestInfo.NetworkId) as 'Technology'
  From TestInfo
       JOIN Sessions ON Sessions.SessionId = TestInfo.SessionId
  Where Sessions.sessionType = 'CALL'

  UNION

  Select Sessions.FileId,
         TestInfo.SessionId,
         TestInfo.TestId,
         Sessions.sessionType,
         TestInfo.startTime,
         DATEADD(ms, TestInfo.duration, TestInfo.startTime) as Endtime,
         Technology.Summary
  From Sessions
       JOIN TestInfo ON TestInfo.SessionId = Sessions.SessionId
       JOIN Technology ON Technology.TestId = Testinfo.TestId
  Where Sessions.sessionType = 'DATA' and
        Technology.TriggerMsg like 'Test end%';


-- dbo.vTestInfoTechnologyAll source

ALTER VIEW vTestInfoTechnologyAll
AS
  Select TestInfo.*,
         vTestInfoTechnology.Technology
  from TestInfo
       LEFT JOIN vTestInfoTechnology ON vTestinfoTechnology.TestId = TestInfo.TestId;


-- dbo.vTimeSlots source

ALTER VIEW vTimeSlots
as
select
	t.msgID,
	t.sessionID,
	t.testID,
	t.msgTime,
	t.posID,
	t.NetworkID,
	'DL'as Link,
	numDLTS as numTS,
	convert(float,t.duration)/1000 as duration
from
	TimeSlotAlloc t
where
	t.numDLTS is not NULL and
	t.numDLTS <> 0
Union
select
	t.msgID,
	t.sessionID,
	t.testID,
	t.msgTime,
	t.posID,
	t.NetworkID,
	'UL'as Link,
	numULTS as numTS,
	convert(float,t.duration)/1000 as duration
from
	TimeSlotAlloc t
where
	t.numULTS is not NULL and
	t.numULTS <> 0;


-- dbo.vUMTSNASMMcharacteristics source

ALTER VIEW vUMTSNASMMcharacteristics
AS
select sessionId,
	testId,
	msgTime,
	case netOpMode
         when 0 then  'Class 1'
	 when 1 then 'Class 2'
	 when 2 then 'Classe 3'
	 else '-' end as netOpMode,
	case ServiceType
         when 0 then  'NO_SERVICE'
	 when 1 then 'CS_ONLY'
	 when 2 then 'Classe 3'
	 else '-' end as ServiceType,
	MCC, MNC, LAC, RAI
from UMTSNASMM;


-- dbo.vUMTSNASQOS source

ALTER VIEW vUMTSNASQOS
AS
Select sessionId, testId, msgTime, posId, networkId,
       ConnectionId,

       case DelayClass
         when 0 then 'Subscribed Delay Class'
         when 1 then 'Delay Class 1'
         when 2 then 'Delay Class 2'
         when 3 then 'Delay Class 3'
         when 4 then 'Delay Class 4 (best effort)'
       else 'Reserved' end as DelayClass,

       case ReliabilityClass
         when 0 then 'Subscribed reliability class'
         when 1 then 'ACK GTP, LLC and RLC; Protected data'
         when 2 then 'UNACK GTP, ACK LLC and RLC; Protected data'
         when 3 then 'UNACK GTP and LLC, ACK RLC; Protected data'
         when 4 then 'UNACK GTP, LLC and RLC; Protected data'
         when 5 then 'UNACK GTP, LLC and RLC; Unprotected data'
       else 'Reserved' end as ReliabilityClass,

       case PeakThroughput
         when   0 then 'Subscribed peak throughput'
         when   2 then 'Up to 2000 octet/s'
         when   3 then 'Up to 4000 octet/s'
         when   4 then 'Up to 8000 octet/s'
         when   5 then 'Up to 16000 octet/s'
         when   6 then 'Up to 32000 octet/s'
         when   7 then 'Up to 64000 octet/s'
         when   8 then 'Up to 128000 octet/s'
         when   9 then 'Up to 256000 octet/s'
         when 0xF then 'Reserved'
       else 'Up to 1000 octet/s' end as PeakThroughput,

       case PrecendenceClass
         when 0 then 'Subscribed precedence'
         when 1 then 'High Priority'
         when 2 then 'Normal Priority'
         when 3 then 'Low Priority'
       else 'Reserved' end as PrecendenceClass,

       case MeanTroughput
         when  0 then 'Subscribed mean throughput'
         when  1 then '100 octet/h'
         when  2 then '200 octet/h'
         when  3 then '500 octet/h'
         when  4 then '1000 octet/h'
         when  5 then '2000 octet/h'
         when  6 then '5000 octet/h'
         when  7 then '10000 octet/h'
         when  8 then '20000 octet/h'
         when  9 then '50000 octet/h'
         when 10 then '100000 octet/h'
         when 11 then '200000 octet/h'
         when 12 then '500000 octet/h'
         when 13 then '1000000 octet/h'
         when 14 then '5000000 octet/h'
         when 15 then '10000000 octet/h'
         when 16 then '20000000 octet/h'
         when 17 then '50000000 octet/h'
         when 31 then 'Best effort'
       else 'Reserved' end as MeanTroughput,

       case TrafficClass
         when 0 then 'Subscribed traffic class'
         when 1 then 'Conversation class'
         when 2 then 'Streaming class'
         when 3 then 'Interactive class'
         when 4 then 'Background class'
       else 'Reserved' end as  TrafficClass,

       case DeliveryOrder
         when 0 then 'Subscribed delivery order'
         when 1 then 'With delivery order'
         when 2 then 'Without delivery order'
       else 'Reserved' end as DeliveryOrder,

       case DeliveryErrSDU
         when 0 then 'Subscribed delivery of erroneous SDUs'
         when 1 then 'No detection'
         when 2 then 'Erroneous SDU delivered'
         when 3 then 'Erroneous SDU not delivered'
       else 'Reserved' end as  DeliveryErrSDU,

       case
         when MaxSDU = 0 then 'Subscribed maximum SDU size'
         when MaxSDU = 0xff then 'Reserved'
         when MaxSDU between 1 and 150 then Convert(varchar,MaxSDU * 10) + ' octets'
         when MaxSDU = 151 then '1502 octets'
         when MaxSDU = 152 then '1510 octets'
         when MaxSDU = 153 then '1520 octets'
       else 'unknwon' end as  MaxSDU,

       case
         when MaxUlBitRate=0 then 'Subscribed max. bit rate'
         when MaxUlBitRate=254 then 'See extended value in L3'
         when MaxUlBitRate between 1 and 63 then Convert(varchar,MaxUlBitRate) + 'kbps'
         when MaxUlBitRate between 64 and 127 then Convert(varchar,(MaxUlBitRate-64)*8+64) + 'kbps'
         when MaxUlBitRate between 128 and 254 then Convert(varchar,(MaxUlBitRate-128)*64+576) + 'kbps'
       else '0 kbps' end as  MaxUlBitRate,

       case
         when MaxDlBitRate=0 then 'Subscribed max. bit rate'
         when MaxDlBitRate=254 then 'See extended value in L3'
         when MaxDlBitRate between 1 and 63 then Convert(varchar,MaxDlBitRate) + 'kbps'
         when MaxDlBitRate between 64 and 127 then Convert(varchar,(MaxDlBitRate-64)*8+64) + 'kbps'
         when MaxDlBitRate between 128 and 254 then Convert(varchar,(MaxDlBitRate-128)*64+576) + 'kbps'
       else '0 kbps' end as  MaxDlBitRate,

       case  ResidualBER
         when 0 then 'Subscribed BER'
         when 1 then '0.05'
         when 2 then '0.01'
         when 3 then '0.005'
         when 4 then '0.004'
         when 5 then '0.001'
         when 6 then '0.0001'
         when 7 then '0.00001'
         when 8 then '0.000001'
         when 9 then '0.00000006'
       else 'Reserved' end as  ResidualBER,

       case SDUErrRatio
         when 0 then 'Subscribed SDU error ratio'
         when 1 then '0.01'
         when 2 then '0.007'
         when 3 then '0.001'
         when 4 then '0.0001'
         when 5 then '0.00001'
         when 6 then '0.000001'
         when 7 then '0.1'
       else 'Reserved' end as SDUErrRatio,

       case
         when TransferDelay=0 then 'Subscribed transfer delay'
         when TransferDelay between 1 and 15 then Convert(varchar,transferDelay*10) + 'ms'
         when TransferDelay between 16 and 31 then Convert(varchar,(transferDelay-16)*50+200) + 'ms'
       else 'Reserved' end as TransferDelay,

       case TrafficHandlingPrio
         when 0 then 'Subscribed traffic handling priority'
         when 1 then 'Priority Level 1'
         when 2 then 'Priority Level 2'
         when 3 then 'Priority Level 3'
       else 'unknown' end as TrafficHandlingPrio,

       GuaranteedUlBitRate,
       GuaranteedDlBitRate
from UMTSNASQOS;


-- dbo.vUMTS_GMM_MM_STATE source

ALTER VIEW vUMTS_GMM_MM_STATE
AS
select sessionId, testId, msgTime, posId, networkId ,
	case Type when 0 then 'GMM' when 1 then 'MM' else '-' end as Type,
	case Type
	  when 0 then
		case State
			when 0 then 'GMM_NULL'
			when 1 then 'GMM_DEREGISTERED'
			when 2 then 'GMM_REGISTERED_INITIATED'
			when 3 then 'GMM_REGISTERED'
			when 4 then 'GMM_DEREGISTERED_INITATED'
			when 5 then 'GMM_ROUTING_AREA_UPDATE_INITIATED'
			when 6 then 'GMM_SERVICE_REQUEST_INITIATED'
			else '-' end
	  when 1 then
		case State
			when 0 then 'MM_NULL'
			when 3 then 'MM_LOCATION_UPDATE_INITIATED'
			when 5 then 'MM_WAIT_FOR_ONGOING_MM_CONNECTION'
			when 6 then 'MM_CONNECTION_ACTIVE'
			when 7 then 'MM_IMSI_DETACH_INITIATED'
			when 8 then 'MM_PROCESS_CM_SERVICE_PROMPT'
			when 9 then 'MM_WAIT_FOR_NETWORK_COMMAND'
			when 10 then 'MM_LOCATION_UPDATE_REJECTED'
			when 13 then 'MM_WAIT_FOR_RR_CONNECTION_LU'
			when 14 then 'MM_WAIT_FOR_RR_CONNECTION_MM'
			when 15 then 'MM_WAIT_FOR_RR_CONNECTION_IMSI_DETACH'
			when 17 then 'MM_REESTABLISHMENT_INITIATED'
			when 18 then 'MM_WAIT_FOR_RR_ACTIVE'
			when 19 then 'MM_IDLE'
			when 20 then 'MM_WAIT_FOR_ADDITIONAL_OUTGOING_MM_CONNECTION'
			when 21 then 'MM_WAIT_FOR_RR_CONNECTION_REESTABLISHMENT'
			when 22 then 'MM_WAIT_FOR_REESTABLISH_DECISION'
			when 23 then 'MM_LOCATION_UPDATING_PENDING'
			when 25 then 'MM_RR_CONNECTION_RELEASE_NOT_ALLOWED'
			else '-' end
	   else '-' end as State,
	case Type
 	  when 0 then
		case Substate
			when 0 then 'GMM_NORMAL_SERVICE'
			when 1 then 'GMM_LIMITED_SERVICE'
			when 2 then 'GMM_ATTACH_NEEDED'
			when 3 then 'GMM_ATTEMPTING_TO_ATTACH'
			when 4 then 'GMM_NO_IMSI'
			when 5 then 'GMM_NO_CELL_AVAILABLE'
			when 6 then 'GMM_PLMN_SEARCH'
			when 7 then 'GMM_SUSPENDED'
			when 8 then 'GMM_UPDATE_NEEDED'
			when 9 then 'GMM_ATTEMPTING_TO_UPDATE'
			when 10 then 'GMM_ATTEMPTING_TO_UPDATE_MM'
			when 11 then 'GMM_IMSI_DETACH_INITIATED'
			when 12 then 'GMM_NULL_SUBSTATE'
			else '-' end
	  when 1 then
		case Substate
			when 0 then 'MM_NULL_SUBSTATE'
			when 1 then 'MM_NO_IMSI'
			when 2 then 'MM_PLMN_SEARCH'
			when 3 then 'MM_LIMITED_SERVICE'
			when 4 then 'MM_ATTEMPTING_TO_UPDATE'
			when 5 then 'MM_LOCATION_UPDATE_NEEDED'
			when 6 then 'MM_NO_CELL_AVAILABLE'
			when 7 then 'MM_PLMN_SEARCH_NORMAL_SERVICE'
			when 8 then 'MM_NORMAL_SERVICE'
			else '-' end
	 else '-' end as Substate,
	case Type
 	  when 0 then
		case UpdateType
			when 0 then 'GMM_GU1_UPDATED'
			when 1 then 'GMM_GU2_NOT_UPDATED'
			when 2 then 'GMM_GU3_PLMN_NOT_ALLOWED'
			when 3 then 'GMM_GU3_ROUTING_AREA_NOT_ALLOWED'
			else '-' end
	  when 1 then
		case UpdateType
			when 0 then 'UPDATED'
			when 1 then 'NOT_UPDATED'
			when 2 then 'ROAMING_NOT_ALLOWED'
			when 3 then 'LOCATION_AREA_NOT_ALLOWED'
			else '-' end
	  else '-' end as UpdateType

from UMTS_GMM_MM_State;


-- dbo.vVFSpeechNonSustainablility source

ALTER VIEW vVFSpeechNonSustainablility
AS
Select
	
	 Sessions.SessionId,
	 0 as TestID,
	 Sessions.NetworkId,
	 Sessions.PosId,
	 m.StartTime,
	 m.EndTime,
	 DATEDIFF(ms, m.StartTime,m.EndTime) as Duration,
	 m.NumSamples,
	 case when m.AvgNB is not NULL then m.AvgNB else m.AvgWB end as AverageLQ,
	 case when m.AvgNB is not NULL then 'NB' else 'WB' end as Bandwidth,
	 case when n.SessionId is not NULL then 'Failed' else 'Successful' end as Result
	 
from
		Sessions
				     join CallSession on (Callsession.SessionId = Sessions.SessionID and CallSession.callStatus = 'Completed') 
				left join 	(select distinct c.SessionId
							 from 
								 CallSession c join TestInfo t on  (t.SessionId = c.SessionId   and t.typeoftest like 'Speech%' and t.valid = 1)
											   join TestInfo t2 on (t2.SessionId = c.SessionId  and t2.typeoftest like 'Speech%' and t2.valid = 1 and t.testID + 1 = t2.TestId)
											   join ResultsLQ08Avg l1 on (l1.testID = t.testID) and (l1.OptionalNB < 1.7 or l1.OptionalWB < 1.3 or l1.status = 'Silence')   
										       join ResultsLQ08Avg l2 on (l2.testID = t2.testID and (l2.OptionalNB < 1.7 or l2.OptionalWB < 1.3 or l2.Status = 'Silence'))		
														) n on (n.SessionId =  Sessions.SessionId)
		        left join 	(select c.SessionId,
									Avg(l1.OptionalWB) as AvgWB,
									avg(l1.OptionalNB) as AvgNB,
									min(t.startTime) as StartTime,
									max(DateADD(ms,t.duration,t.starttime)) as EndTime,
									count(*) as NumSamples
									from 
									   CallSession c join TestInfo t on (t.SessionId = c.SessionId and t.typeoftest like 'Speech%' and t.valid = 1)
										join ResultsLQ08Avg l1 on (l1.testID = t.testID)	
									group by c.sessionID) m on (m.SessionId =  Sessions.SessionId)

			where m.NumSamples > 0;


-- dbo.vVFYouTubeB11 source

ALTER VIEW vVFYouTubeB11
AS
SELECT  
		s.sessionID,
		t.testID,
		t.NetworkId,
		t.PosID,
		t.typeoftest,
		t.qualityIndication  ,
		case when k.ErrorCode is not NULL then k.StartTime else
				case when v.MsgTime is not NULL then v.MsgTime else t.startTime end end as StartTime, 
		ISNULL(p.EndTime,DATEADD(ms,t.duration,t.starttime)) as EndTime,	
		        case when (case when p.ErrorCode is not NULL then p.ErrorCode else (case when f.Event is not NULL then 0 else 1 end) end) = 0 
		      then 'Successful' else 'Failed' end   as Result,
		case when k.StartTime is not NULL then 
			 case when p.EndTime is not NULL then DateDiff(ms,k.starttime,p.Endtime)/1000.0 
			                                 else DATEDIFF(ms,k.startTime,DATEADD(ms,t.duration,t.starttime))/1000.0 end 
			 else DateDiff(ms,ISNULL(v.MsgTime,t.StartTime),ISNULL(p.Endtime, ISNULL(f.MsgTime, DATEADD(ms,t.duration,t.starttime))))/1000.0
		 end as AccessDuration,
	 	r.Player,
		r.URL ,
		case when k.ErrorCode is not NULL then 'Start KPI10620' else 
				case when v.MsgTime is not NULL then 'Player Init' else 'Test start' end end as StartTrigger 
FROM	
		Sessions s  join TestInfo t on (t.SessionId = s.SessionId and t.typeoftest like '%YouTube%')
					left join VideoStatusTrace v on (v.TestID = t.TestId and v.event = 'Initialized')
					left join VideoStatusTrace f on (f.TestID = t.TestId and f.event = 'Displaying')
					left join ResultsKPI k on (k.testID = t.testID and k.KPIID = 10620)
					left join ResultsKPI p on (p.testID = t.testID and p.KPIID = 30621)
					left join ResultsVideoStream r on (r.testID = t.TestId);


-- dbo.vVFYouTubeB21 source

ALTER VIEW vVFYouTubeB21
AS
SELECT  
		s.sessionID,
		t.testID,
		t.NetworkId,
		t.PosID,
		t.typeoftest,
		t.qualityIndication  ,
		case when k.ErrorCode is not NULL then k.StartTime else
				case when v.MsgTime is not NULL then v.MsgTime else t.startTime end end as StartTime, 
		ISNULL(p.EndTime,DATEADD(ms,t.duration,t.starttime)) as EndTime,	
		case when f.Freezings = 'No Freezings' and ISNULL(p.ErrorCode,1) = 0 then 'Successful' else 'Failed' end as Result,
		case when k.StartTime is not NULL then 
			 case when p.EndTime is not NULL then DateDiff(ms,k.starttime,p.Endtime)/1000.0 
			                                 else DATEDIFF(ms,k.startTime,DATEADD(ms,t.duration,t.starttime)) end 
			 else DateDiff(ms,ISNULL(v.MsgTime,t.StartTime),ISNULL(p.Endtime,DATEADD(ms,t.duration,t.starttime)))/1000.0
		 end as Duration,
		case when p.ErrorCode is not NULL then f.PlayoutDuration else NULL end as PlayoutDuration,
	 	r.Player,
		r.URL,
		case when k.ErrorCode is not NULL then 'Start KPI10620' else 
				case when v.MsgTime is not NULL then 'Player Init' else 'Test start' end end as StartTrigger 
FROM	
		Sessions s  join TestInfo t on (t.SessionId = s.SessionId and t.typeoftest like '%YouTube%')
					left join VideoStatusTrace v on (v.TestID = t.TestId and v.event = 'Initialized')
					left join ResultsKPI k on (k.testID = t.testID and k.KPIID = 10620)
					left join ResultsKPI p on (p.testID = t.testID and p.KPIID = 20621)
					left join vETSIYouTubeFreezings f on (f.testID = t.testID)
					left join ResultsVideoStream r on (r.testID = t.TestId)
where
		s.valid = 1;


-- dbo.vVFYouTubeB3 source

ALTER VIEW vVFYouTubeB3
AS
select
		s.SessionId,
		t.TestId,
		t.startTime as msgTime,
		t.PosId,
		t.NetworkId,
		t.typeoftest,
		m.VideoAccess,
		m.VideoAccessDuration,
		m.ReproductionDelay,
		f.NumFreezings,
		ISNULL(f.AccFreezingTime,0) as AccFreezingTime,
		ISNULL(f.MaxFreezingTime,0) as MaxFreezingTime,
		m.VideoDownload,
		m.VideoDownloadDuration,
		case when m.VideoDownload <> 0 then 'Failed' else  
		       case when m.VideoAccessDuration <= 10.0 and 
				  ISNULL(m.ReproductionDelay,25) < 23.0 and 
				  f.NumFreezings <= 10000 and 
				  ISNULL(f.AccFreezingTime,0) < 15000  and 
				  ISNULL(f.MaxFreezingTime,0) < 8000  
				   then 'Successful' else 'Failed' 
				end 
		end as DownloadResult,
		m.VideoAccessDuration + m.VideoDownloadDuration as Duration,
		e.URL ,
		e.VideoCodec,
		e.VideoResolution,
		e.player,
		m.TriggerType 
from 
		Sessions s	join TestInfo t on (t.SessionId = s.SessionId and t.typeoftest like '%YouTube%')
					join ETSIYouTubeTriggerSelectiveKPIs m on (m.TestId = t.TestId)
					left join ResultsVideoStream e on (e.TestId = t.TestId)
					left join vResultsVideoStreamFreezingsAvg f on (f.TestId = t.TestId)
	
group by
		s.SessionId,
		t.TestId,
		t.startTime,
		t.PosId,
		t.NetworkId,
		t.typeoftest,
		m.VideoAccess,
		m.VideoAccessDuration,
		m.ReproductionDelay,
		f.NumFreezings,
		ISNULL(f.AccFreezingTime,0) ,
		ISNULL(f.MaxFreezingTime,0) ,
		m.VideoDownload,
		m.VideoDownloadDuration,
		e.URL ,
		e.VideoCodec,
		e.VideoResolution,
		e.player,
		m.TriggerType;


-- dbo.vVFYouTubeHD source

ALTER VIEW vVFYouTubeHD
AS
select
		s.SessionId,
		t.TestId,
		t.startTime as msgTime,
		t.PosId,
		t.NetworkId,
		t.typeoftest,
		case when m.VideoResolution is NULL then 'Resolution not determined' else  'Resolution determined' end as DownloadResult, -- RTC 369421
		--m.DownloadResult,
		m.Duration,
		ISNULL(case when sum(r.DeltaTime) > 0 then sum(r.DeltaTime * r.VerResolution)/sum(r.DeltaTime) else NULL end,Min(Substring(m.VideoResolution,1,len(m.VideoResolution)-1))) AvgRes,
		MIN(case when ISNULL(r.VerResolution,ISNULL(convert(int,Substring(m.VideoResolution,1,len(m.VideoResolution)-1)),0)) < 720 then 'Failed' else 'Successful' end) as CompleteHD,
		MAX(case when ISNULL(r.VerResolution,ISNULL(convert(int,Substring(m.VideoResolution,1,len(m.VideoResolution)-1)),0)) < 720 then 'Non HD' else 'HD' end) as HDState,
		m.URL ,
		m.VideoCodec,
		m.VideoResolution,
		vst.VideoSize as RenderedBytes,
		m.player,
		m.TriggerType 
from 
		Sessions s	join TestInfo t on (t.SessionId = s.SessionId and t.typeoftest like '%YouTube%')
					join vVFYouTubeB3 m on (m.TestId = t.TestId and m.DownloadResult = 'Successful')
					left join ResultsVq06TimeDom r on (r.TestId = t.TestId)
					left join ResultsVQ08StreamAvg vst on (t.TestId = vst.TestId)


group by
		s.SessionId,
		t.TestId,
		t.startTime,
		t.PosId,
		t.NetworkId,
		t.typeoftest,
		m.DownloadResult,
		m.Duration,
		m.URL ,
		m.VideoCodec,
		m.VideoResolution,
		vst.VideoSize,
		m.player,
		m.TriggerType;


-- dbo.vVFYouTubeKPIB2 source

ALTER VIEW vVFYouTubeKPIB2
AS
SELECT  
		s.sessionID,
		v.testID,
		t.NetworkId,
		t.PosID,
		t.typeoftest,
		case when k.ErrorCode is not NULL then k.StartTime else
				case when v.MsgTime is not NULL then v.MsgTime else t.startTime end end as StartTime, 
		ISNULL(p.EndTime,DATEADD(ms,t.duration,t.starttime)) as EndTime,		
		ISNULL(f.ImpairmentFree,'Failed') as Result,
		case when k.StartTime is not NULL then 
			 case when p.EndTime is not NULL then DateDiff(ms,k.starttime,p.Endtime)/1000.0 
			                                 else DATEDIFF(ms,k.startTime,DATEADD(ms,t.duration,t.starttime)) end 
			 else DateDiff(ms,ISNULL(v.MsgTime,t.StartTime),ISNULL(p.Endtime,DATEADD(ms,t.duration,t.starttime)))/1000.0
		 end as Duration,
		case when p.ErrorCode is not NULL then f.PlayoutDuration else NULL end as PlayoutDuration,
		f.Player,
		case when k.ErrorCode is not NULL then 'Start KPI10620' else 
				case when v.MsgTime is not NULL then 'Player Init' else 'Test start' end end as StartTrigger 
FROM	
		Sessions s  join TestInfo t on (t.SessionId = s.SessionId and t.typeoftest like '%YouTube%')
					left join VideoStatusTrace v on (v.TestID = t.TestId and v.event = 'Initialized')
					left join ResultsKPI k on (k.testID = t.testID and k.KPIID = 10620)
					left join ResultsKPI p on (p.testID = t.testID and p.KPIID = 20621)
					left join vETSIYouTubeFreezings f on (f.testID = t.testID);


-- dbo.vVideoStreamingEvents source

ALTER VIEW vVideoStreamingEvents
AS
SELECT
      s.SessionId,
      s.TestId,
      s.MsgTime,
      s.PosID,
      s.NetworkId,
      s.Player,
      s.Source,
      s.Event,
      case when s.event in ('SETUP','START','Connecting...','Loading','Displaying','Playing','STOP') then
						 'trace' else 'notrace' end as traceindicator
FROM
		VideoStatusTrace s
		where s.event in ('SETUP','START','Connecting...','Loading','Displaying','Playing','STOP');


-- dbo.vVoiceChannelTypeTest source

ALTER VIEW vVoiceChannelTypeTest
AS
  Select x.SessionId,
         x.TestId,
         x.Direction,
         case when MAX(x.Codec) in (3, 4, 5, 10) then 'TCH HR'
              when MAX(x.Codec) in (1, 2, 6, 11) then 'TCH FR'
         end as ChannelType,
         x.Duration
  from vVoiceCodecsTest x
  where x.Duration = (Select MAX(r.Duration)
                      from vVoiceCodecsTest r
                      where r.TestId = x.TestId and r.Direction = x.Direction)
  group by x.SessionId, x.TestId, x.Direction, x.Duration;


-- dbo.vVoiceChannelTypeTestBSide source

ALTER VIEW vVoiceChannelTypeTestBSide
AS
  Select x.SessionId,
         x.TestId,
         x.Direction,
         case when MAX(x.Codec) in (3, 4, 5, 10) then 'TCH HR'
              when MAX(x.Codec) in (1, 2, 6, 11) then 'TCH FR'
         end as ChannelType,
         x.Duration
  from vVoiceCodecsTestBSide x
  where x.Duration = (Select MAX(r.Duration)
                      from vVoiceCodecsTestBSide r
                      where r.TestId = x.TestId and r.Direction = x.Direction)
  group by x.SessionId, x.TestId, x.Direction, x.Duration;


-- dbo.vVoiceCodecDistribution source

ALTER VIEW vVoiceCodecDistribution
AS
  Select v.SessionID,
         v.TestID,
         Max(v.MsgTime) as MsgTime,
         Max(v.PosID) as PosID,
         Max(v.NetworkID) as NetworkID,
         v.Direction,
         SUM(Case when (Codec <  1                      ) then v.Duration else NULL end) * 1.0 as NoCodecInfo,
         SUM(Case when (Codec =  1                      ) then v.Duration else NULL end) * 1.0 as EFR,
         SUM(Case when (Codec =  2                      ) then v.Duration else NULL end) * 1.0 as FR,
         SUM(Case when (Codec =  3                      ) then v.Duration else NULL end) * 1.0 as HR,
         SUM(Case when (Codec =  4                      ) then v.Duration else NULL end) * 1.0 as EHR,
         SUM(Case when (Codec =  5                      ) then v.Duration else NULL end) * 1.0 as AMR_HR,
         SUM(Case when (Codec =  5 and CodecRate = 10.2 ) then v.Duration else NULL end) * 1.0 as AMR_HR_102,
         SUM(Case when (Codec =  5 and CodecRate = 7.95 ) then v.Duration else NULL end) * 1.0 as AMR_HR_795,
         SUM(Case when (Codec =  5 and CodecRate = 7.4  ) then v.Duration else NULL end) * 1.0 as AMR_HR_74,
         SUM(Case when (Codec =  5 and CodecRate = 6.7  ) then v.Duration else NULL end) * 1.0 as AMR_HR_67,
         SUM(Case when (Codec =  5 and CodecRate = 5.9  ) then v.Duration else NULL end) * 1.0 as AMR_HR_59,
         SUM(Case when (Codec =  5 and CodecRate = 5.15 ) then v.Duration else NULL end) * 1.0 as AMR_HR_515,
         SUM(Case when (Codec =  5 and CodecRate = 4.75 ) then v.Duration else NULL end) * 1.0 as AMR_HR_475,
         SUM(Case when (Codec =  6                      ) then v.Duration else NULL end) * 1.0 as AMR_FR,
         SUM(Case when (Codec =  6 and CodecRate = 12.2 ) then v.Duration else NULL end) * 1.0 as AMR_FR_122,
         SUM(Case when (Codec =  6 and CodecRate = 10.2 ) then v.Duration else NULL end) * 1.0 as AMR_FR_102,
         SUM(Case when (Codec =  6 and CodecRate = 7.95 ) then v.Duration else NULL end) * 1.0 as AMR_FR_795,
         SUM(Case when (Codec =  6 and CodecRate = 7.4  ) then v.Duration else NULL end) * 1.0 as AMR_FR_74,
         SUM(Case when (Codec =  6 and CodecRate = 6.7  ) then v.Duration else NULL end) * 1.0 as AMR_FR_67,
         SUM(Case when (Codec =  6 and CodecRate = 5.9  ) then v.Duration else NULL end) * 1.0 as AMR_FR_59,
         SUM(Case when (Codec =  6 and CodecRate = 5.15 ) then v.Duration else NULL end) * 1.0 as AMR_FR_515,
         SUM(Case when (Codec =  6 and CodecRate = 4.75 ) then v.Duration else NULL end) * 1.0 as AMR_FR_475,
         SUM(Case when (Codec =  7                      ) then v.Duration else NULL end) * 1.0 as AMR,
         SUM(Case when (Codec =  7 and CodecRate = 12.2 ) then v.Duration else NULL end) * 1.0 as AMR_122,
         SUM(Case when (Codec =  7 and CodecRate = 10.2 ) then v.Duration else NULL end) * 1.0 as AMR_102,
         SUM(Case when (Codec =  7 and CodecRate = 7.95 ) then v.Duration else NULL end) * 1.0 as AMR_795,
         SUM(Case when (Codec =  7 and CodecRate = 7.4  ) then v.Duration else NULL end) * 1.0 as AMR_74,
         SUM(Case when (Codec =  7 and CodecRate = 6.7  ) then v.Duration else NULL end) * 1.0 as AMR_67,
         SUM(Case when (Codec =  7 and CodecRate = 5.9  ) then v.Duration else NULL end) * 1.0 as AMR_59,
         SUM(Case when (Codec =  7 and CodecRate = 5.15 ) then v.Duration else NULL end) * 1.0 as AMR_515,
         SUM(Case when (Codec =  7 and CodecRate = 4.75 ) then v.Duration else NULL end) * 1.0 as AMR_475,
         SUM(Case when (Codec =  8                      ) then v.Duration else NULL end) * 1.0 as AMR_WB,
         SUM(Case when (Codec =  8 and CodecRate = 23.85) then v.Duration else NULL end) * 1.0 as AMR_WB_2385,
         SUM(Case when (Codec =  8 and CodecRate = 23.05) then v.Duration else NULL end) * 1.0 as AMR_WB_2305,
         SUM(Case when (Codec =  8 and CodecRate = 19.85) then v.Duration else NULL end) * 1.0 as AMR_WB_1985,
         SUM(Case when (Codec =  8 and CodecRate = 15.85) then v.Duration else NULL end) * 1.0 as AMR_WB_1585,
         SUM(Case when (Codec =  8 and CodecRate = 14.25) then v.Duration else NULL end) * 1.0 as AMR_WB_1425,
         SUM(Case when (Codec =  8 and CodecRate = 12.65) then v.Duration else NULL end) * 1.0 as AMR_WB_1265,
         SUM(Case when (Codec =  8 and CodecRate = 8.85 ) then v.Duration else NULL end) * 1.0 as AMR_WB_885,
         SUM(Case when (Codec =  8 and CodecRate = 6.6  ) then v.Duration else NULL end) * 1.0 as AMR_WB_66,
         SUM(Case when (Codec = 10                      ) then v.Duration else NULL end) * 1.0 as AMR_WB_HR,
         SUM(Case when (Codec = 10 and CodecRate = 23.85) then v.Duration else NULL end) * 1.0 as AMR_WB_HR_2385,
         SUM(Case when (Codec = 10 and CodecRate = 23.05) then v.Duration else NULL end) * 1.0 as AMR_WB_HR_2305,
         SUM(Case when (Codec = 10 and CodecRate = 19.85) then v.Duration else NULL end) * 1.0 as AMR_WB_HR_1985,
         SUM(Case when (Codec = 10 and CodecRate = 15.85) then v.Duration else NULL end) * 1.0 as AMR_WB_HR_1585,
         SUM(Case when (Codec = 10 and CodecRate = 14.25) then v.Duration else NULL end) * 1.0 as AMR_WB_HR_1425,
         SUM(Case when (Codec = 10 and CodecRate = 12.65) then v.Duration else NULL end) * 1.0 as AMR_WB_HR_1265,
         SUM(Case when (Codec = 10 and CodecRate = 8.85 ) then v.Duration else NULL end) * 1.0 as AMR_WB_HR_885,
         SUM(Case when (Codec = 10 and CodecRate = 6.6  ) then v.Duration else NULL end) * 1.0 as AMR_WB_HR_66,
         SUM(Case when (Codec = 11                      ) then v.Duration else NULL end) * 1.0 as AMR_WB_FR,
         SUM(Case when (Codec = 11 and CodecRate = 23.85) then v.Duration else NULL end) * 1.0 as AMR_WB_FR_2385,
         SUM(Case when (Codec = 11 and CodecRate = 23.05) then v.Duration else NULL end) * 1.0 as AMR_WB_FR_2305,
         SUM(Case when (Codec = 11 and CodecRate = 19.85) then v.Duration else NULL end) * 1.0 as AMR_WB_FR_1985,
         SUM(Case when (Codec = 11 and CodecRate = 15.85) then v.Duration else NULL end) * 1.0 as AMR_WB_FR_1585,
         SUM(Case when (Codec = 11 and CodecRate = 14.25) then v.Duration else NULL end) * 1.0 as AMR_WB_FR_1425,
         SUM(Case when (Codec = 11 and CodecRate = 12.65) then v.Duration else NULL end) * 1.0 as AMR_WB_FR_1265,
         SUM(Case when (Codec = 11 and CodecRate = 8.85 ) then v.Duration else NULL end) * 1.0 as AMR_WB_FR_885,
         SUM(Case when (Codec = 11 and CodecRate = 6.6  ) then v.Duration else NULL end) * 1.0 as AMR_WB_FR_66,
         SUM(Case when (Codec = 12 and CodecRate = 5.9  ) then v.Duration else NULL end) * 1.0 as EVS_59,
         SUM(Case when (Codec = 12 and CodecRate = 7.2  ) then v.Duration else NULL end) * 1.0 as EVS_72,
         SUM(Case when (Codec = 12 and CodecRate = 8.0  ) then v.Duration else NULL end) * 1.0 as EVS_80,
         SUM(Case when (Codec = 12 and CodecRate = 9.6  ) then v.Duration else NULL end) * 1.0 as EVS_96,
         SUM(Case when (Codec = 12 and CodecRate = 13.2 ) then v.Duration else NULL end) * 1.0 as EVS_132,
         SUM(Case when (Codec = 12 and CodecRate = 16.4 ) then v.Duration else NULL end) * 1.0 as EVS_164,
         SUM(Case when (Codec = 12 and CodecRate = 24.4 ) then v.Duration else NULL end) * 1.0 as EVS_244,
         SUM(Case when (Codec = 12 and CodecRate = 32.0 ) then v.Duration else NULL end) * 1.0 as EVS_320,
         SUM(Case when (Codec = 12 and CodecRate = 48.0 ) then v.Duration else NULL end) * 1.0 as EVS_480,
         SUM(Case when (Codec = 12 and CodecRate = 64.0 ) then v.Duration else NULL end) * 1.0 as EVS_640,
         SUM(Case when (Codec = 12 and CodecRate = 96.0 ) then v.Duration else NULL end) * 1.0 as EVS_960,
         SUM(Case when (Codec = 12 and CodecRate = 128.0) then v.Duration else NULL end) * 1.0 as EVS_1280,
         SUM(Case when (Codec = 50                      ) then v.Duration else NULL end) * 1.0 as EVRC,
         SUM(Case when (Codec = 51                      ) then v.Duration else NULL end) * 1.0 as EVRC_B,
         SUM(Case when (Codec = 52                      ) then v.Duration else NULL end) * 1.0 as EVRC_WB,
         SUM(Case when (Codec = 53                      ) then v.Duration else NULL end) * 1.0 as QCELP,
         SUM(v.Duration) as Duration
  From VoiceCodecTest v
  Group By v.SessionID,
           v.TestID,
           v.Direction;


-- dbo.vVoiceCodecTest source

ALTER VIEW vVoiceCodecTest
AS
  Select vvct.SessionId,
         vvct.TestId,
         vvct.Direction,
         MAX(vvct.CodecNameShort) as CodecNameShort,
         MAX(vvct.CodecName) as CodecName,
         vvct.Duration,
         Max(vvct.CodecRate) as CodecRate,
         Max(vvct.CodecRateFloat) as CodecRateFloat
  From vVoiceCodecsTest vvct
  Where vvct.Duration = (Select MAX(r.Duration)
                         From vVoiceCodecsTest r
                         Where r.TestId = vvct.TestId and r.Direction = vvct.Direction and r.SessionId = vvct.SessionId)
  Group By vvct.TestId, vvct.Direction, vvct.Duration, vvct.SessionId;


-- dbo.vVoiceCodecTestBSide source

ALTER VIEW vVoiceCodecTestBSide
AS
  Select vvctBSide.SessionId,
         vvctBSide.TestId,
         vvctBSide.Direction,
         MAX(vvctBSide.CodecNameShort) as CodecNameShort,
         MAX(vvctBSide.CodecName) as CodecName,
         vvctBSide.Duration,
         Max(vvctBSide.CodecRate) as CodecRate
  From vVoiceCodecsTestBSide vvctBSide
  Where vvctBSide.Duration=(Select MAX(vvctBSide2.Duration)
                            From vVoiceCodecsTestBSide vvctBSide2
                            Where vvctBSide2.TestId = vvctBSide.TestId And vvctBSide2.Direction = vvctBSide.Direction And vvctBSide2.SessionId = vvctBSide.SessionId)
  Group By vvctBSide.TestId, vvctBSide.Direction, vvctBSide.Duration, vvctBSide.SessionId;


-- dbo.vVoiceCodecsTest source

ALTER VIEW vVoiceCodecsTest
AS
  Select vct.SessionId,
         vct.TestId,
         vct.Direction,
         vct.Codec,
         dbo.GetCodec(Codec) as CodecNameShort,
         dbo.GetCodec(Codec) + case when Codec in (5, 6, 7, 8, 10, 11, 12) then ' ' + CONVERT(varchar,vct.CodecRate)
                               else ''
                               end as CodecName,
         SUM(vct.Duration) as Duration,
         CONVERT(varchar,vct.CodecRate) as CodecRate,
         vct.CodecRate as CodecRateFloat
  From VoiceCodecTest vct Join Sessions On(vct.SessionId=Sessions.SessionId)
  Group By vct.SessionId, vct.TestId, vct.Direction, vct.Codec, vct.CodecRate;


-- dbo.vVoiceCodecsTestBSide source

ALTER VIEW vVoiceCodecsTestBSide
AS
  Select vct.SessionId,
         vct.TestId,
         vct.Direction,
         vct.Codec,
         dbo.GetCodec(Codec) as CodecNameShort,
         dbo.GetCodec(Codec) + case when Codec in (5, 6, 7, 8, 10, 11, 12) then ' ' + CONVERT(varchar,vct.CodecRate)
                               else ''
                               end as CodecName,
         SUM(vct.Duration) as Duration,
         CONVERT(varchar,vct.CodecRate) as CodecRate
  From VoiceCodecTest vct Join SessionsB On(vct.SessionId=SessionsB.SessionId)
  Group by vct.SessionId, vct.TestId, vct.Direction, vct.Codec, vct.CodecRate;


-- dbo.vWCDMAAGCdedicated source

ALTER VIEW vWCDMAAGCdedicated
As
	Select
		WCDMAAGC.SessionId,
		WCDMAAGC.TestId,
		WCDMAAGC.msgTime,
		WCDMAAGC.PosId,
		WCDMAAGC.NetworkId,
		WCDMAAGC.RxPwr,
		WCDMAAGC.TxPwr,
		Case When exists(Select rrc.msgid
					From WCDMARRCState rrc, Sessions s1
					Where rrc.SessionId=s1.SessionId And
						WCDMAAGC.msgTime >= rrc.msgTime And
						Filelist.FileID = s1.FileId)
			Then (Select Case when s.RRCState In(2,3,4,5)Then 'valid' else 'invalid' end
				From WCDMARRCState s Where s.msgid=(Select max(w.msgid)
														From WCDMARRCState w, Sessions ses
														Where w.SessionId=ses.SessionId and
															WCDMAAGC.msgTime >= w.msgTime and
															Filelist.FileID = ses.FileID))
			Else 'invalid' End As dedicated
	From
		Sessions,
		FileList,
		WCDMAAGC
	Where
		Sessions.Valid=1 And
		Sessions.FileId=FileList.FileId And
		Sessions.SessionId=WCDMAAGC.SessionId;


-- dbo.vWCDMAActiveSetNeighborSet source

ALTER VIEW vWCDMAActiveSetNeighborSet
AS
	Select
	WCDMANeighborSet.SessionId,
	WCDMANeighborSet.TestId,
	WCDMANeighborSet.MsgTime,
	WCDMANeighborSet.NetworkId,
	WCDMANeighborSet.PosId,
	WCDMANeighborSet.PrimScrCode as PrimScCode,
	WCDMANeighborSet.EcIo_PSC,
	WCDMANeighborSet.RSCP_PSC,
	WCDMANeighborSet.SetValue
	From
	WCDMANeighborSet Join vWCDMASessions On(WCDMANeighborSet.SessionId=vWCDMASessions.SessionId)


	Union
	Select
	WCDMAActiveSet.SessionId,
	WCDMAActiveSet.TestId,
	WCDMAActiveSet.MsgTime,
	WCDMAActiveSet.NetworkId,
	WCDMAActiveSet.PosId,
	WCDMAActiveSet.PrimScCode,
	WCDMAActiveSet.AggrEcIo_PSC,
	WCDMAActiveSet.RSCP_PSC,
	'A' as 'SetValue'
	From
	WCDMAActiveSet Join vWCDMASessions On(WCDMAActiveSet.SessionId=vWCDMASessions.SessionId);


-- dbo.vWCDMABLERdedicated source

ALTER VIEW vWCDMABLERdedicated
AS
	Select
		WCDMABLER.SessionId,
		WCDMABLER.TestId,
		WCDMABLER.MsgTime,
		WCDMABLER.PosId,
		WCDMABLER.NetworkId,
		SUM(crcRec) as crcRsvd,
		SUM(crcError) as crcErrors,
		Case When SUM(crcRec)>0 Then SUM(crcError)*100/SUM(crcRec) Else 0 End As BLER,
		Case When rrcs.RRCState In(2,3,4,5)Then 'valid' Else 'invalid' End As dedicated
	From
		Sessions,
		FileList,
		WCDMABLER,
		WCDMARRCState rrcs
	Where
		Sessions.Valid=1 And
		Sessions.FileId = FileList.FileId and
		Sessions.SessionId = WCDMABLER.SessionId And
		rrcs.msgid=(Select max(w.msgid) From WCDMARRCState w, Sessions s
                  	Where w.SessionId=s.SessionId And
                              WCDMABLER.msgTime >= w.msgTime and
                              Filelist.FileId = s.FileId)
	Group By
		WCDMABLER.SessionId,
		WCDMABLER.TestId,
		WCDMABLER.MsgTime,
		WCDMABLER.PosId,
		WCDMABLER.NetworkId,
		rrcs.RRCState;


-- dbo.vWCDMAGSMNeighborSet source

ALTER VIEW vWCDMAGSMNeighborSet
AS
	SELECT
		SessionId,
		TestId,
		MsgTime,
		PosId,
		NetworkId,
		ARFCN,
		RFBand,
		BSIC,
		ROUND(AVG(RxLev),0) AS RxLev
	FROM
		WCDMAGSMNeighborSetInfo Join WCDMAGSMNeighborSet On(WCDMAGSMNeighborSetInfo.NeighborSetId=WCDMAGSMNeighborSet.NeighborSetId)
	GROUP BY
		SessionId,
		TestId,
		MsgTime,
		PosId,
		NetworkId,
		ARFCN,
		RFBand,
		BSIC;


-- dbo.vWCDMAMeasControlEvents source

ALTER VIEW vWCDMAMeasControlEvents
AS
  Select i.SessionId,
         dbo.DelphiDateTime(i.MsgTime) as dTime,
         CONVERT(varchar, i.MsgTime, 14) as msgTime2,
         i.MeasControlEventId,
         i.EventCount,
         e.Event,
         e.Hysteresis,
         e.TimeToTrigger,
         e.ReportingCellStatus,
         e.TriggeringCondition,
         e.ReportingRange,
         e.Threshold,
         e.Threshold2,
         e.ReportingAmount,
         e.ULTChId,
         e.PendingAfterTrigger,
         e.TxInterruptionAfterTrigger,
         e.TransportChannelIdentity,
         e.TotalCRC,
         e.BadCRC
from WCDMAMeasControlEventInfo i
     JOIN WCDMAMeasControlEvent e ON e.MeasControlEventId = i.MeasControlEventId;


-- dbo.vWCDMARRCMessages source

ALTER VIEW vWCDMARRCMessages
AS
  Select FactId as MsgId,
         SessionId,
         VirtualTestId as TestId,
         FullDate as MsgTime,
         PosId,
         NetworkId,
         Identifier as LogChanType,
         NULL as RB_Id,
         Message as Msg,
         SimpleMsgName as MsgType,
         Identifier2 as MsgIdent,
         Direction,
         MsgName
  from FactL3Messages
  where Technology = 'UMTS';


-- dbo.vWCDMASessions source

ALTER VIEW vWCDMASessions
AS
	Select
	Sessions.SessionId,
	Sessions.FileId
	From
	WCDMANeighborSet Join Sessions On(WCDMANeighborSet.SessionId=Sessions.SessionId)
				Join FileList On(Sessions.FileId=FileList.FileId)
	Group by
	Sessions.SessionId,
	Sessions.FileId;


